INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1, 'Նշաններից ո՞րն է կոչվում «Արգելքի շրջանցումը ձախից»։', 'question1_image.png', '["1", "2", "3", "4", "5"]', '3', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (2, 'Թույլատրվու՞մ է արդյոք ավտոբուսի վարորդին մուտք գործել խաչմերուկ տվյալ իրադրությունում։', 'question2_image.png', '["Թույլատրվում է", "Արգելվում է։", "Թույլատրվում է, եթե ավտոբուսը երթեւեկում է սահմանված երթուղով։"]', 'Արգելվում է։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (2, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (3, 'Նշված դեպքում ո՞ր գոտուց պետք է կատարվի աջ շրջադարձը։', 'question3_image.png', '["Միայն երկրորդ գոտուց։", "Միայն «A» գծանշումով նշված աջ եզրային գոտուց։"]', 'Միայն «A» գծանշումով նշված աջ եզրային գոտուց։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (3, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (4, 'Խաչմերուկում կազմակերպված է շրջանաձեւ երթեւեկություն։ Երթեւեկելի մասը, որով մոտենում եք խաչմերուկին, ունի երթեւեկության երկու գոտի։ Խաչմերուկ մուտք գործելիս` շրջադարձ կատարելու համար ո՞ր գոտին եք պարտավոր զբաղեցնել՝', NULL, '["Աջ գոտին։", "Ձախ գոտին։", "Կա՛մ աջ, կա՛մ ձախ գոտին։"]', 'Կա՛մ աջ, կա՛մ ձախ գոտին։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (4, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (5, 'Թույլատրվու՞մ է արդյոք մուտք գործել բակ նշված տեղից։', 'question5_image.png', '["1.Թույլատրվում է։", "2.Արգելվում է։"]', '1.Թույլատրվում է։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (5, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (6, 'Երկկողմ երթեւեկությամբ գծանշված ճանապարհներին, երեք գոտու առկայության դեպքում (բացառությամբ երթեւեկության դարձափոխային կարգավորմամբ ճանապարհների), որոնցից միջինն օգտագործվում է երկու ուղղություններով երթեւեկության համար, ձախ եզրային գոտի մուտք գործելը՝', NULL, '["Թույլատրվում է։", "Արգելվում է։", "Թույլատրվում է՝ միայն վազանցի, շրջանցման, ձախշրջադարձի կամ հետադարձի համար։"]', 'Արգելվում է։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (6, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (7, 'Ո՞ր պատասխանում է ճիշտ նշված երթեւեկությանթույլատրելի ուղղությունը։', 'question7_image.png', '["Միայն հետադարձ։", "Ուղիղ եւ հետադարձ։", "Միայն ուղիղ։"]', 'Միայն ուղիղ։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (7, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (8, 'Ո՞ր ուղղությամբ է արգելվում երթեւեկությունը՝', 'question8_image.png', '["Դեպի ձախ եւ դեպի աջ։", "Ուղիղ եւ հակառակ ուղղությամբ։", "Միայն ուղիղ։", "Բոլոր ուղղություններով։"]', 'Դեպի ձախ եւ դեպի աջ։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (8, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (9, 'Հետադարձն արգելվում է՝', NULL, '["Հետիոտնային անցումների վրա։", "Թունելներում։", "Կամուրջների, ուղեկամուրջների, էստակադների վրա եւ դրանց տակ։", "Երկաթուղային գծանցներում։", "Թվարկած բոլոր դեպքերում։"]', 'Թվարկած բոլոր դեպքերում։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (9, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (10, 'Թույլատրվու՞մ է արդյոք դեղին ավտոբուսի վարորդին մուտքգործել խաչմերուկ։', 'question10_image.png', '["Թույլատրվում է։", "Արգելվում է։", "Թույլատրվում է, եթե ավտոբուսը երթեւեկում է սահմանված երթուղով։"]', 'Արգելվում է։', 1);
