INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (11, 'Ո՞ր պատասխանում է ճիշտ նշված երթեւեկության թույլատրելի ուղղությունը։', 'question11_image.png', '["Ուղիղ եւ դեպի ձախ` մուտք գործելով բակ։", "Միայն ուղիղ։", "Միայն հետադարձ։", "Ուղիղ եւ հետադարձ։"]', 'Միայն ուղիղ։', 1);
