INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (12, 'Հետադարձն արգելվում է, եթե ճանապարհի թեկուզ եւ մեկ ուղղությամբ տեսանելիությունը պակաս է՝', NULL, '["100 մ-ից։", "150 մ-ից։", "300 մ-ից։"]', '100 մ-ից։', 1);
