INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (13, 'Դուք երթեւեկում եք երեք գոտի ունեցող երկկողմ երթեւեկությամբ ճանապարհով։ Ո՞ր դեպքում է թույլատրվում մուտք գործել միջին գոտի։', NULL, '["Միայն վազանցի դեպքում։", "Միայն շրջանցման դեպքում։։", "Միայն ձախ շրջադարձի կամ հետադարձի դեպքում։", "Թվարկած բոլոր դեպքերում։"]', 'Թվարկած բոլոր դեպքերում։', 1);
