INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (14, 'Ո՞ր ուղղությամբ է թույլատրվում բեռնատար ավտոմոբիլի երթեւեկությունը։', 'question14_image.png', '["Միայն դեպի աջ։", "Դեպի աջ, դեպի ձախ եւ հակառակ ուղղությամբ։", "Միայն դեպի ձախ։"]', 'Դեպի աջ, դեպի ձախ եւ հակառակ ուղղությամբ։', 1);
