INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (15, 'Ո՞ր նկարում է վարորդը ճիշտ կատարում մանեւրը։', 'question15_image.png', '["1", "2", "3"]', '1', 1);
