INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (16, 'Ո՞ր տրանսպորտային միջոցի վարորդն է ճիշտ կատարում հետադարձը։', 'question16_image.png', '["Կապույտ ավտոմոբիլի վարորդը։", "Կարմիր ավտոմոբիլի վարորդը։", "Երկու վարորդներն էլ։"]', 'Կարմիր ավտոմոբիլի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (16, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (17, 'Ճանապարհային նշանների, գծանշման եւ բաժանարար գոտու բացակայության դեպքում վարորդները երկկողմ երթեւեկությամբ ճանապարհների երթեւեկելի մասում գտնվող ճանապարհային կառույցների տարրերը պետք է շրջանցեն՝', NULL, '["Աջ կողմից։", "Ձախ կողմից։"]', 'Աջ կողմից։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (17, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (18, 'Ո՞ր ուղղությամբ է արգելվում երթեւեկությունը։', 'question18_image.png', '["Միայն դեպի ձախ։", "Միայն դեպի աջ։", "Ուղիղ եւ դեպի ձախ։", "Բոլոր ուղղություններով։"]', 'Միայն դեպի աջ։', 1);
