INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (19, 'Ո՞ր տրանսպորտային միջոցի վարորդն է խախտում կանոնները շրջադարձ կատարելիս՝ արգելակման գոտի ունեցող ճանապարհին։', 'question19_image.png', '["Երկու վարորդն էլ։", "Դեղին ավտոմոբիլի վարորդը։", "Երկու վարորդն էլ շրջադարձը կատարում են ճիշտ։"]', 'Դեղին ավտոմոբիլի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (19, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (20, 'Թույլատրվու՞մ է արդյոք տվյալ իրադրությունում կարմիր ավտոմոբիլի վարորդին շարունակել երթեւեկությունը։', 'question20_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Արգելվում է։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (20, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (21, 'Երեք գոտի ունեցող երկկողմ երթեւեկությամբ ճանապարհի վրա Ձեզ անհրաժեշտ է կատարել ձախ շրջադարձ։ Ո՞ր գոտուց կկատարեք տվյալ մանեւրը։', 'question21_image.png', '["Աջ գոտուց։", "Միջին գոտուց։", "Աջ կամ միջին գոտուց։", "Միջին գոտուց, եթե զբաղեցված է աջ գոտին։"]', 'Միջին գոտուց։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (21, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (22, 'Թույլատրվու՞մ է արդյոք կարմիր ավտոմոբիլի վարորդին երթեւեկել տրամվայի գծերով։', 'question22_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Թույլատրվում է։', 1);
