INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (23, 'Հետադարձն արգելվում է՝', 'question23_image.png', '["Հետիոտնային անցումների վրա եւ թունելներում։", "Կամուրջների, ուղեկամուրջների, էստակադների վրա եւ դրանց տակ։", "Երկաթուղային գծանցներում։", "Ճանապարհի` թեկուզ եւ մեկ ուղղությամբ 100 մ-ից պակաս տեսանելիության տեղերում։", "Բոլոր թվարկած դեպքերում։"]', 'Բոլոր թվարկած դեպքերում։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (23, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (24, 'Ո՞ր ուղղություններով է թույլատրվում երթեւեկությունը։', 'question24_image.png', '["Միայն դեպի ձախ։", "Ուղիղ, դեպի ձախ եւ հետադարձ։", "Միայն ուղիղ։"]', 'Ուղիղ, դեպի ձախ եւ հետադարձ։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (24, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (25, 'Ո՞ր տրանսպորտային միջոցների վարորդներն են խախտել ճանապարհային նշանի պահանջները։', 'question25_image.png', '["Մոտոցիկլների վարորդները։", "Ավտոմոբիլի եւ կողային կցորդով մոտոցիկլի վարորդները։", "Միայն ավտոմոբիլի վարորդը։", "Բոլոր տրանսպորտային միջոցների վարորդները։"]', 'Բոլոր տրանսպորտային միջոցների վարորդները։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (25, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (26, 'Համընթաց ուղղությամբ երթեւեկող տրանսպորտային միջոցների միաժամանակյա վերադասավորման դեպքում ճանապարհը պետք է զիջի՝', 'question26_image.png', '["Ձախից ընթացող տրանսպորտային միջոցի վարորդը։", "Աջից ընթացող տրանսպորտային միջոցի վարորդը։"]', 'Ձախից ընթացող տրանսպորտային միջոցի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (26, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (27, 'Ո՞ր տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթեւեկության իրավունք։', 'question27_image.png', '["Բեռնատար ավտոմոբիլի վարորդը։", "Ավտոբուսի վարորդը։"]', 'Բեռնատար ավտոմոբիլի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (27, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (28, 'Պարտավո՞ր է արդյոք սահմանված երթուղով երթեւեկող ավտոբուսի վարորդը նշված իրադրությունում զիջել ճանապարհը։', 'question28_image.png', '["Պարտավոր է։", "Պարտավոր չէ։", "Պարտավոր չէ, քանի որ երթեւեկում է ուղիղ։"]', 'Պարտավոր է։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (28, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (29, 'Եթե համապատասխան նշաններով կահավորված երկայնական թեքությամբ ճանապարհահատվածներում հանդիպակաց երթեւեկությունը դժվարացած է, ապա ճանապարհը պետք է զիջել՝', 'question29_image.png', '["Վայրէջքի ուղղությամբ ընթացող տրանսպորտային միջոցին։", "Ընդհանուր օգտագործման տրանսպորտային միջոցին։", "Վերելքի ուղղությամբ ընթացող տրանսպորտային միջոցին։"]', 'Վերելքի ուղղությամբ ընթացող տրանսպորտային միջոցին։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (29, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (30, 'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։', 'question30_image.png', '["Տրակտորի վարորդը։", "Ավտոբուսի վարորդը։"]', 'Ավտոբուսի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (30, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (31, 'Երթեւեկության առավելություն ունի՝', 'question31_image.png', '["Կապույտ ավտոմոբիլը, քանի որ կարմիրը փոխում է երթեւեկության ուղղությունը դեպի ձախ։", "Կարմիր ավտոմոբիլը, քանի որ միաժամանակյա վերադասավորման դեպքում գտնվում է աջ կողմում։", "Կապույտ ավտոմոբիլը, քանի որ միաժամանակյա վերադասավորման դեպքում գտնվում է ձախ կողմում։"]', 'Կարմիր ավտոմոբիլը, քանի որ միաժամանակյա վերադասավորման դեպքում գտնվում է աջ կողմում։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (31, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (32, 'Պարտավո՞ր են արդյոք տրանսպորտային միջոցների վարորդները բնակավայրերում ճանապարհը զիջել կահավորված եւ նշված կանգառի կետերի տարածքից երթեւեկությունը սկսող ընդհանուր օգտագործման տրանսպորտային միջոցներին։', 'question32_image.png', '["Այո։", "Ոչ։"]', 'Կապույտ ավտոմոբիլը, քանի որ կարմիրը փոխում է երթեւեկության ուղղությունը դեպի ձախ։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (32, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (33, 'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։', 'question33_image.png', '["Թեթեւ մարդատար ավտոմոբիլի վարորդը։", "Բեռնատար ավտոմոբիլի վարորդը։"]', 'Թեթեւ մարդատար ավտոմոբիլի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (33, 3);
