INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (35, 'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։', 'question35_image.png', '["Ավտոմոբիլի վարորդը։", "Տրամվայի վարորդը։"]', 'Ավտոմոբիլի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (35, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (36, 'Նշե՛ք խաչմերուկի անցման հերթականությունը`', 'question36_image.png', '["Ավտոբուսը, բեռնատար ավտոմոբիլը, լծասայլը։", "Ավտոբուսը եւ լծասայլը, բեռնատար ավտոմոբիլը։"]', 'Ավտոբուսը եւ լծասայլը, բեռնատար ավտոմոբիլը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (36, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (37, 'Հանդիպակաց երթեւեկության դեպքում կտրուկ վայրէջքի վրա անհրաժեշտ է ճանապարհը զիջել՝', 'question37_image.png', '["Ընդհանուր օգտագործման տրանսպորտային միջոցին։", "Վերեւ բարձրացող տրանսպորտային միջոցին։", "Ներքեւ իջնող տրանսպորտային միջոցին։"]', 'Վերեւ բարձրացող տրանսպորտային միջոցին։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (37, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (38, 'Բնակավայրերում միեւնույն ուղղությամբ երթեւեկության 3 եւ ավելի գոտիների առկայության դեպքում ձախ եզրային գոտի զբաղեցնել թույլատրվու՞մ է արդյոք ընդհանուր օգտագործման տրանսպորտային միջոցներին։', 'question38_image.png', '["Թույլատրվում է վազանց կատարելիս։", "Թույլատրվում է ձախ շրջադարձ կամ հետադարձ կատարելիս։", "Թույլատրվում է բոլոր դեպքերում։"]', 'Թույլատրվում է ձախ շրջադարձ կամ հետադարձ կատարելիս։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (38, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (39, 'Բոլոր ճանապարհներին միեւնույն ուղղությամբ երթեւեկության 3 եւ ավելի գոտիների առկայության դեպքում ձախ եզրային գոտի զբաղեցնել թույլատրվու՞մ է արդյոք ընդհանուր օգտագործման տրանսպորտային միջոցներին։', 'question39_image.png', '["Թույլատրվում է վազանց կատարելիս։", "Թույլատրվում է ձախ շրջադարձ կամ հետադարձ կատարելիս։", "Թույլատրվում է բոլոր դեպքերում։"]', 'Թույլատրվում է ձախ շրջադարձ կամ հետադարձ կատարելիս։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (39, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (40, 'Ինչպե՞ս պետք է վարվի երթուղային ավտոբուսի վարորդը տվյալ իրավիճակում։', 'question40_image.png', '["Ճանապարհը զիջի թեթեւ մարդատար ավտոմոբիլին։", "Միացնի շրջադարձի ցուցիչը, տա ձայնային ազդանշան եւ սկսի երթեւեկությունը։", "Սկսի երթեւեկությունը` համոզված լինելով, որ թեթեւ մարդատար ավտոմոբիլի վարորդը զիջում է ճանապարհը։"]', 'Սկսի երթեւեկությունը` համոզված լինելով, որ թեթեւ մարդատար ավտոմոբիլի վարորդը զիջում է ճանապարհը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (40, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (41, 'Տվյալ իրադրությունում սպիտակ թեթեւ մարդատար ավտոմոբիլի վարորդը`', 'question41_image.png', '["Ճանապարհը պետք է զիջի երթուղային ավտոբուսին, որը սկսում է երթեւեկությունը նշված կանգառի կետից։", "Ունի առաջնահերթ երթեւեկության իրավունք, քանի որ երթուղային ավտոբուսը վերադասավորվում է երկրորդ գոտի անցնելով։"]', 'Ճանապարհը պետք է զիջի երթուղային ավտոբուսին, որը սկսում է երթեւեկությունը նշված կանգառի կետից։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (41, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (42, 'Ո՞ր տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթեւեկության իրավունք։', 'question42_image.png', '["Թեթեւ մարդատար ավտոմոբիլի վարորդը։", "Երթուղային ավտոբուսի վարորդը։"]', 'Թեթեւ մարդատար ավտոմոբիլի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (42, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (43, 'Ո՞ր տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթեւեկության իրավունք տվյալ իրավիճակում։', 'question43_image.png', '["Ավտոբուսի վարորդը։", "Թեթեւ մարդատար ավտոմոբիլի վարորդը։", "Թեթեւ մարդատար ավտոմոբիլի վարորդը իրավունք չունի անցնել աջ գոտի։"]', 'Ավտոբուսի վարորդը։', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (43, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (44, 'Խաչմերուկում որտեղ կազմակերպված է շրջանաձեւ երթեւեկություն, պարտավո՞ր է արդյոք ավտոբուսի վարորդը զիջել ճանապարհը բեռնատար ավտոմոբիլին։', 'question44_image.png', '["Պարտավոր է։", "Պարտավոր չէ։"]', 'Պարտավոր չէ։', 1);
