INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (133, 'Մերձակա տարածք մուտք գործելիս վարորդը պետք է ճանապարհը զիջի', 'question133_image.png', '["Միայն հետիոտներին", "Միայն հեծանվորդներին", "Հեծանվորդներին և չստեղծի խոչընդոտ հետիոտների համար"]', 'Հեծանվորդներին և չստեղծի խոչընդոտ հետիոտների համար', 1);
