INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (134, 'Մերձակա տարածքից ճանապարհ դուրս գալիս՝ վարորդը պետք է', 'question134_image.png', '["Ճանապարհը զիջի միայն հետիոտներին", "Ճանապարհը զիջի դրանով երթևեկող տրանսպորտային միջոցներին", "Զիջի ճանապարհը երթևեկող տրանսպորտային միջոցների վարորդներին և չստեղծի խոչընդոտ հետիոտների համար"]', 'Զիջի ճանապարհը երթևեկող տրանսպորտային միջոցների վարորդներին և չստեղծի խոչընդոտ հետիոտների համար', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (134, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (135, 'Հետադարձ կատարել նշանից հետո թույլատրվում է', 'question135_image.png', '["Միայն երկու կողմից 100 մետր տեսանելիության դեպքում", "Խոչընդոտ չստեղծելու դեպքում", "Ոչ մի դեպքում"]', 'Ոչ մի դեպքում', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (135, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (136, 'Ազդանշան տալը երթևեկության մյուս մասնակիցների նկատմամբ առավելություն', 'question136_image.png', '["Տալիս է", "Տալիս է միայն վերադասավորվելիս", "Չի տալիս"]', 'Չի տալիս', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (136, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (137, 'Նշված հետագծով աջ շրջադարձը', 'question137_image.png', '["Թույլատրված է", "Արգելված է"]', 'Թույլատրված է', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (137, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (138, 'Բեռնատարից առաջ անցնելուց հետո ո՞ր գոտով կարող եք շարունակել երթևեկությունը', 'question138_image.png', '["Միայն աջ", "Երկու համընթաց գոտիներով էլ թույլատրվում է"]', 'Միայն աջ', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (138, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (139, 'Հետադարձը նշված վայրում', 'question139_image.png', '["Թույլատրվում է", "Թույլատրվում է, եթե առկա չեն ընդհանուր օգտագործման տրանսպորտային միջոցներ", "Արգելվում է"]', 'Արգելվում է', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (139, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (140, 'Առաջնահերթ երթևեկության իրավունք ունի', 'question140_image.png', '["Թեթև մարդատարի վարորդը", "Բեռնատարի վարորդը"]', 'Բեռնատարի վարորդը', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (140, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (141, 'Միաժամանակ վերադասավորվելիս ո՞ր տրանսպորտային միջոցի վարորդը ունի առաջնահերթ երթևեկության իրավունք', 'question141_image.png', '["Բեռնատարի", "Թեթև մարդատարի"]', 'Թեթև մարդատարի', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (141, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (142, 'Թույլատրվո՞ւմ է հետընթացով մոտենալ ուղևորին', 'question142_image.png', '["Այո", "Ոչ"]', 'Ոչ', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (142, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (143, 'Աջ բակ մուտք գոծելու դեպքում պարտավոր ենք զիջել', 'question143_image.png', '["Միայն հետիոտներին", "Միայն հեծանվորդին", "Ոչ մեկին", "Հեծանվորդին և հետիոտներին"]', 'Հեծանվորդին և հետիոտներին', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (143, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (144, 'Այս վերելքի ուղղությամբ շարժվելիս հետադարձ թույլատրվում է, եթե', 'question144_image.png', '["Հնարավոր լինի այն կատարել մեկ գործողությամբ", "Ապահովված է 100 մետր տեսանելիությունը երկու կողմից", "Արգելված է"]', 'Ապահովված է 100 մետր տեսանելիությունը երկու կողմից', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (144, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (145, 'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը', 'question145_image.png', '["Ավտոբուսի վարորդը", "Թեթև մարդատարի վարորդը"]', 'Ավտոբուսի վարորդը', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (145, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (146, 'Թույլատրվում է հետադարձն այս վայրում', 'question146_image.png', '["Թույլատրվում է երկու կողմից 100մ տեսանելիության պայմաններում", "Արգելվում է"]', 'Թույլատրվում է երկու կողմից 100մ տեսանելիության պայմաններում', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (146, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (147, 'Թույլատրվո՞ւմ է անցնել կամուրջը, եթե դա չի խոչընդոտում մոտոցիկլի վարորդին', 'question147_image.png', '["Այո", "Ոչ"]', 'Այո', 1);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (147, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (148, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն ուղեւոր է համարվում՝', 'question148_image.png', '["Տրանսպորտային միջոցի սրահում (խցիկում) կամ տրանսպորտային միջոցի վրա գտնվող անձը` բացառությամբ վարորդի եւ վարել սովորեցնողի։", "Տրանսպորտային միջոցի սրահում (խցիկում) կամ տրանսպորտային միջոցի վրա գտնվող, ինչպես նաեւ տրանսպորտային միջոցը նստող (բարձրացող) ու դրանից դուրս եկող (իջնող) անձը` բացառությամբ վարորդի եւ վարել սովորեցնողի։"]', 'Տրանսպորտային միջոցի սրահում (խցիկում) կամ տրանսպորտային միջոցի վրա գտնվող, ինչպես նաեւ տրանսպորտային միջոցը նստող (բարձրացող) ու դրանից դուրս եկող (իջնող) անձը` բացառությամբ վարորդի եւ վարել սովորեցնողի։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (148, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (149, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «A» կարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝', 'question149_image.png', '["16 տարին լրացած անձանց։", "17 տարին լրացած անձանց։", "18 տարին լրացած անձանց։"]', '18 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (149, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (150, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «BE» կարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝', 'question150_image.png', '["17 տարին լրացած անձանց։", "18 տարին լրացած անձանց։", "19 տարին լրացած անձանց։"]', '19 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (150, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (151, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն` ճանապարհի երթեւեկելի մաս է համարվում`', 'question151_image.png', '["Ճանապարհի տարրը` նախատեսված տրանսպորտային միջոցների երթեւեկության համար։", "Ճանապարհի տարրը` նախատեսված ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկության համար։"]', 'Ճանապարհի տարրը` նախատեսված ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկության համար։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (151, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (152, 'Պարտավո՞ր է արդյոք վարել սովորողն ուսումնական վարման ժամանակ ամրակապվել անվտանգության գոտիներով։', 'question152_image.png', '["Պարտավոր է։", "Պարտավոր չէ։", "Պարտավոր չէ, եթե դա դժվարացնում է ավտոմոբիլ ղեկավարելը։", "Պարտավոր չէ, եթե թույլատրում է վարել սովորեցնողը։"]', 'Պարտավոր է։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (152, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (153, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «D» կարգի եւ «D1» ենթակարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝', 'question153_image.png', '["18 տարին լրացած անձանց։", "19 տարին լրացած անձանց։", "20 տարին լրացած անձանց։", "21 տարին լրացած անձանց։"]', '21 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (153, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (154, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ հետիոտն է համարվում՝', 'question154_image.png', '["Տրանսպորտային միջոցից դուրս` ճանապարհի վրա գտնվող անձը` բացառությամբ ճանապարհի վրա աշխատանքներ իրականացնելու իրավասություն ունեցող եւ օրենսդրությամբ սահմանված կարգով այդ աշխատանքներն իրականացնող անձը։", "Տրանսպորտային միջոցից դուրս` ճանապարհի վրա գտնվող, այդ թվում` ճանապարհի վրա աշխատանքներ իրականացնելու իրավասություն ունեցող եւ օրենսդրությամբ սահմանված կարգով այդ աշխատանքներն իրականացնող անձը։"]', 'Տրանսպորտային միջոցից դուրս` ճանապարհի վրա գտնվող անձը` բացառությամբ ճանապարհի վրա աշխատանքներ իրականացնելու իրավասություն ունեցող եւ օրենսդրությամբ սահմանված կարգով այդ աշխատանքներն իրականացնող անձը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (154, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (155, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի գործնական վարման սկզբնական ուսուցումը իրականացվում է՝', 'question155_image.png', '["Բնակավայրերից դուրս` ճանապարհներին` հաշվի առնելով տրանսպորտային միջոցների երթեւեկության ինտենսիվությունը։", "Փակ հրապարակում կամ ավտոդրոմում։", "Ցանկացած ճանապարհին (բացառությամբ ավտոմայրուղիների)` հաշվի առնելով տրանսպորտային միջոցների երթեւեկության ինտենսիվությունը։"]', 'Փակ հրապարակում կամ ավտոդրոմում։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (155, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (156, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն` մերձակա տարածքից ելքը դեպի ճանապարհ համարվու՞մ է արդյոք խաչմերուկ։', 'question156_image.png', '["Չի համարվում։", "Համարվում է։"]', 'Չի համարվում։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (156, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (157, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «B», «C» եւ «D» կարգերի տրանսպորտային միջոցներ վարելու իրավունքի վկայական ունեցող անձանց թույլատրվում է դրանք վարել նաեւ կցորդներով, եթե կցորդի թույլատրելի առավելագույն զանգվածը չի գերազանցում', 'question157_image.png', '["750 կիլոգրամը։", "800 կիլոգրամը։", "1000 կիլոգրամը։"]', '750 կիլոգրամը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (157, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (158, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ երթևեկելի մասով հեծանվորդներին արգելվում է երթեւեկել՝', 'question158_image.png', '["Առանց պաշտպանիչ ակնոցների։", "Առանց սաղավարտի։", "Երկու դեպքում էլ։"]', 'Առանց սաղավարտի։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (158, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (159, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «B» եւ «C» կարգերի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝', 'question159_image.png', '["16 տարին լրացած անձանց։", "17 տարին լրացած անձանց։", "18 տարին լրացած անձանց։"]', '18 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (159, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (160, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ մոպեդ է համարվում ՝', 'question160_image.png', '["Ոչ ավել 50 սմ խորանարդ բանվորական ծավալի շարժիչով եւ ոչ ավել 50 կմ/ժ առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։", "Ոչ ավել 60 սմ խորանարդ բանվորական ծավալի շարժիչով եւ ոչ ավել 60 կմ/ժ առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։", "Ոչ ավել 70 սմ խորանարդ բանվորական ծավալի շարժիչով եւ ոչ ավել 70 կմ/ժ առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։"]', 'Ոչ ավել 50 սմ խորանարդ բանվորական ծավալի շարժիչով եւ ոչ ավել 50 կմ/ժ առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (160, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (161, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ հարկադրված կանգառ է համարվում՝', 'question161_image.png', '["Երթեւեկության ընդհատումը՝ կապված լուսացույցի արգելող ազդանշանի անսպասելի միացման հետ։", "Երթեւեկության ընդհատումը՝ կապված ճանապարհին գոյացած խցանման հետ։", "Տրանսպորտային միջոցի անսարքության, վարորդի (ուղեւորի) ֆիզիկական եւ (կամ) հոգեկան վիճակով եւ (կամ) բեռի փոխադրմամբ պայմանավորված՝ վտանգի կամ ճանապարհին ի հայտ եկած այլ խոչընդոտի պատճառով տրանսպորտային միջոցն անշարժ վիճակի բերելը։", "Թվարկած բոլոր դեպքերը։"]', 'Թվարկած բոլոր դեպքերը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (161, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (162, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ անբավարար տեսանելիություն է համարվում՝', 'question162_image.png', '["Ճանապարհի տեսանելիության հեռավորությունը՝ օրվա մութ ժամանակ։", "Ճանապարհի տեսանելիության հեռավորությունը բնակավայրերում՝ երթեւեկելի մասի արհեստական լուսավորվածության բացակայության պայմաններում։", "Մառախուղի, անձրեւի, ձյունաթափի եւ (կամ) ճանապարհային երթեւեկության անվտանգության ապահովման համար այլ անբարենպաստ եղանակի պայմաններում, ճանապարհի տեսանելիություն եւ (կամ) մինչեւ 300 մետր տեսանելիության հեռավորություն։"]', 'Մառախուղի, անձրեւի, ձյունաթափի եւ (կամ) ճանապարհային երթեւեկության անվտանգության ապահովման համար այլ անբարենպաստ եղանակի պայմաններում, ճանապարհի տեսանելիություն եւ (կամ) մինչեւ 300 մետր տեսանելիության հեռավորություն։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (162, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (163, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ կանգառ է համարվում՝', NULL, '["Մինչեւ 5 րոպե կամ ուղեւորի նստելու, իջնելու եւ (կամ) տրանսպորտային միջոցը բեռնելու, բեռնաթափելու համար անհրաժեշտ ժամանակով տրանսպորտային միջոցն կանխամտածված անշարժ վիճակի բերելը։", "5 րոպեից ավելի տրանսպորտային միջոցն անշարժ վիճակի բերելը, եթե դա կապված չէ ուղեւորների նստեցման, իջեցման կամ տրանսպորտային միջոցի բեռնման, բեռնաթափման հետ։"]', 'Մինչեւ 5 րոպե կամ ուղեւորի նստելու, իջնելու եւ (կամ) տրանսպորտային միջոցը բեռնելու, բեռնաթափելու համար անհրաժեշտ ժամանակով տրանսպորտային միջոցն կանխամտածված անշարժ վիճակի բերելը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (163, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (164, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ընդհանուր օգտագործման տրանսպորտային միջոց է համարվում՝', NULL, '["Կանգառի կետեր (կանգառներ) ունեցող, երթուղիներով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը (տրամվայ, տրոլեյբուս, ավտոբուս)։", "Կանգառի կետեր (կանգառներ) ունեցող, երթուղիներով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը (տրամվայ, տրոլեյբուս, ավտոբուս), ինչպես նաեւ թեթեւ մարդատար տաքսի ավտոմոբիլը։"]', 'Կանգառի կետեր (կանգառներ) ունեցող, երթուղիներով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը (տրամվայ, տրոլեյբուս, ավտոբուս)։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (164, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (165, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ հետիոտներին են հավասարեցվում՝', NULL, '["Առանց շարժիչի հաշմանդամային սայլակներով տեղաշարժվող հաշմանդամները։", "Բեռնասայլակ, սահնակ, մանկասայլակ կամ հաշմանդամային սայլակ քաշող (հրող) անձինք։", "Թվարկած բոլոր անձինք։"]', 'Թվարկած բոլոր անձինք։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (165, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (166, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ կցորդ (կիսակցորդ) էհամարվում՝', NULL, '["Կոշտ կցիչով քարշակվող ցանկացած մեխանիկական տրանսպորտային միջոցը։", "Շարժիչով չկահավորված տրանսպորտային միջոցը, որը նախատեսված է մեխանիկական տրանսպորտային միջոցով շարժման մեջ դրվելու եւ դրա կազմում որպես մեկ ամբողջություն երթեւեկելու համար (ներառյալ՝ հատուկ կցորդը)։"]', 'Շարժիչով չկահավորված տրանսպորտային միջոցը, որը նախատեսված է մեխանիկական տրանսպորտային միջոցով շարժման մեջ դրվելու եւ դրա կազմում որպես մեկ ամբողջություն երթեւեկելու համար (ներառյալ՝ հատուկ կցորդը)։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (166, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (167, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ Հայաստանի Հանրապետության ճանապարհներին սահմանվում է՝', NULL, '["Աջակողմյան երթեւեկություն։", "Ձախակողմյան երթեւեկություն։"]', 'Աջակողմյան երթեւեկություն։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (167, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (168, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ կայանում է համարվում՝', NULL, '["5 րոպեից ավելի տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը, եթե դա կապված չէ ուղեւորների նստեցման, իջեցման կամ տրանսպորտային միջոցի բեռնման, բեռնաթափման հետ։", "5 րոպեից ավելի տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը, բացառությամբ ճանապարհային երթեւեկության այլ մասնակցի կամ որեւէ արգելքի հետ ընդհարումը կանխելու, ուղեւորի նuտելու, իջնելու եւ (կամ) տրանuպորտային միջոցը բեռնելու, բեռնաթափելու, ինչպես նաև օրենսդրությամբ նախատեսված այլ դեպքերի։"]', '5 րոպեից ավելի տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը, բացառությամբ ճանապարհային երթեւեկության այլ մասնակցի կամ որեւէ արգելքի հետ ընդհարումը կանխելու, ուղեւորի նuտելու, իջնելու եւ (կամ) տրանuպորտային միջոցը բեռնելու, բեռնաթափելու, ինչպես նաև օրենսդրությամբ նախատեսված այլ դեպքերի։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (168, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (169, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ՀՀ զինված ուժեր եւ այլ զորքեր զորակոչված անձանց «D» կարգի եւ «D1» ենթակարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝', NULL, '["18 տարին լրացած անձանց։", "19 տարին լրացած անձանց։", "20 տարին լրացած անձանց։", "21 տարին լրացած անձանց։"]', '19 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (169, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (170, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի ձեռք բերման օրվանից ի՞նչ ժամկետում այն պետք է ներկայացվի պետական գրանցման՝ Ճանապարհային ոստիկանության մարմիններ։', NULL, '["15 օրվա ընթացքում։", "10 օրվա ընթացքում։", "20 օրվա ընթացքում։"]', '15 օրվա ընթացքում։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (170, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (171, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ճանապարհային երթեւեկությանը մասնակցող տրանսպորտային միջոցը տեխնիկապես սարքին վիճակում պահպանելու համար պատասխանատվություն կրում է՝', NULL, '["Տրանսպորտային միջոցի սեփականատերը կամ օգտագործողը։", "Տրանսպորտային միջոցը վաճառած կազմակերպությունը։", "Տրանսպորտային միջոցի՝ վերջին տարեկան տեխնիկական զննությունն իրականացրած կազմակերպությունը։", "Թվարկած բոլոր անձինք եւ կազմակերպությունները։"]', 'Տրանսպորտային միջոցի սեփականատերը կամ օգտագործողը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (171, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (172, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ երթեւեկությունը սկսելուց առաջ տրանսպորտային միջոցի վարորդը պարտավոր է ստուգել՝', NULL, '["Արգելակային համակարգի եւ ղեկային կառավարման սարքինությունը։", "Անվադողերի պահպանաշերտի նախշանկարի մնացորդային բարձրության համապատասխանությունը սահմանված նորմերին։", "Բոլոր թվարկածները։"]', 'Բոլոր թվարկածները։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (172, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (173, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի վարորդը պարտավոր է օժանդակելու նպատակով տրամադրել տրանսպորտային միջոցը՝', NULL, '["Ոստիկանության ծառայողներին՝ շտապ բժշկական օգնության կարիք ունեցող անձանց բժշկական հաստատություն տեղափոխելու համար։", "Բուժաշխատողներին, որոնք բուժօգնություն ցույց տալու համար մեկնում են համընթաց ուղղությամբ (վարորդի համաձայնությամբ)։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (173, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (174, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի վարորդը պարտավոր է ճանապարհատրանսպորտային պատահարին առընչություն ունենալու դեպքում՝', NULL, '["Անմիջապես կանգնեցնել տրանսպորտային միջոցը։", "Միացնել վթարային լուսային ազդանշանը։", "Չտեղաշարժել պատահարի հետ կապված առարկաները։", "Կատարել թվարկած բոլոր գործողությունները։"]', 'Կատարել թվարկած բոլոր գործողությունները։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (174, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (175, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ մեխանիկական տրանսպորտային միջոցի վարորդը պարտավոր է իր մոտ ունենալ՝', NULL, '["Տվյալ կարգի տրանսպորտային միջոցը վարելու վարորդական վկայականը եւ տրանսպորտային միջոցի հաշվառման փաստաթղթերը։", "Լիազորագիր՝ այլ անձին պատկանող տրանսպորտային միջոցը վարելու դեպքում։", "Թվարկած բոլոր փաստաթղթերը։"]', 'Տվյալ կարգի տրանսպորտային միջոցը վարելու վարորդական վկայականը եւ տրանսպորտային միջոցի հաշվառման փաստաթղթերը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (175, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (176, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ երթեւեկության գոտի է համարվում՝', NULL, '["Երթեւեկելի մասի գծանշված երկայնական գոտին, որի լայնությունը բավարար է տրանսպորտային միջոցների մեկ շարքով երթեւեկության համար։", "Երթեւեկելի մասի գծանշված կամ չգծանշված երկայնական գոտին, որի լայնությունը բավարար է տրանսպորտային միջոցների մեկ շարքով երթեւեկության համար։"]', 'Երթեւեկելի մասի գծանշված կամ չգծանշված երկայնական գոտին, որի լայնությունը բավարար է տրանսպորտային միջոցների մեկ շարքով երթեւեկության համար։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (176, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (177, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ թույլատրելի առավելագույն զանգված է համարվում՝', NULL, '["Լրակազմված եւ լիցքավորված տրանսպորտային միջոցի զանգվածը։", "Վարորդով, ուղեւորներով եւ բեռով բեռնված, լրակազմված ու լիցքավորված տրանսպորտային միջոցի զանգվածը։"]', 'Վարորդով, ուղեւորներով եւ բեռով բեռնված, լրակազմված ու լիցքավորված տրանսպորտային միջոցի զանգվածը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (177, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (178, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ կարգավորող է համարվում՝', NULL, '["Ճանապարհային երթեւեկությունը կարգավորելու իրավասություն ունեցող եւ օրենսդրությամբ սահմանված կարգով այդ կարգավորումն իրականացնող անձը։", "Երթեւեկության ցանկացած մասնակից (վարորդ, ուղեւոր կամ հետիոտն), որն անհրաժեշտությունն առաջանալու դեպքում կատարում է կարգավորող գործողություններ։", "Թվարկած բոլոր անձինք։"]', 'Ճանապարհային երթեւեկությունը կարգավորելու իրավասություն ունեցող եւ օրենսդրությամբ սահմանված կարգով այդ կարգավորումն իրականացնող անձը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (178, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (179, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոց վարել nսովորեցնողը՝', NULL, '["Հավասարեցվում է վարորդին։", "Չի հավասարեցվում վարորդին։"]', 'Հավասարեցվում է վարորդին։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (179, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (180, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ վթարային իրադրություն է համարվում՝', NULL, '["Երթեւեկության մասնակցի գործողության եւ (կամ) անգործության հետեւանքով առաջացած իրավիճակը, որի ժամանակ ստեղծվում է ճանապարհատրանսպորտային պատահարի իրական վտանգ։", "Երթեւեկության մասնակցի եւ (կամ) կարգավորողի գործողության եւ (կամ) անգործության հետեւանքով առաջացած իրավիճակը, որի ժամանակ ստեղծվում է ճանապարհատրանսպորտային պատահարի իրական վտանգ։"]', 'Երթեւեկության մասնակցի եւ (կամ) կարգավորողի գործողության եւ (կամ) անգործության հետեւանքով առաջացած իրավիճակը, որի ժամանակ ստեղծվում է ճանապարհատրանսպորտային պատահարի իրական վտանգ։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (180, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (181, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ օրվա մութ ժամանակ է համարվում՝', NULL, '["Աշնանը եւ ձմռանը` երեկոյան ժամը 20.00-ից մինչեւ առավոտյան ժամը 8.00-ը, գարնանը եւ ամռանը` երեկոյան ժամը 22.00-ից մինչեւ առավոտյան ժամը 6.00-ն ընկածժամանակահատվածը։", "Մթնշաղի վերջի եւ աղջամուղջի սկզբի միջեւ ընկած ժամանակահատվածը։", "Արեգակնային լուսավորության բացակայության ժամանակահատվածը։"]', 'Մթնշաղի վերջի եւ աղջամուղջի սկզբի միջեւ ընկած ժամանակահատվածը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (181, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (182, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ավտոբուս է համարվում՝', NULL, '["Ուղեւորների համար նախատեսված 8-ից ավելի նստատեղ ունեցող, իր կառուցվածքով եւ կահավորվածությամբ ուղեւորների եւ ուղեբեռի անվտանգ եւ հարմարավետ փոխադրման համար նախատեսված ավտոմոբիլը։", "Ուղեւորների համար նախատեսված 8 եւ ավելի նստատեղ ունեցող, իր կառուցվածքով եւ կահավորվածությամբ ուղեւորների եւ ուղեբեռի անվտանգ եւ հարմարավետ փոխադրման համար նախատեսված ավտոմոբիլը։"]', 'Ուղեւորների համար նախատեսված 8-ից ավելի նստատեղ ունեցող, իր կառուցվածքով եւ կահավորվածությամբ ուղեւորների եւ ուղեբեռի անվտանգ եւ հարմարավետ փոխադրման համար նախատեսված ավտոմոբիլը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (182, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (183, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ թեթեւ մարդատար ավտոմոբիլ է համարվում՝', NULL, '["Ուղեւորների համար նախատեսված 8-ից ոչ ավելի նստատեղ ունեցող, իր կառուցվածքով եւ կահավորվածությամբ ուղեւորների եւ ուղեբեռի անվտանգ եւ հարմարավետ փոխադրման համար նախատեսված ավտոմոբիլը։", "Ուղեւորների (բացառությամբ մինչեւ 12 տարեկան երեխաների) համար նախատեսված 4-ից ոչ ավելի նստատեղ ունեցող, իր կառուցվածքով եւ կահավորվածությամբ ուղեւորների եւ ուղեբեռի անվտանգ եւ հարմարավետ փոխադրման համար նախատեսված ավտոմոբիլը։"]', 'Ուղեւորների համար նախատեսված 8-ից ոչ ավելի նստատեղ ունեցող, իր կառուցվածքով եւ կահավորվածությամբ ուղեւորների եւ ուղեբեռի անվտանգ եւ հարմարավետ փոխադրման համար նախատեսված ավտոմոբիլը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (183, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (184, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ հետիոտներին են հավասարեցվում՝', NULL, '["Շարժիչ ունեցող հաշմանդամային սայլակով` հետիոտնի արագությամբ տեղաշարժվող հաշմանդամները։", "Հեծանիվ, մոպեդ կամ մոտոցիկլ տանող անձինք։", "Բոլոր թվարկած անձինք։"]', 'Բոլոր թվարկած անձինք։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (184, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (185, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցներ վարելու իրավունքը ծագում է՝', NULL, '["Ճանապարհային ոստիկանության ստորաբաժանումներում տրանսպորտային միջոցներ վարելու գործնական քննությունները դրական հանձնելու պահից։", "Վարորդական իրավունքի վկայական ստանալու պահից։"]', 'Վարորդական իրավունքի վկայական ստանալու պահից։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (185, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (186, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «A» եւ «B» կարգերի տրանսպորտային միջոցներ վարելու միջազգային վարորդական վկայականները կարող են տրվել՝', NULL, '["16 տարին լրացած անձանց։", "17 տարին լրացած անձանց։", "18 տարին լրացած անձանց։"]', '18 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (186, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (187, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «C» կարգի տրանսպորտային միջոցներ վարելու միջազգային վարորդական վկայական կարող է տրվել՝', NULL, '["18 տարին լրացած անձանց։", "20 տարին լրացած անձանց։", "21 տարին լրացած անձանց։"]', '21 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (187, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (188, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ազգային վարորդական վկայականները տրվում են՝', NULL, '["5 տարի ժամանակով։", "10 տարի ժամանակով։", "20 տարի ժամանակով։", "Անժամկետ։"]', '10 տարի ժամանակով։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (188, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (189, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն` միջազգային վարորդական վկայականները տրվում են՝', NULL, '["1 տարի ժամանակով։", "3 տարի ժամանակով։", "5 տարի ժամանակով։", "Անժամկետ։"]', '3 տարի ժամանակով։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (189, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (190, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ Ճանապարհային ոստիկանության ստորաբաժանումներում (բացառությամբ «AM» ենթակարգի տրանսպորտային միջոցի վարորդի թեկնածուի) վարորդի թեկնածուն կարող է մասնակցել գործնական քննության, եթե լրացել է նրա', NULL, '["15 տարին։", "16 տարին։", "17 տարին։"]', '17 տարին։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (190, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (191, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ կանգառ է համարվում՝', NULL, '["Տրանսպորտային միջոցն անշարժ վիճակի բերելը` կապված ուղեւորի պահանջի հետ։", "5 րոպեից ավելի ժամանակով տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը, եթե դա կապված չէ ուղեւորների նստեցման, իջեցման կամ տրանսպորտային միջոցի բեռնման, բեռնաթափման հետ։", "Մինչեւ 5 րոպե կամ ուղեւորի նստելու, իջնելու եւ (կամ) տրանսպորտային միջոցը բեռնելու, բեռնաթափելու համար անհրաժեշտ ժամանակով տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը։"]', 'Մինչեւ 5 րոպե կամ ուղեւորի նստելու, իջնելու եւ (կամ) տրանսպորտային միջոցը բեռնելու, բեռնաթափելու համար անհրաժեշտ ժամանակով տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (191, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (192, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ընդհանուր օգտագործման տրանսպորտային միջոց է համարվում՝', NULL, '["Կանգառի կետեր (կանգառներ) ունեցող, երթուղիներով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը (տրամվայ, տրոլեյբուս, ավտոբուս), ինչպես նաեւ թեթեւ մարդատար տաքսի ավտոմոբիլը։", "Կանգառի կետեր (կանգառներ) ունեցող, երթուղիներով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը (տրամվայ, տրոլեյբուս, ավտոբուս)։", "Զբոսաշրջային երթուղով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը։"]', 'Կանգառի կետեր (կանգառներ) ունեցող, երթուղիներով շարժվող, ուղեւորներ եւ (կամ) ուղեբեռներ տեղափոխող տրանսպորտային միջոցը (տրամվայ, տրոլեյբուս, ավտոբուս)։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (192, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (193, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի թույլատրելի առավելագույն զանգված է համարվում՝', NULL, '["Լրակազմված եւ լիցքավորված տրանսպորտային միջոցի առավելագույն զանգվածը։", "Վարորդով, ուղեւորներով եւ բեռով բեռնված, լրակազմված ու լիցքավորված տրանսպորտային միջոցի զանգվածը, որն արտադրող կազմակերպությունը սահմանել է որպես առավելագույն թույլատրելի։", "Վարորդով, ուղեւորներով եւ բեռով բեռնված տրանսպորտային միջոցի զանգվածը, որն արտադրող կազմակերպությունը սահմանել է որպես առավելագույն թույլատրելի։"]', 'Վարորդով, ուղեւորներով եւ բեռով բեռնված, լրակազմված ու լիցքավորված տրանսպորտային միջոցի զանգվածը, որն արտադրող կազմակերպությունը սահմանել է որպես առավելագույն թույլատրելի։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (193, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (194, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «B», «C», «D» կարգերի եւ «C1», «D1» ենթակարգերի տրանսպորտային միջոցներ վարելու իրավունքի վկայական ունեցող անձանց թույլատրվում է դրանք վարել նաեւ կցորդներով, եթե կցորդի առավելագույն թույլատրելի զանգված է։', NULL, '["950 կիլոգրամը։", "850 կիլոգրամը։", "750 կիլոգրամը։"]', '750 կիլոգրամը։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (194, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (195, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ ընդհանուր օգտագործման տրանսպորտային միջոցի կանգառի կետ է համարվում՝', NULL, '["Ընդհանուր օգտագործման տրանսպորտային միջոցի երթուղու որոշակի հատվածում ուղեւորների նստեցման-իջեցման համար նախատեսված եւ համապատասխան ճանապարհային նշաններով կահավորված վայր։", "Ընդհանուր օգտագործման տրանսպորտային միջոցի երթուղու որոշակի հատվածում ուղեւորների նստեցման-իջեցման համար նախատեսված վայր։"]', 'Ընդհանուր օգտագործման տրանսպորտային միջոցի երթուղու որոշակի հատվածում ուղեւորների նստեցման-իջեցման համար նախատեսված եւ համապատասխան ճանապարհային նշաններով կահավորված վայր։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (195, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (196, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «D» կարգի եւ «D1» ենթակարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել այն անձանց, ովքեր ունեն`', NULL, '["«B» կամ «C» կարգի կամ «C1» ենթակարգի տրանսպորտային միջոցներ վարելու վարորդական վկայական եւ լրացել է նրանց 21 տարին։", "«B» կարգի կամ «B1» ենթակարգի տրանսպորտային միջոցներ վարելու վարորդական վկայական եւ լրացել է նրանց 18 տարին։", "«AB» կարգերի կամ «A1B1» ենթակարգերի տրանսպորտային միջոցներ վարելու վարորդական վկայական եւ լրացել է նրանց 18 տարին։", "«B» կամ «C» կարգի կամ «C1» ենթակարգի տրանսպորտային միջոցներ վարելու վարորդական վկայական եւ լրացել է նրանց 20 տարին։"]', '«B» կամ «C» կարգի կամ «C1» ենթակարգի տրանսպորտային միջոցներ վարելու վարորդական վկայական եւ լրացել է նրանց 21 տարին։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (196, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (197, '«Ճանապարհային երթեւեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «D», «DE» կարգերի, «D1» եւ «D1E» ենթակարգերի տրանսպորտային միջոցներ վարելու միջազգային վարորդական իրավունքի վկայական կարող է տրվել՝', NULL, '["19 տարին լրացած անձանց։", "20 տարին լրացած անձանց։", "21 տարին լրացած անձանց։", "22 տարին լրացած անձանց։"]', '21 տարին լրացած անձանց։', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (197, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (198, 'Հողային ծածկույթով ճանապարհից դուրս գալով ասֆալտբետոնե ծածկույթ ունեցող ճանապարհ', NULL, '["Պետք է այն համարենք գլխավոր ճանապարհ", "Այդ ճանապարհը մեզ հավասարազոր ենք համարում"]', 'Պետք է այն համարենք գլխավոր ճանապարհ', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (198, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (199, 'Քանի՞ երթևեկության գոտիի կա այս երթևեկելի մասում', NULL, '["Մեկ", "Երկու", "Երեք"]', 'Երկու', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (199, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (200, 'Թո՞ւյլատրվում է արդյոք երթևեկել երթևեկելի մասի կենտրոնով նշված լայնության պայմաններում', NULL, '["Այո", "Այո, երբ հանդիպակաց երթևեկությունը բացակայում է", "Ոչ"]', 'Ոչ', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (200, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (201, 'Նշվածներից ո՞ր անշարժ օբյեկտը արգելք չի հանդիսանում', NULL, '["Երթևեկելի մասի ծածկույթի վնասվածքը", "Կողմնակի առարկան", "Անսարք կամ անշարժ ավտոմեքենան", "Խցանման պատճառով կանգ առած ավտոմեքնան"]', 'Խցանման պատճառով կանգ առած ավտոմեքնան', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (201, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (202, 'Ճանապարհի մաս հանդիսանում են արդյո՞ք մայթը կամ կողնակները', NULL, '["Այո", "Միայն կողնակը", "Ոչ"]', 'Այո', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (202, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (203, 'Քանի՞ երթևեկելի մասեր ունի այս ճանապարհը', NULL, '["Մեկ", "Երկու", "Չորս"]', 'Երկու', 2);
