INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (207, 'Ո՞ր նկարում ճանապարհը բաժանարար գոտի ունի', NULL, '["Միայն աջ", "Երկու դեպքում", "Միայն ձախ"]', 'Երկու դեպքում', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (207, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (208, 'Զիջել ճանապարհն այլ տրանսպորտային միջոցների նշանակում է', NULL, '["Վարորդը չպետք է շարունակի կամ վերսկսի շարժումը կամ կատարի որևէ մանևր, եթե դա կարող է այլ տրանսպորտային միջոցների վարորդներին ստիպել փոխել շարժման ուղղությունը կամ արագությունը:", "Վարորդը չպետք է շարունակի կամ վերսկսի շարժումը կամ կատարի որևէ մանևր, եթե դա կարող է այլ տրանսպորտային միջոցների վարորդներին ստիպել անսպասելի փոխել շարժման ուղղությունը կամ արագությունը", "Անվերապահորեն կանգնեցնել տրանսպորտային միջոցը:"]', 'Վարորդը չպետք է շարունակի կամ վերսկսի շարժումը կամ կատարի որևէ մանևր, եթե դա կարող է այլ տրանսպորտային միջոցների վարորդներին ստիպել անսպասելի փոխել շարժման ուղղությունը կամ արագությունը', 2);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (208, 1);
