INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (244, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question245_image.png', '["Առջեւի մասում տեղադրված են սպիտակ գույնի լուսանդրադարձնող հարմարանքներ։", "Անսարք է քարշակի քարշակցման հարմարանքը։", "Երկու դեպքում էլ։"]', 'Անսարք է քարշակի քարշակցման հարմարանքը։', 3);
