INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (245, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question246_image.png', '["Բացակայում են կառուցվածքով նախատեսված անվտանգության ամրագոտիները։", "Հետեւի մասում տեղադրված են սպիտակ գույնի լույսերով հետընթացի լապտերիկներ։", "Երկու դեպքում էլ։"]', 'Բացակայում են կառուցվածքով նախատեսված անվտանգության ամրագոտիները։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (245, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (246, 'Կողային կցորդով մոտոցիկլների շահագործումն արգելվում է, եթե՝', 'question247_image.png', '["Բացակայում է կառուցվածքով նախատեսված` թամբի վրայի ուղեւորի համար լայնակի բռնատեղը։", "Դողերի պահպանաշերտի մնացորդային բարձրությունը կազմում է 0.6 մմ։", "Բացակայում է բժշկական դեղատուփը։", "Թվարկած բոլոր դեպքերում։"]', 'Թվարկած բոլոր դեպքերում։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (246, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (247, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question248_image.png', '["Չի աշխատում կառուցվածքով նախատեսված` վարորդի նստատեղի դիրքը կարգավորող մեխանիզմը։", "Չեն աշխատում ավտոբուսի սրահի ներքին լուսավորության սարքերը։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (247, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (248, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question249_image.png', '["Չեն աշխատում թեթեւ մարդատար ավտոմոբիլի սրահի ներքին լուսավորության սարքերը։", "Բացակայում են կառուցվածքով նախատեսված նստատեղերի գլխակալները։", "Երկու դեպքում էլ։"]', 'Բացակայում են կառուցվածքով նախատեսված նստատեղերի գլխակալները։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (248, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (249, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question250_image.png', '["Հետեւի մասում տեղադրված են կարմիր գույնի լուսանդրադարձնող հարմարանքներ։", "Չի աշխատում կառուցվածքով նախատեսված արագաչափը։", "Երկու դեպքում էլ։"]', 'Չի աշխատում կառուցվածքով նախատեսված արագաչափը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (249, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (250, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question251_image.png', '["Թեթեւ մարդատար ավտոմոբիլի ղեկային կառավարման համակարգի գումարային խաղացքը գերազանցում է 10 աստիճանը։", "Բացակայում են կառուցվածքով նախատեսված ցեխապաշտպան գոգնոցները եւ ցայտապաշտպանիչները։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (250, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (251, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question252_image.png', '["Դժվարությամբ է գործի դրվում շարժիչը։", "Ավտոբուսում բացակայում է բժշկական դեղատուփը։", "Երկու դեպքում էլ։"]', 'Ավտոբուսում բացակայում է բժշկական դեղատուփը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (251, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (252, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question253_image.png', '["Թեթեւ մարդատար ավտոմոբիլում բացակայում է բժշկական դեղատուփը։", "Հետեւի մասում տեղադրված են կարմիր գույնի լույսերով հետընթացի լապտերիկներ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (252, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (253, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question254_image.png', '["Ավտոբուսում բացակայում է «Վթարային կանգառ» նշանը։", "Հետեւի մասում տեղադրված են սպիտակ գույնի լույսերով հաշվառման համարանիշի լուսավորման լապտերիկներ։", "Երկու դեպքում էլ։"]', 'Ավտոբուսում բացակայում է «Վթարային կանգառ» նշանը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (253, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (254, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question255_image.png', '["Թեթեւ մարդատար ավտոմոբիլի կցորդի դողերի պաշտպանաշերտի նախշանկարի մնացորդային բարձրությունը պակաս է 1,6 մմ-ից։", "Հետեւի մասում տեղադրված են նարնջագույն լույսերով շրջադարձի ցուցիչներ։", "Երկու դեպքում էլ։"]', 'Թեթեւ մարդատար ավտոմոբիլի կցորդի դողերի պաշտպանաշերտի նախշանկարի մնացորդային բարձրությունը պակաս է 1,6 մմ-ից։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (254, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (255, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question256_image.png', '["Խախտված է հիդրավլիկ արգելակային հաղորդակի հերմետիկությունը։", "Հետեւի մասում տեղադրված են սպիտակ գույնի լույսերով շրջադարձի ցուցիչներ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (255, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (256, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question257_image.png', '["Նույն սռնու վրա տեղադրված են տարբեր կառուցվածքների դողեր։", "Խախտված է շարժիչի սնման համակարգի հերմետիկությունը։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (256, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (257, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question258_image.png', '["Չի աշխատում ձայնային ազդանշանի սարքը։", "Հովացման համակարգը չի ապահովում շարժիչի աշխատանքի կայուն ջերմային ռեժիմը։", "Երկու դեպքում էլ։"]', 'Չի աշխատում ձայնային ազդանշանի սարքը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (257, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (258, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question259_image.png', '["Ղեկային կառավարման պարուրակային միացումները ձգված կամ սահմանված ձեւով սեւեռված չեն։", "Ավտոբուսում բացակայում են կրակմարիչները։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (258, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (259, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question260_image.png', '["Առկա են ղեկային կառավարման մանրամասերի (դետալների) ու հանգույցների կառուցվածքով չնախատեսված տեղաշարժեր։", "Առջեւի մասում տեղադրված են սպիտակ գույնի լույսերով շրջադարձի ցուցիչներ։", "Երկու դեպքում էլ։"]', 'Առկա են ղեկային կառավարման մանրամասերի (դետալների) ու հանգույցների կառուցվածքով չնախատեսված տեղաշարժեր։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (259, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (260, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question261_image.png', '["Ավտոբուսի դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 1.8 մմ։", "Խախտված է հիդրավլիկ արգելակային հաղորդակի հերմետիկությունը։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (260, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (261, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question262_image.png', '["Չի գործում պնեւմատիկ արգելակային հաղորդակի ճնշաչափը։", "Ավտոբուսի դողերի պահպանաշերտի մնացորդային բարձրությունը կազմում է 1.6 մմ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (261, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (262, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question263_image.png', '["Սահմանված ռեժիմով չեն աշխատում արտաքին լուսային սարքերը։", "Ավտոբուսի դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 0.8 մմ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (262, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (263, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question264_image.png', '["Շարժիչն աշխատում է ընդհատումներով։", "Դողերն ունեն անվադողի հենքը (կորդը) մերկացնող տեղային վնասվածքներ։", "Երկու դեպքում էլ։"]', 'Դողերն ունեն անվադողի հենքը (կորդը) մերկացնող տեղային վնասվածքներ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (263, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (264, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question265_image.png', '["Բացակայում է բժշկական դեղատուփը։", "Դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 2,2 մմ։", "Երկու դեպքում էլ։"]', 'Բացակայում է բժշկական դեղատուփը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (264, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (265, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question266_image.png', '["Չեն աշխատում թեթեւ մարդատար ավտոմոբիլի սրահի ներքին լուսավորության սարքերը։", "Չեն աշխատում ավտոբուսի սրահի ներքին լուսավորության սարքերը։", "Երկու դեպքում էլ։"]', 'Չեն աշխատում ավտոբուսի սրահի ներքին լուսավորության սարքերը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (265, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (266, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question267_image.png', '["Թեթեւ մարդատար ավտոմոբիլի բազայի վրա պատրաստված ավտոբուսի մոտ ղեկային կառավարման համակարգի գումարային խաղացքը գերազանցում է 10 աստիճանը։", "Բացակայում են կառուցվածքով նախատեսված ցեխապաշտպան գոգնոցները եւ ցայտապաշտպանիչները։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (266, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (267, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question268_image.png', '["Թեթեւ մարդատար ավտոմոբիլի բազայի վրա պատրաստված ավտոբուսի ղեկային կառավարման համակարգի գումարային խաղացքը 15 աստիճան է։", "Ավտոբուսի ղեկային կառավարման համակարգի գումարային խաղացքը 15 աստիճան է։", "Երկու դեպքում էլ։"]', 'Թեթեւ մարդատար ավտոմոբիլի բազայի վրա պատրաստված ավտոբուսի ղեկային կառավարման համակարգի գումարային խաղացքը 15 աստիճան է։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (267, 9);
