INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (269, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (270, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question271_image.png', '["Չեն աշխատում դռների վթարային բացիչները։", "Առջևի մասում տեղադրված են կարմիր գույնի լույսերով շրջադարձի ցուցիչներ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
