INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (271, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question272_image.png', '["Չի աշխատում կանգառ կատարելու պահանջի ազդանշանը։", "Հետևի մասում տեղադրված են կարմիր գույնի լույսերով շրջադարձի ցուցիչներ։", "Երկու դեպքում էլ։"]', 'Չի աշխատում կանգառ կատարելու պահանջի ազդանշանը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (271, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (272, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question273_image.png', '["Դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 1.6 մմ։", "Չի աշխատում շարժիչը հովացնող հեղուկի ջերմաստիճանի ցուցիչը։", "Երկու դեպքում էլ։"]', 'Դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 1.6 մմ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (272, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (273, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question274_image.png', '["Դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 2.5 մմ։", "Չեն աշխատում սրահի ներքին լուսավորության սարքերը։", "Երկու դեպքում էլ։"]', 'Չեն աշխատում սրահի ներքին լուսավորության սարքերը։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (273, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (274, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question275_image.png', '["Չեն աշխատում վթարային ելքերը եւ դրանք գործողության մեջ դնող հարմարանքները։", "Չի աշխատում կանգառ կատարելու պահանջի ազդանշանը։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (274, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (275, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question276_image.png', '["Չի աշխատում դռների կառավարման հաղորդակը։", "Բացակայում է բժշկական դեղատուփը։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (275, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (276, '5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question277_image.png', '["Բացակայում են հակագլորման հենակները։", "Հետեւի մասում տեղադրված են կարմիր գույնի հետընթացի լապտերիկներ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (276, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (277, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question278_image.png', '["Առկա է մեկ հատ կրակմարիչ։", "Բացակայում է «Վթարային կանգառ» նշանը։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (277, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (278, 'Ավտոբուսների շահագործումն արգելվում է, եթե՝', 'question279_image.png', '["Առկա է հակագլորման մեկ հենակ։", "Առկա է մեկ կրակմարիչ։", "Երկու դեպքում էլ։"]', 'Երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (278, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (279, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question280_image.png', '["չի աշխատում կառուցվածքով նախատեսված թափքի դռան փականի։", "չի աշխատում կառուցվածքով նախատեսված խցիկի դռան փականի։", "երկու դեպքում էլ։"]', 'երկու դեպքում էլ։', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (279, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (280, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question281_image.png', '["Հետևի մասում տեղադրված են կարմիր գույնի լույսերով շրջադարձի լուսային ցուցիչներ:", "Բացակայում է կառուցվածքով նախատեսված հետին պաշտպանիչ հարմարանքը:", "Երկու դեպքում էլ:"]', 'Բացակայում է կառուցվածքով նախատեսված հետին պաշտպանիչ հարմարանքը:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (280, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (281, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question282_image.png', '["անսարք է կամ բացակայում է կառուցվածքով նախատեսված ղեկային կառավարման ուժեղարարը:", "չի աշխատում ձայնարկիչը:", "երկու դեպքում էլ:"]', 'անսարք է կամ բացակայում է կառուցվածքով նախատեսված ղեկային կառավարման ուժեղարարը:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (281, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (282, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question283_image.png', '["կայանման արգելակային համակարգը ստանդարտով սահմանված թեքության վրա չի ապահովում անշարժ վիճակ:", "խախտված է փոխանցման տուփի կիպարարների հերմետիկությունը:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (282, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (283, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question284_image.png', '["չի աշխատում պահեստային անիվի բռնիչը:", "խախտված է հետին կամրջակի կիպարարների հերմետիկությունը:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (283, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (284, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question285_image.png', '["կառուցվածքով նախատեսված անվտանգության ամրագոտիների ժապավենի վրա առկա են տեսանելի պատռվածքներ:", "կահավորված չէ հակամառախուղային լապտերիկներով:", "երկու դեպքում էլ:"]', 'կառուցվածքով նախատեսված անվտանգության ամրագոտիների ժապավենի վրա առկա են տեսանելի պատռվածքներ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (284, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (285, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question286_image.png', '["չի աշխատում կառուցվածքով նախատեսված շարժիչի ծածկոցի փականի:", "վարագուրապատված են հետին կողային ապակիները և առկա են հետին տեսանելիության 2 կողային հայելիները:", "երկու դեպքում էլ:"]', 'չի աշխատում կառուցվածքով նախատեսված շարժիչի ծածկոցի փականի:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (285, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (286, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question287_image.png', '["վարագուրապատված են հետին կողային ապակիները և բացակայում են հետին տեսանելիության 2 կողային հայելիները:", "չեն աշխատում կառուցվածքով նախատեսված ապակիների տաքացման ու փչահարման սարքերը:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (286, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (287, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question288_image.png', '["չի աշխատում կառուցվածքով նախատեսված վառելիքի բաքի խցանը:", "առջևի կողային ապակիները վարագուրապատված են:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (287, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (288, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question289_image.png', '["ձայնային ազդանշանի սարքով տրվող ազդանշանը չի աշխատում:", "բացակայում են տրանսպորտային միջոցի կառուցվածքով նախատեսված ապակիները:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (288, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (289, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question290_image.png', '["անվահեցի կամ անվասկավառակի վրա առկա են ճաքեր:", "անվահեցի ամրացման անցքերի ձևի և չափերի տեսանելի խախտումներ են առկա:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (289, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (290, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question291_image.png', '["կեղտոտված են արտաքին լուսային սարքերը և լուսանդրադարձիչները:", "կեղտոտված են առջևի և հետին պաշտպանիչ հարմարանքները:", "երկու դեպքում էլ:"]', 'կեղտոտված են արտաքին լուսային սարքերը և լուսանդրադարձիչները:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (290, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (291, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question292_image.png', '["լուսային սարքերի վրա բացակայում են լամպերը կամ ցրիչները:", "օգտագործվում են տվյալ լուսային սարքի տեսակին չհամապատասխանող ցրիչներ կամ լամպեր:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (291, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (292, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question293_image.png', '["կեղտոտված են արտաքին լուսային սարքերը և լուսանդրադարձիչները:", "արտադրությունից հանված տրանսպորտային միջոցի վրա տեղադրված է այլ մակնիշի տրանսպորտային միջոցի արտաքին լուսային սարքեր:", "երկու դեպքում էլ:"]', 'կեղտոտված են արտաքին լուսային սարքերը և լուսանդրադարձիչները:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (292, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (293, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question294_image.png', '["տրանսպորտային միջոցի նույն սռնու վրա տեղադրված են պահպանաշերտի տարբեր նախշանկարներով դողեր:", "թեթև մարդատար ավտոմոբիլի դողի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 1,6մմ:", "երկու դեպքում էլ:"]', 'տրանսպորտային միջոցի նույն սռնու վրա տեղադրված են պահպանաշերտի տարբեր նախշանկարներով դողեր:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (293, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (294, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question295_image.png', '["բեռնատար ավտոմոբիլի դողի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը կազմում է 1,4մմ:", "առջևի մասում տեղադրված են դեղին գույնի լուսաանդրադարձնող հարմարանքներ:", "երկու դեպքում էլ:"]', 'առջևի մասում տեղադրված են դեղին գույնի լուսաանդրադարձնող հարմարանքներ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (294, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (295, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question296_image.png', '["հետևի մասում տեղադրված են դեղին գույնի լուսաանդրադարձնող հարմարանքներ:", "առջևի մասում տեղադրված են դեղին գույնի լուսաանդրադարձնող հարմարանքներ:", "երկու դեպքում էլ:"]', 'երկու դեպքում էլ:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (295, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (296, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', 'question297_image.png', '["Բժիշկ-վարորդի կողմից վարած ավտոմոբիլի վրա բացակայում է ''Բժիշկ'' ճանաչման նշանը:", "չի աշխատում կառուցվածքով նախատեսված վառելիքի բաքի խցանը:", "երկու դեպքում էլ:"]', 'չի աշխատում կառուցվածքով նախատեսված վառելիքի բաքի խցանը:', 3);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (296, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (297, 'Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝', NULL, '["տրանսպորտային միջոցի նույն սռնու վրա տեղադրված են պահպանաշերտի տարբեր նախշանկարներով դողեր:", "առջևի մասում դեղին լուսանդրադարձնող հիմնագույնով և կամիր լուսանդրադարձնող եզրագծերով տեղադրված է ''Երեխաների փոխադրում'' ճանաչման նշանը:", "երկու դեպքում էլ:"]', 'տրանսպորտային միջոցի նույն սռնու վրա տեղադրված են պահպանաշերտի տարբեր նախշանկարներով դողեր:', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (297, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (298, 'Թույլատրվու՞մ է արդյոք մուտք գործել այս նշանով նշված գոտի աջ շրջադարձ կատարելիս։', NULL, '["Թույլատրվում է։", "Արգելվում է։", "Թույլատրվում է, եթե այդ գոտին մնացած երթեւեկելի մասից բաժանված չէ գծանշման հոծ գծով։"]', 'Թույլատրվում է, եթե այդ գոտին մնացած երթեւեկելի մասից բաժանված չէ գծանշման հոծ գծով։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (298, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (299, 'Այս ճանապարհային նշանը ցույց է տալիս`', NULL, '["Ճանապարհի հատված, որտեղ առկա է մայթ կամ հետիոտնային արահետ։", "Ճանապարհի հատված, որտեղ առկա է հետիոտնային անցում։", "Ճանապարհի հատված, որտեղ բացակայում է մայթ կամ հետիոտնային արահետ։"]', 'Ճանապարհի հատված, որտեղ առկա է հետիոտնային անցում։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (299, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (300, 'Նշաններից ո՞րն է արգելում երթեւեկությունը նշանի վրա պատկերվածից ավելի փոքր միջտարածությամբ։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (300, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (301, 'Ճանապարհի վտանգավոր հատվածի տեղամասից ի՞նչ հեռավորության վրա են տեղադրվում այս նշանները բնակավայրերում։', NULL, '["15 - 25 մ։", "25 - 50 մ։", "50 - 100 մ։", "100 - 150 մ։", "150 - 300 մ։"]', '50 - 100 մ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (301, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (302, 'Այս ճանապարհային նշանը՝', NULL, '["Արգելում է բոլոր մեխանիկական տրանսպորտային միջոցների երթեւեկությունը՝ բացառությամբ առանց կողային կցորդի երկանիվ մոտոցիկլների։", "Արգելվում է բոլոր տրանսպորտային միջոցների երթեւեկությունը՝ բացառությամբ անվավոր տրակտորների։", "Արգելվում է տրակտորների եւ ինքնագնաց մեքենաների երթեւեկությունը։"]', 'Արգելվում է տրակտորների եւ ինքնագնաց մեքենաների երթեւեկությունը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (302, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (303, 'Նշաններից ո՞րն է պարտադրում զիջել ճանապարհը հանդիպակաց ուղղությամբ ճանապարհի նեղ հատված մուտք գործող կամ դրան մոտեցող տրանսպորտային միջոցներին։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (303, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (304, 'Նշաններից ո՞րն է նախազգուշացնում հավասարազոր ճանապարհների խաչմերուկին մոտենալու մասին։', NULL, '["1", "2", "3", "4", "5"]', '5', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (304, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (305, 'Նշաններից ո՞րն է տեղադրվում երթեւեկելի մասերի հատումից անմիջապես առաջ։', NULL, '["1", "2", "3", "4", "5"]', '2', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (305, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (306, 'Այս նշանները թույլատրում են երթեւեկությունը`', NULL, '["Միայն դեպի ձախ։", "Միայն ուղիղ։", "Միայն դեպի աջ։", "Ուղիղ, դեպի աջ եւ հակառակ ուղղությամբ։"]', 'Ուղիղ, դեպի աջ եւ հակառակ ուղղությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (306, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (307, 'Նշաններից ո՞րն է վարորդին առավելություն տալիս հանդիպակաց տրանսպորտային միջոցների նկատմամբ։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (307, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (308, 'Ի՞նչ է նշանակում նշանի տակ տեղադրված ցուցանակը։', NULL, '["Նշանից մինչեւ առաջին շրջադարձի սկիզբը եղած հեռավորությունը։", "Առաջին շրջադարձից մինչեւ երկրորդ շրջադարձի սկիզբը եղած հեռավորությունը։", "Վտանգավոր շրջադարձերով ճանապարհի հատվածի երկարությունը։"]', 'Վտանգավոր շրջադարձերով ճանապարհի հատվածի երկարությունը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (308, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (309, 'Ի՞նչ են նշանակում հետեւյալ նշանները։', NULL, '["Մոտոցիկլների երթեւեկությունը դեպի աջ արգելվում է։", "Մոտոցիկլների երթեւեկությունը դեպի աջ թույլատրվում է։"]', 'Մոտոցիկլների երթեւեկությունը դեպի աջ արգելվում է։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (309, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (310, 'Նշաններից ո՞րն է արգելում կայանումն ամսվա զույգ օրերին։', NULL, '["1", "2", "3", "4", "5"]', '5', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (310, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (311, 'Այս ճանապարհային նշանը՝', NULL, '["Թույլատրում է երթեւեկել միայն նշված կամ ավելի բարձր արագությամբ։", "Արգելում է երթեւեկել նշանի վրա նշվածից ավելի բարձր արագությամբ։", "Ցույց է տալիս այն արագությունը, որով առաջարկվում է երթեւեկել ճանապարհի տվյալ հատվածում։"]', 'Թույլատրում է երթեւեկել միայն նշված կամ ավելի բարձր արագությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (311, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (312, 'Հետեւյալ նշաններից ո՞րն է պարտադրում զիջել ճանապարհը հանդիպակաց երթեւեկող տրանսպորտային միջոցներին։', 'question313_image.png', '["1", "2", "3", "4", "5"]', '2', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (312, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (313, 'Այս նշանը կոչվում է՝', NULL, '["Արգելքի շրջանցման նախնական ցուցիչ։", "Այլ երթեւեկելի մաս վերադասավորվելու նախնական ցուցիչ։", "Հանդիպակաց երթեւեկության գոտի դուրս գալու նախնական ցուցիչ։"]', 'Այլ երթեւեկելի մաս վերադասավորվելու նախնական ցուցիչ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (313, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (314, 'Նշաններից ո՞րն է պարտադրում զիջել ճանապարհը հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (314, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (315, 'Թույլատրվու՞մ է արդյոք ավտոբուսի վարորդին վազանց կատարել այս նշանի ազդման գոտում։', NULL, '["Թույլատրվում է բոլոր դեպքերում՝ վ dépasser, вразү дзе.и спанское, ́неку.", "Չի թույլատրվում։", "Թույլատրվում է, եթե վազանցվող տրանսպորտային միջոցի արագությունը չի գերազանցում 30 կմ/ժ։"]', 'Թույլատրվում է բոլոր դեպքերում՝ վ dépasser, вразү дзе.и спанское, ́неку.', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (315, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (316, 'Հետեւյալ նշաններից ո՞րն է թույլատրում երթեւեկել միայն նշված (կմ/ժ) կամ ավելի բարձր արագությամբ։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (316, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (317, 'Նշաններից ո՞րն է ցույց տալիս միակողմ երթեւեկության ճանապարհի հատվածը։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (317, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (318, 'Ի՞նչ է ցույց տալիս այս նշանի տակ տեղադրված ցուցանակը՝', NULL, '["Ճանապարհի նեղ հատվածի երկարությունը։", "Նշանից մինչեւ սահմանափակման տեղն ընկած հեռավորությունը։", "Մինչեւ ճանապարհի նեղ հատվածի շրջանցման տեղն ընկած հեռավորությունը։"]', 'Նշանից մինչեւ սահմանափակման տեղն ընկած հեռավորությունը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (318, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (319, 'Այս ճանապարհային նշանը նախազգուշացնում է, որ առջեւում՝', NULL, '["Կամուրջ կամ լաստանավային անցում չունեցող ջրային արգելքով ճանապարհահատված է։", "Ջրային արգելքով ճանապարհահատված է, որի վրա առկա է բացվող կամուրջ։", "Տեղամաս է, որտեղ ճանապարհը դուրս է գալիս ափ կամ առափ։"]', 'Տեղամաս է, որտեղ ճանապարհը դուրս է գալիս ափ կամ առափ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (319, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (320, 'Նշաններից ո՞րն է ցույց տալիս տրանսպորտային միջոցների կանգառն ու կայանելն արգելող ճանապարհային նշանների ազդեցության գոտին։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (320, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (321, 'Հետեւյալ նշաններից ո՞րն է ցույց տալիս նախազգուշացնող նշանների ազդեցության` ճանապարհի վտանգավոր հատվածի երկարությունը։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (321, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (322, 'Այս ճանապարհային նշանը ցույց է տալիս՝', NULL, '["Միակողմ երթեւեկությամբ ճանապարհ, որով թույլատրվում է միայն բեռնատար ավտոմոբիլների երթեւեկությունը։", "Միայն բեռնատար ավտոմոբիլների երթեւեկության համար նախատեսված գոտին։", "Բեռնատար ավտոմոբիլների համար առաջարկվող երթեւեկության ուղղությունը։"]', 'Բեռնատար ավտոմոբիլների համար առաջարկվող երթեւեկության ուղղությունը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (322, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (323, 'Նշաններից ո՞րն է կոչվում «Հյուրանոց» կամ «Մոթել»։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (323, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (324, 'Այսպիսի ճանաչման նշանով կահավորվում են այն ավտոմոբիլները, որոնք՝', NULL, '["Փոխադրում են վտանգավոր բեռներ։", "Ղեկավարվում են հաշմանդամների կողմից։", "Ղեկավարվում են խուլ կամ խուլ ու համր վարորդների կողմից։", "Ղեկավարվում են մինչեւ 3 տարի վարորդական փորձ ունեցող վարորդների կողմից։"]', 'Ղեկավարվում են խուլ կամ խուլ ու համր վարորդների կողմից։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (324, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (325, 'Նշաններից ո՞րն է ցույց տալիս 50 կմ/ժ առավելագույն արագության սահմանափակման գոտու վերջը։', NULL, '["1", "2", "3", "4", "5"]', '2', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (325, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (326, 'Ինչի՞ մասին են զգուշացնում այս նշանը եւ ցուցանակը։', NULL, '["Նորոգման աշխատանքների կատարման պատճառով ճանապարհի կողնակին կանգառ կատարելը արգելվում է։", "Նորոգման աշխատանքների կատարման պատճառով ճանապարհի կողնակ մուտք գործելը վտանգավոր է։", "Նորոգման աշխատանքների կատարման պատճառով ճանապարհի կողնակին կայանելն արգելվում է։"]', 'Նորոգման աշխատանքների կատարման պատճառով ճանապարհի կողնակ մուտք գործելը վտանգավոր է։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (326, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (327, 'Այսպիսի ճանաչման նշանով են կահավորվում այն տրանսպորտային միջոցները, որոնք՝', NULL, '["Ղեկավարվում են հաշմանդամների կողմից։", "Փոխադրում են ծանրաքաշ եւ մեծ եզրաչափերով բեռներ։", "Փոխադրում են վտանգավոր բեռներ։", "Ղեկավարվում են խուլ կամ խուլ ու համր վարորդների կողմից։"]', 'Փոխադրում են վտանգավոր բեռներ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (327, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (328, 'Նշաններից ո՞րն է վերացնում նախկին բոլոր սահմանափակումները։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (328, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (329, 'Ո՞ր դեպքում է վարորդը ճիշտ կատարել այս նշանի պահանջները։', NULL, '["Զիջել է ճանապարհը հատվող ճանապարհով ընթացող մեխանիկական տրանսպորտային միջոցներին։", "Զիջել է ճանապարհը հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։"]', 'Զիջել է ճանապարհը հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (329, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (330, 'Տեղադրվածներից ո՞րն է կիրառվում որպես ավտոգնացքի ճանաչման նշան։', NULL, '["Ձախ նշանը։", "Աջ նշանը։", "Երկու նշաններն էլ։"]', 'Աջ նշանը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (330, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (331, 'Ո՞ր նշանն է պարտադրում զիջել ճանապարհը հատվող ճանապարհով երթեւեկող տրանսպորտային միջոցներին։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (331, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (332, 'Հետեւյալ նշաններից (ցուցանակներից) ո՞րն է ցույց տալիս տրանսպորտային միջոցի կանգնեցման ձեւը կայանման տեղերում։', NULL, '["1", "2", "3", "4", "5"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (332, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (333, 'Թույլատրվու՞մ է արդյոք ուղեւորներ նստեցնելու համար կանգ առնել այս նշանով նշված գոտու վրա։', NULL, '["Թույլատրվում է, եթե այդ գոտին գտնվում է երթեւեկելի մասի աջ եզրի մոտ եւ մնացած երթեւեկելի մասից բաժանված չէ գծանշման հոծ գծով։", "Արգելվում է։", "Թույլատրվում է։"]', 'Թույլատրվում է, եթե այդ գոտին գտնվում է երթեւեկելի մասի աջ եզրի մոտ եւ մնացած երթեւեկելի մասից բաժանված չէ գծանշման հոծ գծով։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (333, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (334, 'Այս ճանապարհային նշանի առկայության դեպքում՝', NULL, '["Արգելվում է բոլոր տեսակի տրանսպորտային միջոցներով վազանցի կատարումը, բացառությամբ դանդաղընթաց տրանսպորտային միջոցների, լծասայլերի, առանց կողային կցորդի երկանիվ մոտոցիկլների, մոպեդների եւ հեծանիվների։", "Թույլատրվում է 3.5 տ ոչ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներով վ Matemակատարման։", "Թույլատրվում է վազանցի կատարումը, եթե վազանցող տրանսպորտային միջոցի արագությունը չի գերազանցում 30 կմ/ժ։"]', 'Արգելվում է բոլոր տեսակի տրանսպորտային միջոցներով վազանցի կատարումը, բացառությամբ դանդաղընթաց տրանսպորտային միջոցների, լծասայլերի, առանց կողային կցորդի երկանիվ մոտոցիկլների, մոպեդների եւ հեծանիվների։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (334, 1);
