INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (336, 'Նշաններից ո՞րն է ցույց տալիս երթեւեկության ուղղությունները T-աձեւ խաչմերուկում։', NULL, '["1", "2", "3", "4", "5"]', '2', 4);
