INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (337, 'Այս ճանապարհային նշանը ցույց է տալիս՝', NULL, '["Միջանցիկ անցում չունեցող ճանապարհ։", "Երթեւեկության ուղղությունը դեպի բնակավայրում գտնվող օբյեկտ։", "Թափառքի գոտու կամ վերելքի վրա լրացուցիչ գոտու վերջը։"]', 'Միջանցիկ անցում չունեցող ճանապարհ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (337, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (338, 'Ո՞ ր նշանի ազդեցությունը չի տարածվում ընդհանուր օգտագործման տրանսպորտային միջոցների վրա։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (338, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (339, 'Ո՞ր տրանսպորտային միջոցների երթեւեկությունն է թույլատրվում այս նշանի ազդեցության ճանապարհներին։', NULL, '["Մեխանիկական տրանսպորտային միջոցների։", "Բոլոր տրանսպորտային միջոցների։", "Ավտոմոբիլների եւ մոտոցիկլների։", "Այն տրանսպորտային միջոցների, որոնց առավելագույն արագությունը գերազանցում է 40 կմ/ժ։"]', 'Ավտոմոբիլների եւ մոտոցիկլների։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (339, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (340, 'Այս ճանապարհային նշաններից ո՞րը չի համարվում արգելող։', NULL, '["1", "2", "3", "4", "5"]', '2', 4);
