INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (341, 'Ի՞նչ է նշանակում այս ճանաչման նշանը։', NULL, '["Առջեւում երթեւեկելի մասի անհարթություններ ունեցող ճանապարհի հատված է։", "Առջեւում տվյալ ուղղությամբ երթեւեկելու համար երեք գոտի ունեցող ճանապարհի հատված է։", "Մեխանիկական տրանսպորտային միջոցի վրա տեղադրված են բութակավոր դողեր։"]', 'Մեխանիկական տրանսպորտային միջոցի վրա տեղադրված են բութակավոր դողեր։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (341, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (342, 'Նշաններից ո՞րն է կոչվում «Միակողմ երթեւեկությամբ ճանապարհի վերջ»։', NULL, '["1", "2", "3", "4", "5"]', '4', 4);
