INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (343, 'Նշաններից ո՞րն է պարտադրում զիջել ճանապարհը հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։', NULL, '["1", "2", "3", "4", "5"]', '2', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (343, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (344, 'Հետեւյալ նշանները ցույց են տալիս՝', NULL, '["Կայանման տեղը 30 մետրից` «Հաշմանդամներ» ճանաչման նշանով կահավորված ավտոմոբիլների համար։", "Կայանման տեղը 30 մ երկարությամբ գոտում` տրանսպորտային միջոցների համար` բացառությամբ մոտոսայլակների։", "Կայանման տեղը 30 մ երկարությամբ գոտում` մոտոսայլակների եւ «Հաշմանդամ» ճանաչման նշանով կահավորված ավտոմոբիլների համար։"]', 'Կայանման տեղը 30 մ երկարությամբ գոտում` մոտոսայլակների եւ «Հաշմանդամ» ճանաչման նշանով կահավորված ավտոմոբիլների համար։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (344, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (345, 'Այս նշաններից ո՞րն է համարվում տրանսպորտային միջոցի ճանաչման նշան։', NULL, '["1", "2", "3"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (345, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (346, 'Ո՞ր տրանսպորտային միջոցի երթեւեկությունն է արգելում այս ճանապարհային նշանը։', NULL, '["Մեխանիկական տրանսպորտային միջոցների։", "Միայն ավտոմոբիլների։", "Միայն թեթեւ մարդատար ավտոմոբիլների։"]', 'Մեխանիկական տրանսպորտային միջոցների։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (346, 1);
