INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (348, 'Նշաններից ո՞րն է տեղադրվում տրանսպորտային միջոցների առջեւի եւ ետեւի կողմերում` երեխաների կազմակերպված խմբեր տեղափոխելիս։', NULL, '["1.", "2.", "3.", "4."]', '1.', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (348, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (349, 'Ի՞նչ են ցույց տալիս նշված ճանապարհային նշանները։', NULL, '["Գլխավոր ճանապարհը շարունակվում է խաչմերուկից դեպի ձախ։", "Գլխավոր ճանապարհը շարունակվում է խաչմերուկից ուղիղ եւ դեպի ձախ։"]', 'Գլխավոր ճանապարհը շարունակվում է խաչմերուկից դեպի ձախ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (349, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (350, 'Ի՞նչ են ցույց տալիս նշված ճանապարհային նշանները։', NULL, '["Ցուցանակի ազդեցության գոտում վարորդները պետք է երթեւեկեն նշանի վրա ցույց տրվածից ավելի բարձր արագությամբ։", "Ցուցանակի ազդեցության գոտում վարորդներին առաջարկվում է երթեւեկել նշանի վրա ցույց տրված արագությամբ։"]', 'Ցուցանակի ազդեցության գոտում վարորդներին առաջարկվում է երթեւեկել նշանի վրա ցույց տրված արագությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (350, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (351, 'Ո՞ր նշանների ազդեցությունն է գործում միայն այն ժամանակահատվածում, որի ընթացքում երթեւեկելի մասի ծածկույթը խոնավ է։', NULL, '["Միայն A եւ C։", "Միայն B։", "Միայն C։", "Բոլոր։"]', 'Միայն C։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (351, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (352, 'Ինչպե՞ս պետք է վարվի վարորդը տվյալ իրադրությունում։', NULL, '["Շարունակի ընթացքն ուղիղ։", "Վերադասավորվի ճանապարհի հանդիպակաց երթեւեկելի գոտի։"]', 'Վերադասավորվի ճանապարհի հանդիպակաց երթեւեկելի գոտի։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (352, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (353, 'Ի՞նչ են ցույց տալիս նշված ճանապարհային նշանները։', NULL, '["Նշանից 150-300 մետրից հետո աջ կողմից կա ճանապարհի նեղացում, որի երկարությունը 100 մ է։", "Նշանից 100 մետրից հետո, ճանապարի աջ կողմից կա ճանապարհի նեղացում։"]', 'Նշանից 150-300 մետրից հետո աջ կողմից կա ճանապարհի նեղացում, որի երկարությունը 100 մ է։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (353, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (354, 'Ո՞ր ուղղությամբ է թույլատրվում վարորդին երթեւեկել։', NULL, '["Միայն աջ եւ ձախ։", "Միայն ուղիղ։", "Ուղիղ եւ հակառակ ուղղությամբ։"]', 'Ուղիղ եւ հակառակ ուղղությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (354, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (355, 'Ի՞նչ են ցույց տալիս նշված ճանապարհային նշանները։', NULL, '["Կանգառն արգելված է շաբաթ օրերին։", "Կանգառն արգելված է կիրակի օրերին։", "Կանգառն արգելված է շաբաթ-կիրակի եւ տոն օրերին։", "Կանգառն արգելված է ձյունաթափի ժամանակ։"]', 'Կանգառն արգելված է շաբաթ-կիրակի եւ տոն օրերին։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (355, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (356, 'Ո՞ր ճանապարհային նշանն է արգելում հետադարձը։', NULL, '["1.", "2.", "3"]', '3', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (356, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (357, 'Ի՞նչ են ցույց տալիս նշված ճանապարհային նշանները։', NULL, '["Նորոգման աշխատանքների պատճառով կողնակ մուտք գործելը վտանգավոր է։", "Ճանապարհին իրականացվում են վերանորոգման աշխատանքներ։"]', 'Նորոգման աշխատանքների պատճառով կողնակ մուտք գործելը վտանգավոր է։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (357, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (358, 'Ի՞նչպես պիտի վարվի վարորդն այն դեպքում, երբ խաչմերուկից առաջ տեղադրված է հետեւյալ ճանապարհային նշանը։', NULL, '["Անցնել խաչմերուկը` անվտանգությունը պահպանելով։", "Ճանապարհը զիջել հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։", "Կանգնել նշանի առջեւ եւ ճանապարհը զիջել հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։"]', 'Կանգնել նշանի առջեւ եւ ճանապարհը զիջել հատվող ճանապարհով ընթացող տրանսպորտային միջոցներին։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (358, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (359, 'Ո՞ր ճանապարհային նշանների ազդեցությունը չի տարածվում ընդհանուր օգտագործման տրանսպորտային միջոցների վրա։', NULL, '["Ոչ մեկը։", "Միայն առաջինը։", "Միայն չորրորդը։"]', 'Միայն չորրորդը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (359, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (360, 'Հետեւյալ ճանապարհային նշանը ցույց է տալիս`', NULL, '["Խաչմերուկում պետք է երթեւեկել դեպի ձախ կամ աջ։", "Հատվող ճանապարհին կազմակերպված է դարձափոխային երթեւեկություն։", "Հատվող ճանապարհին կազմակերպված է միակողմանի երթեւեկություն։"]', 'Հատվող ճանապարհին կազմակերպված է դարձափոխային երթեւեկություն։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (360, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (361, 'Տվյալ իրադրությունում պարտավո՞ր է վարորդը ճանապարհը զիջել բեռնատար ավտոմոբիլին։', NULL, '["Պարտավոր է։", "Պարտավոր չէ։"]', 'Պարտավոր է։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (361, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (362, 'Ի՞նչ են ցույց տալիս հետեւյալ ճանապարհային նշանները։', NULL, '["Ճանապարհի սառցապատման ժամանակ պետք է երթեւեկել 40 կմ/ժ արագությամբ։", "Թաց ճանապարհածածկույթի դեպքում պետք է երթեւեկել 40 կմ/ժ-ից ոչ ավելի արագությամբ։"]', 'Թաց ճանապարհածածկույթի դեպքում պետք է երթեւեկել 40 կմ/ժ-ից ոչ ավելի արագությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (362, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (363, 'Ի՞նչ են ցույց տալիս հետեւյալ ճանապարհային նշանները։', NULL, '["Կանգառն արգելված է շաբաթ օրերին։", "Կանգառն արգելված է կիրակի օրերին։", "Կանգառն արգելված է աշխատանքային օրերին։"]', 'Կանգառն արգելված է աշխատանքային օրերին։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (363, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (364, 'Ի՞նչ է ցույց տալիս հետեւյալ ճանապարհային նշանը։', NULL, '["Ճանապարհի տվյալ հատվածում թույլատրում է երթեւեկել 50 կմ/ժ-ից ոչ ավելի արագությամբ։", "Առաջարկվում է ճանապարհի տվյալ հատվածում երթեւեկել 50 կմ/ժ արագությամբ։", "Թույլատրվում է երթևեկել միայն նշանում նշված կամ ավելի բարձր արագությամբ։"]', 'Առաջարկվում է ճանապարհի տվյալ հատվածում երթեւեկել 50 կմ/ժ արագությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (364, 1);
