INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (367, 'Տվյալ ճանապարհային նշանների ազդեցությունը տարածվում է`', NULL, '["Ճանապարհի ձախ կողմում։", "Ճանապարհի աջ կողմում։", "Ճանապարհի այն կողմում, որտեղ դրանք տեղադրված են։"]', 'Ճանապարհի այն կողմում, որտեղ դրանք տեղադրված են։', 4);
