INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (368, 'Տվյալ իրադրությունում ո՞ր հետագծով է թույլատրվում արգելքի շրջանցումը։', NULL, '["Միայն «a»։", "Միայն «b»։", "«a» եւ «b»։"]', '«a» եւ «b»։', 4);
