INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (369, 'Ինչպե՞ս պետք է վարվի վարորդը տվյալ իրավիճակում։', NULL, '["Անհրաժեշտ է կանգ առնել առաջին նշանի մոտ։", "Անհրաժեշտ է կանգ առնել երկրորդ նշանից առաջ։", "Անհրաժեշտ է կանգ առնել երկաթուղային առաջին գծից ոչ պակաս 5 մետր հեռավորության վրա։"]', 'Անհրաժեշտ է կանգ առնել երկրորդ նշանից առաջ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (369, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (370, 'Ի՞նչպես պետք է վարվի վարորդը, եթե խաչմերուկում մտադիր է կատարել աջ շրջադարձ։', NULL, '["Կարող է վերադասավորվել աջ երթեւեկելի գոտի, դրանից հետո կատարել աջ շրջադարձ։", "Կարող է մոտենալ խաչմերուկին, այնուհետեւ կատարել աջ շրջադարձ։", "Երկու պատասխաններն էլ ճիշտ են։"]', 'Երկու պատասխաններն էլ ճիշտ են։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (370, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (371, 'Տվյալ իրադրությունում նշանից 200 մ հեռավորության վրա վարորդն ունի՞ արդյոք հետադարձի իրավունք։', 'question373_image.png', '["Իրավունք ունի։", "Իրավունք չունի։"]', 'Իրավունք ունի։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (371, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (372, 'Տվյալ դեպքում պարտավո՞ր է վարորդը կանգ առնել կարգավորողի կողմից նշված տեղում։', NULL, '["Պարտավոր չէ, քանի որ նշանն արգելում է կանգառը։", "Պարտավոր է։"]', 'Պարտավոր է։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (372, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (373, 'Ինչպե՞ս պետք է վարվի վարորդը տվյալ իրավիճակում։', NULL, '["Անցնի երկաթուղային գծանցն` ապահովելով անվտանգությունը։", "Անցնի երկաթուղային գծանցն առանց կանգ առնելու։", "Կանգ առնի նշանից առաջ եւ պահպանելով անվտանգությունն` անցնի բազմագիծ երկաթուղային գծանցը։"]', 'Կանգ առնի նշանից առաջ եւ պահպանելով անվտանգությունն` անցնի բազմագիծ երկաթուղային գծանցը։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (373, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (374, 'Ի՞նչ է ցույց տալիս երթեւեկելի մասում արված գծանշումը։', NULL, '["Համընթաց ուղղությամբ երթեւեկող տրանսպորտային միջոցների համար առանձնացված գոտիների սահմանները։", "Դարձափոխային երթեւեկության գոտու սահմանները։"]', 'Դարձափոխային երթեւեկության գոտու սահմանները։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (374, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (375, 'Ո՞ ր ուղղությամբ է թույլատրվում թեթեւ մարդատար ավտոմոբիլի երթեւեկությունը։', NULL, '["Դեպի ձախ եւ հակառակ ուղղությամբ։", "Ցանկացած ուղղությամբ։", "Ուղիղ, ձախ եւ հակառակ ուղղությամբ։"]', 'Ուղիղ, ձախ եւ հակառակ ուղղությամբ։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (375, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (376, 'Ինչպե՞ս պետք է վարվի վարորդը տվյալ իրադրությունում։', NULL, '["Անհրաժեշտության դեպքում ճանապարհը զիջի հատվող ճանապարհով երթեւեկող տրանսպորտային միջոցին։", "Կանգ առնի եւ ճանապարհը զիջի հատվող ճանապարհով երթեւեկող տրանսպորտային միջոցին։"]', 'Կանգ առնի եւ ճանապարհը զիջի հատվող ճանապարհով երթեւեկող տրանսպորտային միջոցին։', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (376, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (377, 'Ստորև ներկայացվող ճանապարհային նշաններից ո՞րն է արգելում մուտք գործել խաչմերուկի տարածք, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, բացառությամբ աջ կամ ձախ շրջադարձ կատարելու դեպքերի', NULL, '["1.", "2.", "3.", "4."]', '3.', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (377, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (378, 'Ի՞նչ առավելագույն հեռավորության վրա է տեղադրվում բարդ խաչմերուկներում «խաչմերուկի տարածք» ճանապարհային նշանը, եթե այն հնարավոր չէ տեղադրել խաչմերուկի սահմանին:', NULL, '["10 մետր", "20 մետր", "30 մետր"]', '30 մետր', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (378, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (379, 'Ինչի՞ մասին է զգուշացնում հետևյալ ճանապարհային նշանը:', NULL, '["Կանգառն արգելվում է:", "Արգելվում է մուտք գործել խաչմերուկի տարածք, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կ հարկադրի կանգ առնել:", "Արգելվում է մուտք գործել խաչմերուկի տարածք, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում:"]', 'Արգելվում է մուտք գործել խաչմերուկի տարածք, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կ հարկադրի կանգ առնել:', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (379, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (380, 'Ի՞նչ է ցույց տակիս հետևյալ ճանապարհային գծանշումը:', NULL, '["Տրանսպորտային միջոցների կայանման վայր:", "Հետիոտնային անցման տեղ:", "Անվտանգության կղզյակ:", "Խաչմերուկի հատված, որտեղ արգելվում է մուտք գործել, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կ հարկադրի կանգ առնել:"]', 'Խաչմերուկի հատված, որտեղ արգելվում է մուտք գործել, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կ հարկադրի կանգ առնել:', 4);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (380, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (381, 'Ստորև ներկայացված ճանապարհային գծանշումներից ո՞րն է ցույց տալիս խաչմերուկի հատվածը, որտեղ արգելվում է մուտք գործել, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կ հարկադրի կանգ առնել:', NULL, '["1.", "2.", "3."]', '3.', 4);
