INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (397, 'Ի՞նչ է ցույց տալիս լրացուցիչ տեղեկատվության ցուցանակը', NULL, '["նշանից մինչև խաչմերուկ եղած հեռավորությունը, երբ խաչմերուկից անմիջապես առաջ տեղադրված է «Զիջեք ճանապարհը» նշանը", "նշանից մինչև խաչմերուկ եղած հեռավորությունը, երբ խաչմերուկից անմիջապես առաջ տեղադրված է «Երթևեկությունն առանց կանգառի արգելված է» նշանը", "Սահմանային անցակետի գտնվելու վայրը"]', 'նշանից մինչև խաչմերուկ եղած հեռավորությունը, երբ խաչմերուկից անմիջապես առաջ տեղադրված է «Երթևեկությունն առանց կանգառի արգելված է» նշանը', 4);
