INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (525, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ՝', 'question527_image.png', '["Դեղին ավտոբուսը, բեռնատար ավտոմոբիլը, կանաչ ավտոբուսը։", "Բեռնատար ավտոմոբիլը, դեղին ավտոբուսը, կանաչ ավտոբուսը։", "Դեղին ավտոբուսը, կանաչ ավտոբուսը, բեռնատար ավտոմոբիլը։"]', 'Բեռնատար ավտոմոբիլը, դեղին ավտոբուսը, կանաչ ավտոբուսը։', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (525, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (526, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ՝', 'question528_image.png', '["Ավտոբուսը, թեթեւ մարդատար ավտոմոբիլը եւ բեռնատար ավտոմոբիլը միաժամանակ։", "Թեթեւ մարդատար ավտոմոբիլը եւ բեռնատար ավտոմոբիլը միաժամանակ, ավտոբուսը։"]', 'Ավտոբուսը, թեթեւ մարդատար ավտոմոբիլը եւ բեռնատար ավտոմոբիլը միաժամանակ։', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (526, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (527, 'Ի՞նչ հերթականությամբ կանցնեն խաչմերուկը տրանսպորտային միջոցները, եթե լուսացույցերը չեն աշխատում՝', 'question529_image.png', '["Տրոլեյբուսը եւ մոտոցիկլը, ավտոբուսը եւ թեթեւ մարդատար ավտոմոբիլը։", "Մոտոցիկլը, ավտոբուսը եւ թեթեւ մարդատար ավտոմոբիլը, տրոլեյբուսը։", "Ավտոբուսը եւ թեթեւ մարդատար ավտոմոբիլը, տրոլեյբուսը եւ մոտոցիկլը։"]', 'Մոտոցիկլը, ավտոբուսը եւ թեթեւ մարդատար ավտոմոբիլը, տրոլեյբուսը։', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (527, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (528, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ՝', 'question530_image.png', '["Բեռնատար ավտոմոբիլը, տրամվայը եւ ավտոբուսը, մոտոցիկլը եւ թեթեւ մարդատար ավտոմոբիլը։", "Տրամվայը եւ ավտոբուսը, մոտոցիկլը եւ թեթեւ մարդատար ավտոմոբիլը, բեռնատար ավտոմոբիլը։"]', 'Բեռնատար ավտոմոբիլը, տրամվայը եւ ավտոբուսը, մոտոցիկլը եւ թեթեւ մարդատար ավտոմոբիլը։', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (528, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (529, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ՝', 'question531_image.png', '["«Շտապ օգնության» ավտոմոբիլը, տրամվայը, մոտոցիկլը, ավտոբուսը, թեթեւ մարդատար ավտոմոբիլը։", "Մոտոցիկլը, ավտոբուսը, տրամվայը եւ «Շտապ օգնության» ավտոմոբիլը, թեթեւ մարդատար ավտոմոբիլը։"]', 'Մոտոցիկլը, ավտոբուսը, տրամվայը եւ «Շտապ օգնության» ավտոմոբիլը, թեթեւ մարդատար ավտոմոբիլը։', 5);
