INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (543, 'Խաչմերուկից անմիջապես հետո գոյացած խցանման պայմաններում մուտք գործելը խաչմերուկ թույլատրելի է միայն', 'question545_image.png', '["Եթե երթևեկությունն ուղիղ ենք շարունակելու", "Եթե շրջադարձ կամ հետադարձ ենք կատարելու", "Թվարկված բոլոր դեպքերում:"]', 'Եթե շրջադարձ կամ հետադարձ ենք կատարելու', 5);
