INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (548, 'Ճանապարհը պետք է զիջեք', 'question550_image.png', '["Ավտոբուսի վարորդին", "Երկու վարորդներին", "Ոչ ոքի"]', 'Ոչ ոքի', 5);
