INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (549, 'Այս իրավիճակում խաչմերուկն անցնելիս զիջել ճանապարհը', 'question551_image.png', '["Պարտավոր եք", "Պարտավոր չեք"]', 'Պարտավոր չեք', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (549, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (550, 'Խաչմերուկն անցնելիս այս իրավիճակում', 'question552_image.png', '["Առաջինն անցնելու իրավունք ունենք", "Պետք է զիջենք տրամվայի վարորդին", "Պետք է զիջենք բեռնատարի վարորդին", "Պետք է զիջենք բոլոր վարորդներին"]', 'Առաջինն անցնելու իրավունք ունենք', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (550, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (551, '«Շրջանաձև երթևեկություն» նշանով կահավորված շրջանաձև երթևեկությամբ խաչմերուկ մուտք գործելիս տրանսպորտային միջոցի վարորդը', 'question553_image.png', '["պարտավոր է ճանապարհը զիջել այդ խաչմերուկում երթևեկող տրանսպորտային միջոցներին", "ունի երթևեկության առավելություն արդեն իսկ այդ խաչմերուկում երթևեկողների նկատմամբ:"]', 'պարտավոր է ճանապարհը զիջել այդ խաչմերուկում երթևեկող տրանսպորտային միջոցներին', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (551, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (552, 'Այս իրադրությունում ձախ շրջադարձի ժամանակ պարտավոր ենք զիջել ճանապարհը', 'question554_image.png', '["Բոլոր վարորդներին", "Միայն թեթև մարդատարի վարորդին", "Ավտոբուսի և թեթև մարդատարի վարորդներին"]', 'Ավտոբուսի և թեթև մարդատարի վարորդներին', 5);
