INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (553, 'Ո՞ր վարորդն է պարտավոր չխոչընդոտել հետիոտներին', 'question555_image.png', '["Թեթև մարդատարի վարորդը", "Բեռնատարի վարորդը", "Երկու վարորդները"]', 'Երկու վարորդները', 5);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (553, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (554, 'Այս իրավիճակում վարորդը կարող է՞ կատարել ձախ շրջադարձը', 'question556_image.png', '["Այո", "Այո, եթե չի խոչընդոտի բեռնատարի վարորդին", "Ոչ"]', 'Այո, եթե չի խոչընդոտի բեռնատարի վարորդին', 5);
