INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (556, 'Նշանները հայտնում են, որ', 'question558_image.png', '["200 մետրից ճանապարհը հատվողին զիջելու անհրաժեշտություն է լինելու:", "200 մետր հատվածում պետք է զիջենք բոլորին:"]', '200 մետրից ճանապարհը հատվողին զիջելու անհրաժեշտություն է լինելու:', 5);
