INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (576, 'Ձախ շրջադարձ կատարելիս պարտավոր եք ճանապարհը զիջել', 'question578_image.png', '["Միայն թեթև մարդատարի վարորդին", "Թեթև մարդատարի և ավտոբուսի վարորդին", "Ոչ ոքի"]', 'Միայն թեթև մարդատարի վարորդին', 5);
