INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (577, 'Երբ վարորդը չի կարող որոշել ճանապարհի ծածկույթի առկայությունը (օրվա մութ ժամանակ, ցեխ, ձյուն և այլն), և բացակայում են առավելության նշանները, ապա', 'question579_image.png', '["Նա պետք է համարի, որ գտնվում է երկրորդական ճանապարհի վրա", "Նա պետք է առաջնորդվի հավասարազոր խաչմերուկի անցման կանոններով:"]', 'Նա պետք է համարի, որ գտնվում է երկրորդական ճանապարհի վրա', 5);
