INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (579, 'Զիջել ճանապարհը պարտավոր ենք', 'question581_image.png', '["Թեթև մարդատարի վարորդին", "Ավտոբուսի և թեթև մարդատարի վարորդներին", "Բոլոր վարորդներին"]', 'Ավտոբուսի և թեթև մարդատարի վարորդներին', 5);
