INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (581, 'Լուսացույցի դեղին թարթող ազդանշանի պայմաններում խաչմերուկն ուղիղ անցնելիս պարտավոր ենք', 'question583_image.png', '["Կանգնել և սպասել կանաչ թույլատրող ազդանշանի միանալուն", "Զիջել թեթև մարդատարի վարորդին", "Զիջել տրամվայի վարորդին"]', 'Զիջել թեթև մարդատարի վարորդին', 5);
