INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (607, 'Ո՞ր նկարում է պատկերված գլխավոր ճանապարհ', 'question609_image.png', '["Վերին ձախ", "Վերին աջ", "Վերևի նկարներում", "Բոլոր"]', 'Վերևի նկարներում', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (607, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (608, 'Խաչմերուկում ո՞ր ճանապարհն է համարվում գլխավոր', 'question610_image.png', '["Կոշտ ծածկույթով (ասֆալտբետոն, ցեմենտբետոն, քարե նյութեր և այլն) ճանապարհը հողային ծածկույթ ունեցողի նկատմամբ", "Եռագոտի ճանապարհը ամեն ուղղությամբ մեկ գոտի ունեցողի նկատմամբ", "Ասֆալտբետոնե ճանապարհը սալիկապատ ճանապարհի նկատմամբ"]', 'Կոշտ ծածկույթով (ասֆալտբետոն, ցեմենտբետոն, քարե նյութեր և այլն) ճանապարհը հողային ծածկույթ ունեցողի նկատմամբ', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (608, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (609, 'Երթեւեկությունն արգելվում է՝', 'question611_image.png', '["Կարմիր եւ սպիտակ ավտոմոբիլներին։", "Կապույտ, կանաչ եւ սպիտակ ավտոմոբիլներին։", "Սպիտակ, կապույտ եւ դեղին ավտոմոբիլներին։"]', 'Կապույտ, կանաչ եւ սպիտակ ավտոմոբիլներին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (609, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (610, 'Վարորդներից ո՞վ իրավունք ունի երթեւեկել ուղիղ։', 'question612_image.png', '["Ավտոբուսի եւ մոտոցիկլի վարորդները։", "Թեթեւ մարդատար եւ բեռնատար ավտոմոբիլների վարորդները։", "Թեթեւ մարդատար ավտոմոբիլի վարորդը։"]', 'Թեթեւ մարդատար ավտոմոբիլի վարորդը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (610, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (611, 'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։', 'question613_image.png', '["Ավտոմոբիլի վարորդը։", "Տրամվայի վարորդը։"]', 'Տրամվայի վարորդը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (611, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (612, 'Եթե կարգավորողի աջ ձեռքը պարզված է առաջ, ապա ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկությունը թույլատրվում է՝', 'question614_image.png', '["Ձախ կողմից` դեպի ձախ եւ հակառակ ուղղությամբ։", "Աջ կողմից` միայն դեպի աջ։", "Ձախ կողմից` բոլոր ուղղություններով։", "Թիկունքից` միայն դեպի աջ։"]', 'Ձախ կողմից` բոլոր ուղղություններով։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (612, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (613, 'Ո՞ր պատասխանում են ճիշտ նշված այն տրանսպորտային միջոցները, որոնց թույլատրվում է երթեւեկությունը։', 'question615_image.png', '["Մոտոցիկլը։", "Բեռնատար ավտոմոբիլը։", "Ավտոբուսը։", "Թեթեւ մարդատար ավտոմոբիլը։", "Թեթեւ մարդատար եւ բեռնատար ավտոմոբիլները։"]', 'Թեթեւ մարդատար ավտոմոբիլը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (613, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (614, 'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը՝', 'question616_image.png', '["Մոտոցիկլի վարորդը։", "Ավտոմոբիլի վարորդը։"]', 'Ավտոմոբիլի վարորդը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (614, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (615, 'Կարգավորողի այս ազդանշանը նշանակում է, որ երթեւեկությունը թույլատրվում է՝', 'question617_image.png', '["Կապույտ եւ կանաչ ավտոմոբիլներին։ Արգելվում է կարմիրին, դեղինին եւ սպիտակին։", "Կապույտ, կարմիր եւ կանաչ ավտոմոբիլներին։ Արգելվում է դեղինին եւ սպիտակին։"]', 'Կապույտ, կարմիր եւ կանաչ ավտոմոբիլներին։ Արգելվում է դեղինին եւ սպիտակին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (615, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (616, 'Ո՞ր տրանսպորտային միջոցները կարող են կատարել աջ շրջադարձ։', 'question618_image.png', '["Միայն կարմիր ավտոմոբիլը։", "Բոլոր տրանսպորտային միջոցները։", "Կարմիր եւ կանաչ ավտոմոբիլները։"]', 'Կարմիր եւ կանաչ ավտոմոբիլները։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (616, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (617, 'Երթեւեկությունը թույլատրվում է՝', 'question619_image.png', '["Ուղիղ։", "Դեպի աջ՝ առաջին անցումով։", "Դեպի աջ՝ երկրորդ անցումով։", "Դեպի աջ՝ առաջին եւ երկրորդ անցումներով։"]', 'Դեպի աջ՝ առաջին անցումով։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (617, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (618, 'Երթեւեկությունը թույլատրվում է՝', 'question620_image.png', '["Դեպի աջ՝ առաջին անցումով։", "Ուղիղ եւ դեպի աջ՝ առաջին անցումով։"]', 'Դեպի աջ՝ առաջին անցումով։', 6);
