INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (619, 'Այս լուսացույցն արգելում է երթեւեկությունը՝', 'question621_image.png', '["Միայն դեպի ձախ։", "Ուղիղ եւ դեպի ձախ։", "Ուղիղ եւ դեպի աջ։", "Միայն դեպի աջ։"]', 'Միայն դեպի ձախ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (619, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (620, 'Եթե կարգավորողի ձեռքերը կողմ են պարզված կամ իջեցված են, ապա ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկությունը թույլատրվում է՝', 'question622_image.png', '["Թիկունքի եւ կրծքի կողմից՝ միայն դեպի աջ։", "Ձախ եւ աջ կողմերից՝ ուղիղ եւ դեպի աջ։", "Ձախ եւ աջ կողմերից՝ միայն ուղիղ։"]', 'Ձախ եւ աջ կողմերից՝ ուղիղ եւ դեպի աջ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (620, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (621, 'Կարմիր ավտոմոբիլի վարորդը՝', 'question623_image.png', '["Պետք է զիջի ճանապարհը։", "Ունի առաջնահերթ երթեւեկության իրավունք։"]', 'Պետք է զիջի ճանապարհը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (621, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (622, 'Ո՞ր տրանսպորտային միջոցներին է թույլատրվում երթեւեկությունը։', 'question624_image.png', '["Դեղին եւ կարմիր ավտոմոբիլներին։", "Կանաչ, կարմիր եւ սպիտակ ավտոմոբիլներին։", "Սպիտակ եւ կանաչ ավտոմոբիլներին։"]', 'Դեղին եւ կարմիր ավտոմոբիլներին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (622, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (623, 'Լուսացույցի ի՞նչ ազդանշանի դեպքում ավտոմոբիլի վարորդը կարող է ավարտել հետադարձը։', 'question625_image.png', '["Կարմիր։", "Կանաչ։", "Ցանկացած։"]', 'Կանաչ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (623, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (624, 'Ի՞նչ է նշանակում լուսացույցի դեղին եւ կարմիր գույների ազդանշանների զուգակցումը։', 'question626_image.png', '["Թույլատրվում է սկսել երթեւեկությունը։", "Արգելվում է երթեւեկությունը եւ տեղեկացնում կանաչ ազդանշանի առաջիկայում միանալու մասին։", "Խաչմերուկին մոտենում է հատուկ ձայնային ազդանշան եւ առկայծող փարոսիկներ միացրած տրանպորտային միջոց։"]', 'Արգելվում է երթեւեկությունը եւ տեղեկացնում կանաչ ազդանշանի առաջիկայում միանալու մասին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (624, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (625, 'Ո՞ր նկարում է վարորդը ճիշտ կատարում շրջադարձը։', 'question627_image.png', '["Ձախ նկարում։", "Աջ նկարում։"]', 'Ձախ նկարում։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (625, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (626, 'Պարտավո՞ր է արդյոք տրամվայի վարորդը լուսացույցի կանաչ ազդանշանի դեպքում զիջել ճանապարհն այլ ուղղություններից մոտեցող տրանսպորտային միջոցներին։', 'question628_image.png', '["Պարտավոր է։", "Պարտավոր չէ։"]', 'Պարտավոր է։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (626, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (627, 'Այս լուսացույցը կիրառվում է երթեւեկությունը կարգավորելու համար՝', 'question629_image.png', '["Երթեւեկելի մասի ամբողջ լայնությամբ։", "Երթեւեկելի մասի այն գոտիներով, որտեղ երթեւեկության ուղղությունը կարող է փոխվել հանդիպակացի։", "Միայն ընդհանուր օգտագործման տրանսպորտային միջոցների երթեւեկության համար նախատեսված գոտիներում։"]', 'Երթեւեկելի մասի այն գոտիներով, որտեղ երթեւեկության ուղղությունը կարող է փոխվել հանդիպակացի։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (627, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (628, 'Եթե կարգավորողի աջ ձեռքը պարզված է առաջ, ապա նրա ձախ կողմից ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկությունը թույլատրվում է՝', 'question630_image.png', '["Բոլոր ուղղություններով։", "Միայն դեպի ձախ։"]', 'Բոլոր ուղղություններով։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (628, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (629, 'Ո՞ր տրանսպորտային միջոցների երթեւեկությունն է թույլատրվում լուսացույցի տվյալ ազդանշանի դեպքում։', 'question631_image.png', '["Տրամվայի, դեղին եւ կարմիր ավտոմոբիլների։", "Դեղին եւ կարմիր ավտոմոբիլների։", "Բոլոր տրանսպորտային միջոցների։"]', 'Դեղին եւ կարմիր ավտոմոբիլների։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (629, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (630, 'Երթեւեկությունը թույլատրվում է՝', 'question632_image.png', '["Բոլոր տրանսպորտային միջոցներին։", "Մոտոցիկլին։", "Ավտոմոբիլին եւ մոտոցիկլին։"]', 'Մոտոցիկլին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (630, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (631, 'Եթե կարգավորողի ձեռքերը կողմ են պարզված կամ իջեցված են, ապա նրա ձախ եւ աջ կողմերից ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկությունը թույլատրվում է՝', 'question633_image.png', '["Ուղիղ եւ դեպի աջ։", "Միայն ուղիղ։"]', 'Ուղիղ եւ դեպի աջ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (631, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (632, 'Ո՞ր տրանսպորտային միջոցի վարորդն ունի երթեւեկության առավելություն։', 'question634_image.png', '["Ավտոմոբիլի վարորդը։", "Տրամվայի վարորդը։"]', 'Տրամվայի վարորդը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (632, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (633, 'Երթեւեկությունն արգելվում է՝', 'question635_image.png', '["Կանաչ եւ սպիտակ ավտոմոբիլներին։", "Սպիտակ, կապույտ եւ կանաչ ավտոմոբիլներին։", "Սպիտակ եւ դեղին ավտոմոբիլներին։", "Կանաչ եւ դեղին ավտոմոբիլներին։"]', 'Սպիտակ, կապույտ եւ կանաչ ավտոմոբիլներին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (633, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (634, 'Այս լուսացույցի կարմիր ազդանշանի դեպքում երթեւեկությունն արգելվում է՝', 'question636_image.png', '["Երթեւեկելի մասի ամբողջ լայնությամբ։", "50 կմ/ժ ոչ ավելի արագությամբ։", "Այն գոտիով, որի վերեւում տեղակայված է։"]', 'Այն գոտիով, որի վերեւում տեղակայված է։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (634, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (635, 'Ի՞նչ նշանակություն ունի լուսացույցի կլոր կանաչ թարթող ազդանշանը։', 'question637_image.png', '["Տեղեկացնում է, որ մուտքը խաչմերուկ արգելվում է։", "Թույլատրում է երթեւեկությունը եւ տեղեկացնում, որ դրա գործողության ժամկետը լրանում է եւ շուտով կմիանա արգելող ազդանշանը։"]', 'Թույլատրում է երթեւեկությունը եւ տեղեկացնում, որ դրա գործողության ժամկետը լրանում է եւ շուտով կմիանա արգելող ազդանշանը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (635, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (636, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ՝', 'question638_image.png', '["Տրամվայը, կարմիր ավտոմոբիլը, կանաչ ավտոմոբիլը։", "Կարմիր ավտոմոբիլը, տրամվայը` կանաչ ավտոմոբիլի հետ միաժամանակ։", "Տրամվայը` կանաչ ավտոմոբիլի հետ միաժամանակ, կարմիր ավտոմոբիլը։"]', 'Կարմիր ավտոմոբիլը, տրամվայը` կանաչ ավտոմոբիլի հետ միաժամանակ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (636, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (637, 'Ո՞ր պատասխանում են ճիշտ նշված այն տրանսպորտային միջոցները, որոնց երթեւեկությունը թույլատրվում է։', 'question639_image.png', '["Ավտոմոբիլները եւ մոտոցիկլը։", "Բոլոր տրանսպորտային միջոցները։", "Ավտոմոբիլները եւ տրամվայը։"]', 'Ավտոմոբիլները եւ մոտոցիկլը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (637, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (638, 'Եթե կարգավորողի աջ ձեռքը պարզված է առաջ, ապա նրա ձախ կողմից ոչ ռելսագնաց տրանսպորտային միջոցների երթեւեկությունը թույլատրվում է՝', 'question640_image.png', '["Ուղիղ եւ դեպի ձախ։", "Բոլոր ուղղություններով։"]', 'Բոլոր ուղղություններով։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (638, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (639, 'Երթեւեկությունն արգելվում է՝', 'question641_image.png', '["Կապտադեղին ավտոմոբիլին` դեպի ձախ։", "Կապտադեղին ավտոմոբիլին` ուղիղ, կարմիր ավտոմոբիլին` ուղիղ եւ դեպի աջ։", "Կարմիր ավտոմոբիլին։"]', 'Կապտադեղին ավտոմոբիլին` դեպի ձախ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (639, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (640, 'Ո՞ր ուղղությամբ է թույլատրվում երթեւեկությունը։', 'question642_image.png', '["Ուղիղ եւ դեպի աջ` առաջին անցումով։", "Դեպի աջ` առաջին անցումով։", "Դեպի աջ` երկրորդ անցումով։", "Դեպի աջ` առաջին եւ երկրորդ անցումներով։"]', 'Դեպի աջ` առաջին անցումով։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (640, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (641, 'Խաչմերուկն առաջինը կանցնի՝', 'question643_image.png', '["Կարմիր ավտոմոբիլը։", "Կապույտ ավտոմոբիլը։", "Կանաչ ավտոմոբիլը։"]', 'Կանաչ ավտոմոբիլը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (641, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (642, 'Ո՞ր նկարում է վարորդը ճիշտ կատարում շրջադարձը։', 'question644_image.png', '["Ձախ նկարում։", "Աջ նկարում։", "Երկու նկարներում էլ։"]', 'Ձախ նկարում։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (642, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (643, 'Կարմիր ավտոմոբիլը խաչմերուկը կանցնի՝', 'question645_image.png', '["Առաջինը։", "Երկրորդը։", "Երրորդը։", "Վերջինը։"]', 'Վերջինը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (643, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (644, 'Այս լուսացույցը կիրառվում է՝', 'question646_image.png', '["Տրամվայների եւ տրոլեյբուսների երթեւեկությունը կարգավորելու համար։", "Միայն տրամվայների երթեւեկությունը կարգավորելու համար։", "Տրամվայների, ինչպես նաեւ առանձնացված գոտիներով երթեւեկող ընդհանուր օգտագործման այլ տրանսպորտային միջոցների երթեւեկությունը կարգավորելու համար։"]', 'Տրամվայների, ինչպես նաեւ առանձնացված գոտիներով երթեւեկող ընդհանուր օգտագործման այլ տրանսպորտային միջոցների երթեւեկությունը կարգավորելու համար։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (644, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (645, 'Ավտոմոբիլը խաչմերուկը կանցնի՝', 'question647_image.png', '["Առաջինը։", "Երկրորդը։"]', 'Առաջինը։', 6);
