INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (646, 'Երթեւեկությունը թույլատրվում է՝', 'question648_image.png', '["Կապտադեղին ավտոմոբիլին` ուղիղ, կարմիրին` դեպի աջ։", "Կարմիր ավտոմոբիլին` ուղիղ եւ դեպի աջ, կապտադեղինին` ուղիղ։", "Երկու ավտոմոբիլներին` միայն ուղիղ։"]', 'Կարմիր ավտոմոբիլին` ուղիղ եւ դեպի աջ, կապտադեղինին` ուղիղ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (646, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (647, 'Երթեւեկությունը թույլատրվում է՝', 'question649_image.png', '["Կարմիր ավտոմոբիլին։", "Մոտոցիկլին։", "Տրամվային եւ կարմիր ավտոմոբիլին։", "Տրամվային։", "Կապույտ ավտոմոբիլին։"]', 'Կարմիր ավտոմոբիլին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (647, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (648, 'Թույլատրվու՞մ է երթեւեկել նշված հետագծով, երբ դարձափոխային լուսացույցերն անջատված են։', 'question650_image.png', '["Թույլատրվում է։", "Թույլատրվում է վազանցելու նպատակով։", "Արգելվում է։", "Թույլատրվում է հանդիպակաց երթեւեկող տրանսպորտային միջոցների բացակայության դեպքում։"]', 'Արգելվում է։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (648, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (649, 'Տվյալ իրավիճակում ո՞ր տրանսպորտային միջոցներն ունեն երթեւեկությունը շարունակելու իրավունք։', 'question651_image.png', '["Թեթեւ մարդատար ավտոմոբիլը` ուղիղ, պարեկային ավտոմոբիլը` բոլոր ուղղություններով, ավտոբուսը` միայն աջ։", "Միայն պարեկային ավտոմոբիլը` բոլոր ուղղություններով։", "Պարեկային ավտոմոբիլը` բոլոր ուղղություններով, ավտոբուսը` միայն աջ։"]', 'Պարեկային ավտոմոբիլը` բոլոր ուղղություններով, ավտոբուսը` միայն աջ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (649, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (650, 'Ի՞նչ է տեղեկացնում լուսացույցի ազդանշանը։', 'question652_image.png', '["Լուսացույցն անսարք է։", "Խաչմերուկն անցնելիս վարորդները պետք է ղեկավարվեն ճանապարհային նշանի պահանջներով։", "Վարորդները պետք է սպասեն լուսացույցի թույլատրող ազդանշանին։"]', 'Վարորդները պետք է սպասեն լուսացույցի թույլատրող ազդանշանին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (650, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (651, 'Թույլատրվու՞մ է թեթեւ մարդատար ավտոմոբիլի վարորդին առաջ անցնել ավտոբուսից, երբ դարձափոխային լուսացույցն անջատված է։', 'question653_image.png', '["Թույլատրվում է։", "Թույլատրվում է, եթե ավտոբուսը շարժվում է 30 կմ/ժ արագությամբ։", "Թույլատրվում է, եթե չկան հանդիպակաց երթեւեկող տրանսպորտային միջոցներ։", "Արգելվում է։"]', 'Արգելվում է։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (651, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (652, 'Ո՞ր տրանսպորտային միջոցը պետք է զիջի ճանապարհը։', 'question654_image.png', '["Ավտոբուսը։", "Մոտոցիկլը եւ թեթեւ մարդատար ավտոմոբիլը։"]', 'Ավտոբուսը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (652, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (653, 'Նշված հետագծերով երթեւեկությունը շարունակելու իրավունք ունեն', 'question655_image.png', '["Բեռնատար ավտոմոբիլի վարորդը։", "Ավտոբուսի եւ բեռնատար ավտոմոբիլների վարորդները։", "Թեթեւ մարդատար ավտոմոբիլի եւ ավտոբուսի վարորդները։", "Ավտոբուսի վարորդը։"]', 'Ավտոբուսի վարորդը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (653, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (654, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ։', 'question656_image.png', '["Տրամվայը, թեթեւ մարդատար ավտոմոբիլը, ավտոբուսը։", "Թեթեւ մարդատար ավտոմոբիլը, տրամվայը, ավտոբուսը։", "Թեթեւ մարդատար ավտոմոբիլը, ավտոբուսը, տրամվայը։"]', 'Թեթեւ մարդատար ավտոմոբիլը, տրամվայը, ավտոբուսը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (654, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (655, 'Տվյալ իրադրությունում ավտոբուսի վարորդն ունի՞ ուղիղ երթեւեկելու իրավունք։', 'question657_image.png', '["Այո։", "Ոչ։", "Այո, եթե նա երթեւեկում է սահմանված երթուղով։"]', 'Ոչ։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (655, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (656, 'Ո՞ր ուղղությամբ կարող է վարորդը շարունակել երթեւեկությունը։', 'question658_image.png', '["Դեպի աջ` առաջին անցումով։", "Դեպի աջ` առաջին եւ երկրորդ անցումներով։", "Դեպի ձախ` առաջին անցումով։"]', 'Դեպի աջ` առաջին անցումով։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (656, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (657, 'Աջ շրջադարձի դեպքում վարորդը պարտավոր է ճանապարհը զիջել', 'question659_image.png', '["Միայն հեծանվորդին։", "Միայն հետիոտներին։", "Հետիոտներին եւ հեծանվորդին։", "Կարող է շարունակել երթեւեկությունն առանց կանգ առնելու։"]', 'Հետիոտներին եւ հեծանվորդին։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (657, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (658, 'Տրանսպորտային միջոցները խաչմերուկը կանցնեն հետեւյալ հերթականությամբ։', 'question660_image.png', '["Տրամվայը, ավտոբուսը, բեռնատար ավտոմոբիլը, մոտոցիկլը։", "Ավտոբուսը, բեռնատար ավտոմոբիլը, տրամվայը, մոտոցիկլը։", "Ավտոբուսը, տրամվայը եւ մոտոցիկլը, բեռնատար ավտոմոբիլը։"]', 'Ավտոբուսը, տրամվայը եւ մոտոցիկլը, բեռնատար ավտոմոբիլը։', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (658, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (659, 'Այս իրավիճակում ո՞ր տրամվայի վարորդին պետք է զիջել ճանապարհը', 'question661_image.png', '["Ոչ մեկին", "Երկու տրամվայների", "Միայն Ա"]', 'Երկու տրամվայների', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (659, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (660, 'Ո՞ր վարորդն ունի առաջնահերթ երթևեկության իրավունք', 'question662_image.png', '["Ավտոբուսի վարորդը", "Թեթև մարդատարի վարորդը"]', 'Թեթև մարդատարի վարորդը', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (660, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (661, 'Այս իրավիճակում ձախ շրջադարձ կատարելիս', 'question663_image.png', '["Կզիջենք ճանապարհը տրամվային", "Խաչմերուկն առաջինը կանցնեմ"]', 'Խաչմերուկն առաջինը կանցնեմ', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (661, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (662, 'Ինչպե՞ս վարվել այս իրավիճակում', 'question664_image.png', '["Մուտք գործել խաչմերուկ և զիջելով ճանապարհը թեթև մարդատարի վարորդին անցնել խաչմերուկը:", "Սպասել «Կանգ-գծի»՛ առջև, մինչև թեթև մարդատարի վարորդը կանցնի խաչմերուկը", "Անցնել առաջինը"]', 'Մուտք գործել խաչմերուկ և զիջելով ճանապարհը թեթև մարդատարի վարորդին անցնել խաչմերուկը:', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (662, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (663, 'Ո՞ր վարորդն է խախտում երթևեկության կանոնները շրջադարձ կատարելիս', 'question665_image.png', '["Թեթև մարդատարի", "Մոտոցիկլի", "Երկու վարորդները", "Ոչ ոք"]', 'Երկու վարորդները', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (663, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (664, 'Աջ շրջադարձ կատարելիս այս իրավիճակում զիջել ճանապարհը', 'question666_image.png', '["Պարտավոր եք", "Պարտավոր չեք"]', 'Պարտավոր եք', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (664, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (665, 'Աջ շրջադարձ թույլատրելի է՞ այս իրավիճակում', 'question667_image.png', '["Այո՝ չխոչընդոտելով հետիոտններին", "Ոչ"]', 'Այո՝ չխոչընդոտելով հետիոտններին', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (665, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (666, 'Զիջել ճանապարհը տրամվայի վարորդին այս իրավիճակում', 'question668_image.png', '["Պարտավոր չեք", "Պարտավոր եք"]', 'Պարտավոր եք', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (666, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (667, 'Կանաչ ազդանշանի միանալու դեպքում վարորդը', 'question669_image.png', '["Պետք է զիջի բեռնատարի վարորդին", "Ունի առաջնահերթ երթևեկելու իրավունք"]', 'Պետք է զիջի բեռնատարի վարորդին', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (667, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (668, 'Այս խաչմերուկում վարորդը', 'question670_image.png', '["Կանցնի առաջինը", "Պետք է զիջի ճանապարհը տրամվային"]', 'Կանցնի առաջինը', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (668, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (669, 'Խաչմերուկն ուղիղ անցնելիս վարորդը', 'question671_image.png', '["Կարող է առաջինն անցնել", "Պետք է զիջի տրամվային", "Պետք է զիջի երկու վարորդներին"]', 'Պետք է զիջի տրամվային', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (669, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (670, 'Շրջադարձը կատարելիս վարորդը պարտավոր է ճանապարհը զիջել', 'question672_image.png', '["Միայն հետիոտներին", "Հեծանվորդին", "Հեծանվորդին և հետիոտներին"]', 'Հեծանվորդին և հետիոտներին', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (670, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (671, 'Աջ շրջադարձ կատարելիս պարտավո՞ր եք զիջել ճանապարհը հանդիպակացից մոտեցող վարորդին', 'question673_image.png', '["Այո", "Ոչ"]', 'Ոչ', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (671, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (672, 'Խաչմերուկն ուղիղ անցնելիս', 'question674_image.png', '["Կարող ենք անցնել առաջինը", "Պարտավոր ենք զիջել ճանապարհը թեթև մարդատարի վարորդին"]', 'Պարտավոր ենք զիջել ճանապարհը թեթև մարդատարի վարորդին', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (672, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (673, 'Ձախ շրջադարձ կատարելիս պետք է զիջել', 'question675_image.png', '["Միայն թեթև մարդատարի վարորդին", "Միայն հետիոտներին", "Թեթև մարդատարի վարորդին և հետիոտներին"]', 'Թեթև մարդատարի վարորդին և հետիոտներին', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (673, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (674, 'Այս իրավիճակում աջ շրջադարձ թույլատրվո՞ւմ է', 'question676_image.png', '["Ոչ", "Այո՝ չխոչընդոտելով հետիոտնին"]', 'Այո՝ չխոչընդոտելով հետիոտնին', 6);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (674, 7);
