INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (677, 'Այս իրավիճակում ճանապարհը պարտավոր է զիջել', 'question679_image.png', '["Թեթև մարդատարի վարորդը", "Տրամվայի վարորդը"]', 'Տրամվայի վարորդը', 6);
