INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (678, 'Աջ շրջադարձ կատարելիս', 'question680_image.png', '["Պարտավոր ենք զիջել ճանապարհը տրամվայի վարորդին", "Կանցնենք խաչմերուկն առաջինը"]', 'Կանցնենք խաչմերուկն առաջինը', 6);
