INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (679, 'Մտադիր եք կատարել ձախ շրջադարձ: Ո՞ւմ եք պարտավոր զիջել ճանապարհը', 'question681_image.png', '["Միայն տրամվայի վարորդին", "Ոչ ոքի", "Ավտոմոբիլի և տրամվայի վարորդներին"]', 'Ավտոմոբիլի և տրամվայի վարորդներին', 6);
