INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (680, 'Ձախ շրջադարձ կատարելիս', 'question682_image.png', '["Մանևրը կկատարեմ առանց կանգ առնելու", "Խաչմերուկ մուտք գործելուց հետո կկանգնեմ երկրորդ \"Կանգ-գծի\" առջև և կսպասեմ կանաչ ազդանշանի միանալուն"]', 'Խաչմերուկ մուտք գործելուց հետո կկանգնեմ երկրորդ "Կանգ-գծի" առջև և կսպասեմ կանաչ ազդանշանի միանալուն', 6);
