INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (681, 'Պարտավոր ենք արդյո՞ք այս իրավիճակում զիջել բեռնատարի վարորդին', 'question683_image.png', '["Այո", "Ոչ"]', 'Այո', 6);
