INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (682, 'Ձախ շրջադարձն այս իրադրությունում կատարելիս պետք է', 'question684_image.png', '["Մուտք գործի խաչմերուկ և սպասի կարգավորողի ձախ շրջադարձ թույլատրող ազդանշանին", "Կանգ առնի \"Կանգ-գիծ\" գծանշման առջև և սպասի կարգավորողի ձախ շրջադարձ թույլատրող ազդանշանին", "Դուրս գա խաչմերուկ և հանդիպակացից մոտեցող վարորդին ճանապարհը զիջելուց հետո անցնի խաչմերուկը"]', 'Կանգ առնի "Կանգ-գիծ" գծանշման առջև և սպասի կարգավորողի ձախ շրջադարձ թույլատրող ազդանշանին', 6);
