INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (704, 'Ո՞ր տրանսպորտային միջոցներին է թույլատրվում կայանումը։', 'question706_image.png', '["Միայն մոտոցիկլին։", "Միայն բեռնատար ավտոմոբիլին։", "Միայն թեթեւ մարդատար ավտոմոբիլին։", "Թեթեւ մարդատար ավտոմոբիլին եւ մոտոցիկլին։", "Բոլոր տրանսպորտային միջոցներին։"]', 'Թեթեւ մարդատար ավտոմոբիլին եւ մոտոցիկլին։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (704, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (705, 'Կայանումն արգելվում է՝', 'question707_image.png', '["Կամուրջների, էստակադների եւ ուղեկամուրջների վրա։", "Կամուրջների, էստակադների եւ ուղեկամուրջների տակ։", "Թվարկած բոլոր դեպքերում։"]', 'Թվարկած բոլոր դեպքերում։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (705, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (706, 'Թույլատրվու՞մ է արդյոք ուղեւոր իջեցնել ճանապարհի այն տեղում, որտեղ եզրաքարի վերին մակերեսին գծված է դեղին հոծ գիծ եւ տեղադրված է «Կանգառն արգելվում է» նշանը։', 'question708_image.png', '["Թույլատրվում է։", "Արգելվում է։", "Թույլատրվում է՝ ընդհանուր օգտագործման տրանսպորտային միջոցների բացակայության դեպքում։", "Թույլատրվում է միայն ընդհանուր օգտագործման տրանսպորտային միջոցներին։"]', 'Արգելվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (706, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (707, 'Ազդու՞մ է արդյո՞ք արգելող նշանը ճանապարհի այն հատվածի վերա, որտեղ կանգառ է կատարել վարորդը։', NULL, '["Ազդում է։", "Չի ազդում։"]', 'Ազդում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (707, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (708, 'Թույլատրվու՞մ է արդյո՞ք ավտոմոբիլի կայանումը նշված տեղում։', 'question710_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Թույլատրվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (708, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (709, 'Երկաթուղային գծանցներից ի՞նչ հեռավորության վրա է արգելվում տրանսպորտային միջոցների կայանումը։', 'question711_image.png', '["300 մ։", "150 մ։", "100 մ։", "50 մ։", "25 մ։"]', '25 մ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (709, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (710, 'Թույլատրվու՞մ է արդյո՞ք տվյալ դեպքում կանգ առնել ուղեւոր իջեցնելու համար։', 'question712_image.png', '["Թույլատրվում է, եթե դա խոչընդոտ չի ստեղծի ընդհանուր օգտագործման տրանսպորտային միջոցների երթեւեկությանը։", "Արգելվում է։"]', 'Թույլատրվում է, եթե դա խոչընդոտ չի ստեղծի ընդհանուր օգտագործման տրանսպորտային միջոցների երթեւեկությանը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (710, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (711, 'Վարորդներից ո՞րն է պարտավոր կանգ առնել։', 'question713_image.png', '["Թեթեւ մարդատար ավտոմոբիլի վարորդը։", "Ավտոբուսի վարորդը։", "Երկու վարորդն էլ։"]', 'Թեթեւ մարդատար ավտոմոբիլի վարորդը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (711, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (712, 'Տվյալ ճանապարհային գծանշումը թույլատրում է երթեւեկել`', 'question714_image.png', '["Միայն դեպի ձախ։", "Դեպի ձախ եւ հակառակ ուղղությամբ։", "Միայն հակառակ ուղղությամբ։", "Ուղիղ, ձախ եւ հակառակ ուղղությամբ։"]', 'Դեպի ձախ եւ հակառակ ուղղությամբ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (712, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (713, 'Ո՞ր տրանսպորտային միջոցներին է թույլատրվում կայանել տվյալ ճանապարհային նշանի ազդեցության գոտում։', 'question715_image.png', '["Միայն ընդհանուր օգտագործման տրանսպորտային միջոցներին։", "Տրանսպորտային միջոցներին, որոնք վարում են հաշմանդամները եւ միացված հաշվիչով տաքսիներին։"]', 'Տրանսպորտային միջոցներին, որոնք վարում են հաշմանդամները եւ միացված հաշվիչով տաքսիներին։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (713, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (714, 'Ի՞նչ է նշանակում տվյալ ճանապարհային գծանշումը։', 'question716_image.png', '["Ուղեւորներ նստեցնելու-իջեցնելու տեղ։", "Ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետ։", "Ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի եւ տաքսիների կայանման տեղ։"]', 'Ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (714, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (715, 'Ի՞նչ է ցույց տալիս հորիզոնական գծանշման դեղին հոծ գիծը։', 'question717_image.png', '["Այն տեղը, որտեղ արգելվում է տրանսպորտային միջոցների կանգառը եւ կայանումը։", "Այն տեղը, որտեղ թույլատրվում է կանգառ կատարել՝ ուղեւորներ իջեցնելու կամ տրանսպորտային միջոցը բեռնաթափելու համար։", "Այն տեղը, որտեղ արգելվում է տրանսպորտային միջոցների կայանումը։"]', 'Այն տեղը, որտեղ արգելվում է տրանսպորտային միջոցների կանգառը եւ կայանումը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (715, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (716, 'Թույլատրվու՞մ է արդյո՞ք վարորդին հատել տրանսպորտային միջոցների կայանման տեղերի սահմանները նշող գծանշման հոծ գիծը։', 'question718_image.png', '["Արգելվում է։", "Թույլատրվում է։"]', 'Թույլատրվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (716, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (717, 'Սլաքներով նշված ո՞ր ուղղություններով է թույլատրվում երթեւեկությունը։', 'question719_image.png', '["Միայն ուղիղ։", "Դեպի ձախ եւ հակառակ ուղղությամբ։", "Ուղիղ, դեպի ձախ եւ հակառակ ուղղությամբ։"]', 'Միայն ուղիղ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (717, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (718, 'Ի՞նչ է ցույց տալիս այս գծանշումը։', 'question720_image.png', '["Հետիոտնային անցում, որտեղ երթեւեկությունը կարգավորվում է լուսացույցով։", "Այն տեղը, որտեղ հեծանվային արահետը հատում է ճանապարհի երթեւեկելի մասը։", "Այն տեղը, որտեղ հետիոտնային արահետը հատում է ճանապարհի երթեւեկելի մասը։"]', 'Այն տեղը, որտեղ հեծանվային արահետը հատում է ճանապարհի երթեւեկելի մասը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (718, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (719, 'Քանի՞ գոտի ունի ճանապարհը, որտեղ հանդիպակաց ուղղությունների տրանսպորտային հոսքերը բաժանվում են կրկնակի հոծ գծերով։', 'question721_image.png', '["Երկու գոտի։", "Երկու կամ երեք գոտի։", "Երեք գոտի։", "Չորս եւ ավելի գոտիներ։"]', 'Չորս եւ ավելի գոտիներ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (719, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (720, 'Ի՞նչ են նախազգուշացնում երթեւեկելի մասի վրա գծանշված սլաքները։', 'question722_image.png', '["Նախազգուշացնում են վարորդին ճանապարհի վտանգավոր հատվածին մոտենալու մասին։", "Նախազգուշացնում են երթեւեկության գոտու վերջին մոտենալու մասին։", "Ցույց են տալիս ճանապարհի վտանգավոր շրջադարձի ուղղությունը։"]', 'Նախազգուշացնում են երթեւեկության գոտու վերջին մոտենալու մասին։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (720, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (721, 'Գծանշման այս գծերից ո՞րն է օգտագործվում դարձափոխային երթեւեկությամբ գոտիները նշելու համար։', 'question723_image.png', '["1-ին գիծը։", "2-րդ գիծը։", "3-րդ գիծը։", "2-րդ եւ 3 -րդ գծերը։", "3-րդ եւ 4 -րդ գծերը։"]', '2-րդ գիծը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (721, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (722, 'Որտե՞ղ է գծվում կանգառը եւ կայանումն արգելող տեղերը նշող դեղին հոծ գիծը։', 'question724_image.png', '["Երթեւեկելի մասի վրա։", "Երթեւեկելի մասի եզրի մոտ։", "Երթեւեկելի մասի եզրի մոտ կամ եզրաքարի վերին մակերեսին։", "Միայն եզրաքարի վերին մակերեսին։"]', 'Երթեւեկելի մասի եզրի մոտ կամ եզրաքարի վերին մակերեսին։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (722, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (723, 'Ճանապարհային նշաններից որի՞ հետ կարող է կիրառվել դեղին գույնի ընդհատվող գծանշումը։', 'question725_image.png', '["«Կանգառն արգելվում է»։", "«Կայանելն արգելվում է»։", "«Կայանելն արգելվում է ամսվա կենտ օրերին»։"]', '«Կայանելն արգելվում է»։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (723, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (724, 'Ո՞ր տրանսպորտային միջոցներին է թույլատրվում երթեւեկել երթեւեկելի մասի աջ գոտիով։', 'question726_image.png', '["Բոլոր մեխանիկական տրանսպորտային միջոցներին։", "Ընդհանուր օգտագործման տրանսպորտային միջոցներին եւ տաքսիներին։", "Միայն հեծանիվներին։", "Միայն ընդհանուր օգտագործման տրանսպորտային միջոցներին։"]', 'Միայն ընդհանուր օգտագործման տրանսպորտային միջոցներին։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (724, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (725, 'Այս ճանապարհային գծանշումն ունի հետեւյալ նշանակությունը։', 'question727_image.png', '["Ցույց է տալիս մայթամերձ կայանման տեղերը, որտեղ նշված են մեխանիկական տրանսպորտային միջոցների կանգնեցման ձեւերը։", "Ցույց է տալիս այն տեղերը, որտեղ արգելվում է մեխանիկական տրանսպորտային միջոցների կանգառը։", "Ցույց է տալիս ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետերը եւ տաքսիների կայանման վայրերը։"]', 'Ցույց է տալիս ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետերը եւ տաքսիների կայանման վայրերը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (725, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (726, 'Այս հորիզոնական ճանապարհային գծանշումը ցույց է տալիս՝', NULL, '["Երթեւեկելի մասի նեղացում, որտեղ նվազում է երթեւեկության գոտիների քանակը տվյալ ուղղությամբ։", "Այն տեղը, որտեղ վարորդը պետք է անհրաժեշտության դեպքում կանգ առնի` հատվող ճանապարհով երթեւեկող տրանսպորտային միջոցներին ճանապարհը զիջելու համար։", "Մոտեցում կանգառն արգելված տեղին։"]', 'Այն տեղը, որտեղ վարորդը պետք է անհրաժեշտության դեպքում կանգ առնի` հատվող ճանապարհով երթեւեկող տրանսպորտային միջոցներին ճանապարհը զիջելու համար։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (726, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (727, 'Թույլատրվու՞մ է արդյոք մուտք գործել սպիտակ լայն գծերով գծանշված ուղղորդ կղզյակ։', 'question729_image.png', '["Թույլատրվում է միայն կանգառ կատարելու համար։", "Թույլատրվում է հետընթացի ժամանակ։", "Արգելվում է։"]', 'Արգելվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (727, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (728, 'Ինչպե՞ս պետք է վարվի վարորդը՝ մոտենալով խաչմերուկին՝ «Կանգ - գիծ» գծանշման եւ լուսացույցի կանաչ ազդանշանի պայմաններում։', 'question730_image.png', '["Կանգ առնի «Կանգ-գծի» մոտ, որից հետո վերսկսի երթեւեկությունը։", "Շարունակի երթեւեկությունը խաչմերուկով` առանց կանգառի։"]', 'Շարունակի երթեւեկությունը խաչմերուկով` առանց կանգառի։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (728, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (729, 'Ի՞նչ է ցույց տալիս այս գծանշումը։', 'question731_image.png', '["Հետիոտնային անցում։", "Այն տեղը, որտեղ հեծանվային արահետը հատում է ճանապարհի երթեւեկելի մասը։", "Անասուններ քշելու համար նախատեսված տեղը։"]', 'Այն տեղը, որտեղ հեծանվային արահետը հատում է ճանապարհի երթեւեկելի մասը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (729, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (730, 'Վարորդը որտե՞ղ պետք է կանգնեցնի տրանսպորտային միջոցն այս գծանշման առկայության դեպքում։', 'question732_image.png', '["Գծանշման մոտ։", "Գծանշման վրա։", "Գծանշումից ոչ պակաս, քան 5 մ հեռավորության վրա։"]', 'Գծանշման մոտ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (730, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (731, 'Ի՞նչ է նշանակում այս գծանշումը։', 'question733_image.png', '["Ընդհանուր օգտագործման տրանսպորտային միջոցների համար նախատեսված երթեւեկության գոտի։", "Հատուկ նշանակության ավտոմոբիլների համար նախատեսված երթեւեկության գոտի։", "Ցույց է տալիս երթեւեկության այն գոտիների սահմանները, որտեղ իրականացվում է դարձափոխային կարգավորում։"]', 'Ցույց է տալիս երթեւեկության այն գոտիների սահմանները, որտեղ իրականացվում է դարձափոխային կարգավորում։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (731, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (732, 'Թույլատրվու՞մ է արդյոք նշված վայրում հետադարձ կատարել։', 'question734_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Թույլատրվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (732, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (733, 'Թույլատրվու՞մ է արդյոք տվյալ գծանշման առկայության դեպքում զբոսաշրջության երթուղով երթեւեկող ավտոբուսի վարորդին մուտք գործել «A» գծանշումով գոտի։', 'question735_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Թույլատրվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (733, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (734, 'Ի՞նչ է ցույց տալիս ընդհատվող լայն գծի տեսքով գծանշումը։', 'question736_image.png', '["Երթեւեկելի մասի եւ կողնակի միջեւ առկա սահմանը։", "Երթեւեկելի մասի հիմնական գոտու եւ թափառքի գոտու միջեւ առկա սահմանը։", "Երթեւեկելի մասի հիմնական գոտու եւ արգելակման գոտու միջեւ առկա սահմանը։"]', 'Երթեւեկելի մասի հիմնական գոտու եւ թափառքի գոտու միջեւ առկա սահմանը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (734, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (735, 'Ո՞ր ավտոմոբիլին է թույլատրվում կանգառ կատարել այս նշանների ազդման գոտում։', NULL, '["Կարմիրին։", "Երկու ավտոմոբիլներին էլ։", "Ոչ մեկին։", "Դեղինին՝ «Հաշմանդամ» ճանաչման նշանով կահավորված։"]', 'Դեղինին՝ «Հաշմանդամ» ճանաչման նշանով կահավորված։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (735, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (736, 'Ո՞ր նկարում է վարորդը ճիշտ կատարել կանգառ` ուղեւորներ իջեցնելու համար։', NULL, '["Ձախ նկարում։", "Երկու նկարներում էլ։", "Աջ նկարում։"]', 'Ձախ նկարում։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (736, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (737, 'Որպես գնացքի կանգառի ազդանշան ծառայում է՝', 'question739_image.png', '["Ձեռքի շրջանաձեւ շարժումը (ցերեկը` վառ գույնի լաթով կամ որեւէ լավ տեսանելի առարկայով, գիշերը` ջ Howell-ով կամ լապտերով)։", "Սկավառակով կամ կարմիր դրոշակով գլխավերեւ բարձրացված ձեռքը։", "Առաջ պարզած ձեռքը։", "Վեր եւ վար ճոճվող` առաջ պարզած ձեռքը։"]', 'Ձեռքի շրջանաձեւ շարժումը (ցերեկը` վառ գույնի լաթով կամ որեւէ լավ տեսանելի առարկայով, գիշերը` ջ Howell-ով կամ լապտերով)։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (737, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (738, 'Բնակավայրերում, յուրաքանչյուր ուղղությամբ մեկ երթեւեկելի գոտի ունեցող եւ մեջտեղում տրամվայի գծեր չունեցող ճանապարհների ձախ կողմում կանգառն ու կայանումը՝', 'question740_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Թույլատրվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (738, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (739, '«Կանգ-գծից» կամ «Երթեւեկությունն առանց կանգառի արգելվում է» նշանից ի՞նչ հեռավարության վրա պետք է կանգնեցվի տրանսպորտային միջոցը՝ մոտեցող գնացքին ճանապարհը զիջելու համար։', 'question741_image.png', '["1,5 մ։", "2,5 մ։", "5 մ։", "10 մ։", "Անմիջապես «Կանգ-գծի» եւ (կամ) նշանի մոտ։"]', 'Անմիջապես «Կանգ-գծի» եւ (կամ) նշանի մոտ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (739, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (740, 'Թույլատրվու՞մ է արդյոք կանգառը նշված տեղում։', 'question742_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Արգելվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (740, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (741, 'Թույլատրվու՞մ է արդյոք ավտոմոբիլի կանգառն այս վայրում։', NULL, '["Արգելվում է, քանի որ գծանշման ընդհատվող գծի եւ կանգառած տրանսպորտային միջոցի միջեւ հեռավորությունը պակաս է 3 մետրից։", "Արգելվում է ամսվա զույգ օրերին։", "Թույլատրվում է։"]', 'Թույլատրվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (741, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (742, 'Ո՞ր տրանսպորտային միջոցի վարորդն է խախտել կայանման կանոնները։', 'question744_image.png', '["Կապույտ ավտոմոբիլի վարորդը։", "Կարմիր ավտոմոբիլի վարորդը։", "Երկու վարորդներն էլ խախտել են։", "Երկու վարորդներն էլ չեն խախտել։"]', 'Երկու վարորդներն էլ խախտել են։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (742, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (743, 'Որտե՞ղ է թույլատրվում երկարատեւ հանգստի, գիշերակացի եւ այլ նպատակներով կայանելը բնակավայրերից դուրս։', 'question745_image.png', '["Ճանապարհի կողնակներին։", "Կայանման համար նախատեսված հրապարակներում կամ ճանապարհի սահմաններից դուրս։", "Ճանապարհի երթեւեկելի մասի աջ SIDE-ով` չխոչընդոտելով այլ տրանսպորտային միջոցների երթեւեկությունը։", "Ճանապարհի ձախ SIDE-ով` ապահովելով ճանապարհային երթեւեկության անվտանգությունը։"]', 'Կայանման համար նախատեսված հրապարակներում կամ ճանապարհի սահմաններից դուրս։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (743, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (744, 'Կանգառն արգելվում է, եթե հոծ գծի եւ կանգնած տրանսպորտային միջոցի միջեւ տարածությունը կազմում է`', NULL, '["6 մ։", "5.5 մ։", "4 մ։", "3.5 մ։", "2.5 մ։"]', '2.5 մ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (744, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (745, 'Եթե երկաթուղային գծանցով երթեւեկությունը արգելված է եւ բացակայում են լուսացույցը, ճանապարհային նշանները, գծանշումն ու ուղեփակոցը, ապա վարորդը պետք է կանգնի՝', 'question747_image.png', '["Մոտակա ռելսից ոչ պակաս, քան 5 մ հեռավորության վրա։", "Մոտակա ռելսից ոչ պակաս, քան 7 մ հեռավորության վրա։", "Մոտակա ռելսից ոչ պակաս, քան 10 մ հեռավորության վրա։"]', 'Մոտակա ռելսից ոչ պակաս, քան 10 մ հեռավորության վրա։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (745, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (746, 'Ի՞նչ հեռավորության վրա է արգելվում տրանսպորտային միջոցների կայանումը երկաթուղային գծանցներից՝', 'question748_image.png', '["15 մ։", "50 մ։", "100 մ։", "150 մ։"]', '15 մ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (746, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (747, 'Ո՞ր պատասխանում են ճիշտ թվարկած կանգառի կանոնները խախտած վարորդները։', NULL, '["Կարմիր ավտոմոբիլի եւ մոտոցիկլի վարորդները։", "Կապույտ ավտոմոբիլի վարորդը։", "Մոտոցիկլի վարորդը։", "Բոլոր տրանսպորտային միջոցների վարորդները։"]', 'Բոլոր տրանսպորտային միջոցների վարորդները։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (747, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (748, 'Ո՞ր տրանսպորտային միջոցների վարորդներն են սխալ կանգառ կատարել ուղեւորներ իջեցնելու համար։', 'question750_image.png', '["Թեթեւ մարդատար ավտոմոբիլի վարորդը։", "Մոտոցիկլի վարորդը։", "Ավտոբուսի վարորդը։", "Մոտոցիկլի և ավտոբուսի վարորդները։", "Բոլոր վարորդները։"]', 'Մոտոցիկլի և ավտոբուսի վարորդները։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (748, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (749, 'Եթե երկաթուղային գծանցով երթեւեկությունն արգելված է եւ բացակայում են լուսացույցը, ճանապարհային նշաններն ու գծանշումը, ապա վարորդը պետք է կանգնի՝', 'question751_image.png', '["Ուղեփակոցից ոչ պակաս, քան 5 մ հեռավորության վրա։", "Ուղեփակոցից ոչ պակաս, քան 3 մ հեռավորության վրա։", "Ուղեփակոցից անմիջապես առաջ։"]', 'Ուղեփակոցից ոչ պակաս, քան 5 մ հեռավորության վրա։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (749, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (750, 'Թույլատրվու՞մ է զբոսաշրջային ավտոբուսին երթեւեկել «A» գծանշումով գոտիով։', 'question752_image.png', '["Արգելվում է։", "Թույլատրվում է։"]', 'Արգելվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (750, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (751, 'Ի՞նչ է նշանակում երթեւեկելի մասի գոտում գծանշված «A» տառը։', 'question753_image.png', '["Ճանապարհի (երթուղու) համարը։", "Ընդհանուր օգտագործման տրանսպորտային միջոցների երթեւեկության համար նախատեսված հատուկ գոտի։", ",,A\" կարգի տրանսպորտային միջոցների երթեւեկության համար նախատեսված հատուկ գոտի։"]', 'Ընդհանուր օգտագործման տրանսպորտային միջոցների երթեւեկության համար նախատեսված հատուկ գոտի։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (751, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (752, 'Տրանսպորտային միջոցին թույլատրվու՞մ է կանգնել նշված տեղում ուղեւորներ իջեցնելու համար։', 'question754_image.png', '["Թույլատրվում է։", "Արգելվում է։", "Թույլատրվում է` բայց մայթին բարձրանալով։"]', 'Արգելվում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (752, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (753, 'Թույլատրվու՞մ է շարունակել երթեւեկությունը սլաքով նշված ուղղությամբ։', 'question755_image.png', '["Արգելվում է։", "Թույլատրվում է բոլոր դեպքերում։", "Թույլատրվում է ուղեւորներ իջեցնելու նպատակով կանգառ կատարելու համար։", "Թույլատրվում է բեռնատար ավտոմոբիլին վարձելու նպատակով։"]', 'Թույլատրվում է ուղեւորներ իջեցնելու նպատակով կանգառ կատարելու համար։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (753, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (754, 'Այսպիսի ուղղաձիգ գծանշմամբ նշվում են`', 'question756_image.png', '["Կամրջի, թունելի ստորին եզրերը։", "Չլուսավորված թունելների մուտքը։", "Ճանապարհային շինությունների ցանկացած տարր, որը վտանգ է ստեղծում երթեւեկության համար։"]', 'Կամրջի, թունելի ստորին եզրերը։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (754, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (755, 'Ինչպե՞ս պետք է վարվի թեթեւ մարդատար ավտոմոբիլի վարորդը, եթե ավտոբուսի վարորդը սկսել է արգելակել։', 'question757_image.png', '["Շարունակի երթեւեկությունը։", "Դանդաղեցնի ընթացքը, անհրաժեշտության դեպքում կանգնի եւ շարունակի երթեւեկությունը` համոզվելով, որ անցումում հետիոտներ չկան։", "Կանգ առնի եւ շարունակի երթեւեկությունը միայն այն դեպքում, երբ ավտոբուսը կվերսկսի երթեւեկությունը։"]', 'Դանդաղեցնի ընթացքը, անհրաժեշտության դեպքում կանգնի եւ շարունակի երթեւեկությունը` համոզվելով, որ անցումում հետիոտներ չկան։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (755, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (756, 'Ավտոբուսի վարորդը կատարել է կանգառ ուղեւորներ նստեցնելու նպատակով։ Թեթեւ մարդատար ավտոմոբիլը երթեւեկում է 70 կմ/ժ արագությամբ։ Ո՞ր տրանսպորտային միջոցի վարորդն է խախտում ճանապարհային երթեւեկության կանոնների պահանջները։', 'question758_image.png', '["Ոչ ոք։", "Ավտոբուսի վարորդը։", "Թեթեւ մարդատար ավտոմոբիլի վարորդը։", "Երկու վարորդներն էլ։"]', 'Ոչ ոք։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (756, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (757, 'Թվարկվածներից ո՞ր դեպքում կարող է ավտոբուսի վարորդն անցնել երկկողմ երթեւեկության եռագոտի ճանապարհի մեջտեղի գոտի, որը օգտագործվում է երկու ուղղությամբ երթեւեկության համար։', 'question759_image.png', '["Վազանցելու կամ շրջանցելու նպատակով։", "Ձախ շրջադարձ կամ հետադարձ կատարելու նպատակով։", "Վերոնշյալ երկու դեպքում էլ։", "Ոչ մի պատասխանը ճիշտ չէ։"]', 'Վերոնշյալ երկու դեպքում էլ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (757, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (758, 'Որտե՞ղ պետք է կանգ առնի վարորդը տվյալ իրավիճակում։', 'question760_image.png', '["Կանգառը պարտադիր չէ։", "Լուսացույցի առջեւ։", "«Կանգ-գիծ» գծանշման առջեւ։", "Երթեւեկելի գոտիների հատման առջեւ։"]', '«Կանգ-գիծ» գծանշման առջեւ։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (758, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (759, 'Ավտոբուսը կանգ է առել հետիոտնին զիջելու համար։ Թեթեւ մարդատար ավտոմոբիլի վարորդը տվյալ իրադրությունում խախտու՞մ է ճանապարհային երթեւեկության կանոնների պահանջները։', 'question761_image.png', '["Խախտում է։", "Չի խախտում։"]', 'Խախտում է։', 7);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (759, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (760, 'Թույլատրվու՞մ է կանոնավոր ուղևորափոխադրումներ իրականացնող ավտոբուսի վարորդին ուղեւորներ նստեցնելու նպատակով կանգառ կատարել նշված վայրում։', 'question762_image.png', '["Արգելվում է։", "Թույլատրվում է։"]', 'Արգելվում է։', 7);
