INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (761, 'Զբոսաշրջային ավտոբուսի վարորդը երկարատեւ հանգստի նպատակով իրավունք ունի՞ կանգ առնել նշված վայրում։', 'question763_image.png', '["Իրավունք չունի։", "Իրավունք ունի։"]', 'Իրավունք չունի։', 7);
