INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (762, 'Դեպի ձախ երթեւեկությունը շարունակելու համար որտե՞ղ պետք է կանգ առնի ավտոբուսի վարորդը ճանապարհը թեթեւ մարդատար ավտոմոբիլին զիջելու համար։', 'question764_image.png', '["Ճանապարհային նշանի առջեւ։", "Գծանշման մոտ։", "Վարորդի հայեցողությամբ անվտանգ տեղում։"]', 'Գծանշման մոտ։', 7);
