INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (763, 'Տվյալ իրավիճակում որտե՞ղ պետք է կանգ առնել։', 'question765_image.png', '["Առաջին ճանապարհային նշանի մոտ։", "«Կանգ-գիծ» գծանշման առջեւ։", "Երկրորդ ճանապարհային նշանի մոտ։", "Կանգառը պարտադիր չէ։"]', '«Կանգ-գիծ» գծանշման առջեւ։', 7);
