INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (764, 'Տվյալ նշանի ազդեցության գոտում ո՞ր տրանսպորտային միջոցներին է թույլատրվում կանգառ կատարել։', 'question766_image.png', '["Միայն ընդհանուր օգտագործման տրանսպորտային միջոցներին։", "Միայն հաշմանդամների կողմից ղեկավարվող տրանսպորտային միջոցներին։", "Միայն միացված հաշվիչով տաքսիներին։", "Բոլորին արգելվում է։"]', 'Բոլորին արգելվում է։', 7);
