INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (765, 'Նշված ճանապարհային նշանների ազդման գոտում թույլատրվու՞մ է կանգառ կատարել, ուղեւորներ նստեցնելու նպատակով։', NULL, '["Թույլատրվում է։", "Արգելվում է։"]', 'Թույլատրվում է։', 7);
