INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (766, 'Ո՞ր տրանսպորտային միջոցների համար է առանձնացված «A» տառով գծանշված գոտին։', NULL, '["Միայն ավտոբուսների համար, որոնք շարժվում են սահմանված երթուղով։", "Տրոլեյբուսների եւ տաքսիների համար։", "Ընդհանուր օգտագործման տրանսպորտային միջոցների համար։"]', 'Ընդհանուր օգտագործման տրանսպորտային միջոցների համար։', 7);
