INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (825, 'Երբ նարնջագույն և սպիտակ գծանշումները իրար հակասում են, վարորդները', 'question827_image.png', '["Կարող են կատարել իրենց հարմար գծանշման պահանջները", "Պետք է կատարեն սպիտակ գծանշման պահանջները", "Պետք է կատարեն նարնջագույն գծանշման պահանջները"]', 'Պետք է կատարեն նարնջագույն գծանշման պահանջները', 7);
