INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (828, 'Այս գծանշումը', 'question830_image.png', '["Բնակելի գոտու սահմաններն է ցույց տալիս", "Արհեստական անհարթությունն է ցույց տալիս", "Արգելում է հետագա երթևեկությունը"]', 'Արհեստական անհարթությունն է ցույց տալիս', 7);
