INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (835, 'Ընդհատվող գծանշման գծիկների մեծացումը հայտնում է', 'question837_image.png', '["Գոտու վերջին մոտենալու մասին", "Վտանգավոր հատվածին մոտենալու", "Որ այդ գծանշումը շուտով հոծ է դառնալու"]', 'Որ այդ գծանշումը շուտով հոծ է դառնալու', 7);
