INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (843, 'Ո՞ր ուղղությամբ է թույլատրվում երթեւեկությունը։', NULL, '["Միայն ուղիղ։", "Ուղիղ եւ դեպի աջ։", "Ուղիղ, դեպի աջ եւ դեպի ձախ։", "Բոլոր ուղղություններով։"]', 'Ուղիղ, դեպի աջ եւ դեպի ձախ։', 8);
