INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (845, 'Ի՞նչ արագությամբ է թույլատրվում երթեւեկել 3.5 տ ոչ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներով՝ բնակավայրերից դուրս։', NULL, '["90 կմ/ժ արագությունից ոչ ավելի։", "70 կմ/ժ արագությունից ոչ ավելի։", "80 կմ/ժ արագությունից ոչ ավելի։"]', '90 կմ/ժ արագությունից ոչ ավելի։', 8);
