INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (847, 'Թույլատրվու՞մ է արդյոք միջքաղաքային ավտոբուսի վարորդին բնակավայրերից դուրս գերազանցել 70 կմ/ժ արագությունը։', NULL, '["Թույլատրվում է` միայն երթեւեկության համար տվյալ ուղղությամբ երկու եւ ավելի գոտի ունեցող ճանապարհներով երթեւեկելիս։", "Թույլատրվում է, եթե չի գերազանցում 90 կմ/ժ արագությունը։", "Արգելվում է։"]', 'Թույլատրվում է, եթե չի գերազանցում 90 կմ/ժ արագությունը։', 8);
