INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (848, 'Քարշակման ժամանակ վթարային լուսային ազդանշանի բացակայության կամ անսարքության դեպքում, «Վթարային կանգառ» նշանը տեղադրվում է՝', NULL, '["Քարշակվող տրանսպորտային միջոցի հետեւի մասում։", "Քարշակող տրանսպորտային միջոցի առջեւի մասում։", "Վարորդի հայեցողությամբ` տրանսպորտային միջոցներից մեկի վրա` տեսանելի տեղում։"]', 'Քարշակվող տրանսպորտային միջոցի հետեւի մասում։', 8);
