INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (850, 'Թույլատրվու՞մ է արդյոք կոշտ կամ ճկուն կցիչով քարշակման ժամանակ մարդկանց փոխադրումը բեռնատար ավտոմոբիլի թափքում՝', NULL, '["Թույլատրվում է քարշակող եւ քարշակվող ավտոմոբիլների թափքում։", "Թույլատրվում է միայն քարշակվող ավտոմոբիլի թափքում։", "Թույլատրվում է միայն քարշակող ավտոմոբիլի թափքում։", "Երկու ավտոմոբիլների թափքում էլ արգելվում է։"]', 'Թույլատրվում է միայն քարշակող ավտոմոբիլի թափքում։', 8);
