INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (851, 'Կոշտ կամ ճկուն կցիչով քարշակման ժամանակ նշվածներից ո՞ր դեպքում է թույլատրվում մարդկանց փոխադրումը քարշակվող ավտոմոբիլում։', NULL, '["Թույլատրվում է ավտոբուսում։", "Թույլատրվում է թեթեւ մարդատար ավտոմոբիլում։", "Թույլատրվում է բեռնատար ավտոմոբիլի թափքում՝ կոշտ կցիչով քարշակելիս։"]', 'Թույլատրվում է թեթեւ մարդատար ավտոմոբիլում։', 8);
