INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (868, 'Թեթեւ մարդատար ավտոմոբիլի առջեւի նստատեղին, եթե այն կահավորված չէ երեխաներին պահող հարմարանքով, թույլատրվում է փոխադրել երեխաներ, եթե լրացել է նրանց՝', NULL, '["10 տարին։", "11 տարին։", "12 տարին։"]', '12 տարին։', 8);
