INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (871, 'Թույլատրվու՞մ է արդյոք երթեւեկության ժամանակ մարդկանց գտնվելը բեռնատար ավտոմոբիլի թափքում, եթե այն կահավորված չէ մարդկանց փոխադրելու համար։', NULL, '["Արգելվում է։", "Թույլատրվում է՝ ավտոմայրուղի չհամարվող ճանապարհներին։", "Թույլատրվում է՝ միայն բեռն ուղեկցող կամ այն ստանալու համար մեկնող անձանց՝ այն պայմանով, որ նրանք ապահովված են ավտոմոբիլի կողերի մակարդակից ցածր տեղադրված նստարաներով։"]', 'Թույլատրվում է՝ միայն բեռն ուղեկցող կամ այն ստանալու համար մեկնող անձանց՝ այն պայմանով, որ նրանք ապահովված են ավտոմոբիլի կողերի մակարդակից ցածր տեղադրված նստարաներով։', 8);
