INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (893, 'Կոշտ կամ ճկուն կցիչով քարշակման ժամանակ թույլատրվու՞մ է արդյո՞ք ուղեւորների փոխադրումը քարշակվող ավտոբուսում։', NULL, '["Արգելվում է։", "Թույլատրվում է կոշտ կցիչով քարշակման ժամանակ։", "Թույլատրվում է։"]', 'Արգելվում է։', 8);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (893, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (894, 'Քարշակման ժամանակ քարշակվող տրանսպորտային միջոցի վրա պետք է միացված լինեն', NULL, '["Լապտերների հեռահար լույսերը։", "Լապտերների մոտակա լույսերը։", "Վթարային լուսային ազդանշանը։"]', 'Վթարային լուսային ազդանշանը։', 8);
