INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (897, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (898, 'Ի՞նչ արագությամբ է թույլատրվում տրանսպորտային միջոցների երթեւեկությունը «Բնակելի գոտի» եւ «Բնակելի գոտու վերջ» ճանապարհային նշանների ազդեցության տարածքներում։', NULL, '["5 կմ/ժ ոչ ավելի։", "10 կմ/ժ ոչ ավելի։", "20 կմ/ժ ոչ ավելի։"]', '20 կմ/ժ ոչ ավելի։', 8);
