INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (899, 'Ի՞նչ առավելագույն արագությամբ է թույլատրվում թեթեւ մարդատար ավտոմոբիլների երթեւեկությունը այս ճանապարհային նշանի ազդեցության ճանապարհահատվածներում։', NULL, '["70 կմ/ժ։", "80 կմ/ժ։", "90 կմ/ժ։", "100 կմ/ժ։", "110 կմ/ժ։"]', '110 կմ/ժ։', 8);
