INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (995, 'Ինչի՞ մասին է տեղեկացնում թեթեւ մարդատար ավտոմոբիլի վարորդի կողմից ձեռքով տրված ազդանշանը։', 'question997_image.png', '["Աջ շրջադարձ է կատարում։", "Շարունակում է երթեւեկությունը ուղիղ։", "Արգելակում է` ճանապարհը մոտոցիկլին զիջելու համար։"]', 'Աջ շրջադարձ է կատարում։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (995, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (996, 'Ինչի՞ մասին է տեղեկացնում թեթեւ մարդատար ավտոմոբիլի վարորդի կողմից ձեռքով տրված ազդանշանը։', 'question998_image.png', '["Մտադիր է կատարել ձախ շրջադարձ կամ հետադարձ։", "Արգելակում է` ճանապարհը բեռնատար ավտոմոբիլին զիջելու համար։"]', 'Մտադիր է կատարել ձախ շրջադարձ կամ հետադարձ։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (996, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (997, 'Պարտավո՞ր է արդյոք վարորդը միացնել շրջադարձի ցուցիչը տվյալ դեպքում։', 'question999_image.png', '["Պարտավոր է։", "Պարտավոր չէ։"]', 'Պարտավոր է։', 9);
