INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (998, 'Օրվա լուսավոր ժամերին երեխաների կազմակերպված խմբեր տեղափոխելու ժամանակ պետք է միացված լինեն ավտոբուսի`', 'question1000_image.png', '["Լապտերների հեռահար լույսերը։", "Լապտերների մոտակա լույսերը։", "Վթարային լուսային ազդանշանը։", "Սրահի ներքին լուսավորության սարքերը։"]', 'Լապտերների մոտակա լույսերը։', 9);
