INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (999, 'Թույլատրվու՞մ է բեռնատար ավտոմոբիլի վարորդին վազանցել ավտոբուսին, որը երթեւեկում է 60 կմ/ժ արագությամբ։', 'question1001_image.png', '["Արգելվում է։", "Թույլատրվում է։"]', 'Թույլատրվում է։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (999, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1000, 'Թույլատրվու՞մ է վազանց կատարել տվյալ իրավիճակում։', 'question1002_image.png', '["Արգելվում է։", "Թույլատրվում է։", "Թույլատրվում է, եթե ավտոբուսը երթեւեկում է 30 կմ/ժ պակաս արագությամբ։"]', 'Արգելվում է։', 9);
