INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1001, 'Թույլատրվու՞մ է արդյոք մուտք գործել երկաթուղային գծանց տվյալ իրավիճակում։', 'question1003_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Արգելվում է։', 9);
