INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1002, 'Թույլատրվու՞մ է արդյոք մուտք գործել երկաթուղային գծանց տվյալ իրավիճակում։', 'question1004_image.png', '["Թույլատրվում է, եթե գնացք չի մոտենում։", "Թույլատրվում է, եթե ուղեփակոցը բաց է։", "Արգելվում է։"]', 'Արգելվում է։', 9);
