INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1003, 'Ինչպե՞ս պետք է գործել տվյալ իրադրությունում։', 'question1005_image.png', '["Գնացքի բացակայության դեպքում շրջանցել ուղեփակոցը եւ շարունակել երթեւեկությունը։", "Կանգ առնել եւ սպասել ուղեփակոցի բացմանը։"]', 'Կանգ առնել եւ սպասել ուղեփակոցի բացմանը։', 9);
