INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1004, 'Տվյալ իրավիճակում թույլատրվու՞մ է անցնել երկաթուղային գծանցը։', 'question1006_image.png', '["Թույլատրվում է, եթե գնացք չի մոտենում։", "Թույլատրվում է։", "Արգելվում է։"]', 'Արգելվում է։', 9);
