INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1005, 'Տվյալ իրավիճակում թույլատրվու՞մ է անցնել երկաթուղային գծանցը։', 'question1007_image.png', '["Արգելվում է։", "Թույլատրվում է, եթե մոտեցող գնացք չկա։", "Թույլատրվում է, քանի որ գծանցի հերթապահն արգելում է հանդիպակաց տրանսպորտային միջոցի անցումը։"]', 'Արգելվում է։', 9);
