INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1006, 'Տվյալ իրավիճակում որտե՞ղ կարելի է սկսել վազանցը։', 'question1008_image.png', '["Երկաթուղային գծանցում։", "Երկաթուղային գծանցն անցնելուց հետո։", "Երկաթուղային գծանցից 100 մետր անցնելուց հետո։"]', 'Երկաթուղային գծանցն անցնելուց հետո։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1006, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1007, 'Տվյալ իրավիճակում թույլատրվու՞մ է վազանց կատարել։', 'question1009_image.png', '["Թույլատրվում է, քանի որ հանդիպակաց երթեւեկող տրանսպորտային միջոց չկա։", "Արգելվում է։", "Թույլատրվում է, եթե լծասայլը շարժվում է 30 կմ/ժ պակաս արագությամբ։"]', 'Արգելվում է։', 9);
