INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1008, 'Ի՞նչ մանևր է կատարում թեթև մարդատարի վարորդը։', 'question1010_image.png', '["Կողանցում։", "Վազանց։", "Շրջանցում։"]', 'Վազանց։', 9);
