INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1009, 'Թույլատրվում է արդյո՞ք վազանցել մոտոցիկլին։', 'question1011_image.png', '["Թույլատրվում է։", "Արգելվում է։"]', 'Արգելվում է։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1009, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1010, 'Ո՞ր դեպքում է թույլատրվում հանդիպակաց երթևեկության գոտով վազանց կատարել յուրաքանչյուր ուղղությամբ մեկ գոտի ունեցող ճանապարհներին։', 'question1012_image.png', '["Միայն, երբ հանդիպակաց ուղղությամբ գոտին բավարար տարածությամբ ազատ է։", "Միայն, երբ մեզ վազանց չեն կատարում։", "Երկու պայմաններն էլ անհրաժեշտ է, որ ապահովված լինեն։"]', 'Երկու պայմաններն էլ անհրաժեշտ է, որ ապահովված լինեն։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1010, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1011, 'Թույլատրվո՞ւմ է վազանցել նշված իրավիճակում։', 'question1013_image.png', '["Արգելվում է։", "Թույլատրվում է, եթե մանևրը կավարտվի տեսանելիության սահմաններում։", "Թույլատրվում է։"]', 'Թույլատրվում է։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1011, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1012, 'Թույլատրվո՞ւմ է վազանցել բեռնատարին։', 'question1014_image.png', '["Այո։", "Այո, եթե վազանցը մինչև խաչմերուկ կավարտվի։", "Ոչ։"]', 'Այո, եթե վազանցը մինչև խաչմերուկ կավարտվի։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1012, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1013, 'Ի՞նչ է պահանջվում վազանցվող տրանսպորտային միջոցի վարորդից։', 'question1015_image.png', '["Նա պարտավոր է զիջել ճանապարհը վազանց կատարողին։", "Նա որևէ կերպ չպետք է խոչընդոտի վազանցողին՝ բարձրացնելով արագությունը կամ կատարելով այլ գործողություն։"]', 'Նա որևէ կերպ չպետք է խոչընդոտի վազանցողին՝ բարձրացնելով արագությունը կամ կատարելով այլ գործողություն։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1013, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1014, 'Թույլատրվո՞ւմ է այս իրավիճակում վազանց կատարել։', 'question1016_image.png', '["Արգելվում է։", "Թույլատրվում է, եթե բեռնատարի արագությունը 30 կմ/ժ-ից պակաս է։", "Թույլատրվում է։"]', 'Արգելվում է։', 9);
