INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1015, 'Թույլատրվո՞ւմ է բեռնատարի վարորդին վազանցել տրակտորին, եթե թույլատրելի առավելագույն զանգվածը 3 տոննա է։', 'question1017_image.png', '["Այո։", "Այո, եթե տրակտորը 30 կմ/ժ-ից պակաս է ընթանում։", "Ոչ։"]', 'Այո։', 9);
