INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1016, 'Եթե հանդիպակաց երթևեկությունը դժվար է այս իրավիճակում, ապա ճանապարհը պետք է զիջի', 'question1018_image.png', '["Բեռնատարի վարորդը։", "Թեթև մարդատարի վարորդը։"]', 'Բեռնատարի վարորդը։', 9);
