INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1017, 'Հետիոտնային անցման վրա վազանցն', 'question1019_image.png', '["Արգելվում է միայն հետիոտնի առկայության դեպքում։", "Արգելվում է։", "Թույլատրվում է։"]', 'Արգելվում է։', 9);
