INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1019, 'Ի՞նչ է ցույց տալիս ճանապարհային նշանը։', 'question1021_image.png', '["500 մետր հետո տապալված ծառ կա։", "500 մետր հետո հանգստի վայր է։", "500 մետր հատվածում հանգստի վայր է։"]', '500 մետր հետո հանգստի վայր է։', 9);
