INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1020, 'Վարորդը միացնել շրջադարձի լուսային ցուցիչն այս իրավիճակում պարտավո՞ր է։', 'question1022_image.png', '["Պարտավոր է։", "Պարտավոր է, եթե հետևից մոտեցող վարորդ կա։", "Պարտավոր չէ։"]', 'Պարտավոր չէ։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1020, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1021, 'Վարորդի դեպի վեր պարզած ձեռքով ի՞նչ է տեղեկացնում։', 'question1023_image.png', '["Ձախ շրջադարձ կատարելու մասին։", "Ուղիղ երթևեկելու մասին։", "Ընթացքը դանդաղեցնելու մասին։"]', 'Ընթացքը դանդաղեցնելու մասին։', 9);
