INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1022, 'Ազդանշան տալը երթևեկության մյուս մասնակիցների նկատմամբ առավելություն տալի՞ս է։', 'question1024_image.png', '["Տալիս է։", "Չի տալիս։", "Տալիս է միայն շարժում սկսելիս։"]', 'Չի տալիս։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1022, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1023, 'Ի՞նչի մասին է տեղեկացնում մոտոցիկլի վարորդը։', 'question1025_image.png', '["Ուղիղ երթևեկությունը շարունակելու մասին։", "Ձախ շրջադարձ կատարելու մասին։", "Թեթև մարդատարին զիջելու նպատակով արագությունն իջեցնելու մասին։"]', 'Թեթև մարդատարին զիջելու նպատակով արագությունն իջեցնելու մասին։', 9);
