INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1024, 'Ձախ շրջադարձ կատարելիս այս իրավիճակում ազդանշան տալը պարտադի՞ր է։', 'question1026_image.png', '["Պարտադիր է։", "Պարտադիր չէ։"]', 'Պարտադիր է։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1024, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1025, 'Վազանց կատարելիս ձախ շրջադարձի լուսային ցուցիչը ե՞րբ պետք է անջատել։', 'question1027_image.png', '["Անմիջապես ձախ գոտի վերադասավորվելուց հետո։", "Միայն առջևից ընթացողից առաջ անցնելուց հետո։", "Վարորդի հայեցողությամբ։"]', 'Անմիջապես ձախ գոտի վերադասավորվելուց հետո։', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1025, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1026, 'Հետադարձն այս խաչմերուկում կատարելիս ո՞ր շրջադարձի ցուցիչը պետք է միացնենք:', 'question1028_image.png', '["Աջ", "Ձախ", "Ոչ մեկը"]', 'Աջ', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1026, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1027, 'Պարտավոր եք արդյո՞ք նշված իրադրությունում տալ ազդանշան լուսային ցուցիչով:', 'question1029_image.png', '["Այո", "Ոչ", "Այո, եթե աջ գոտով երթևեկող վարորդ կա"]', 'Այո', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1027, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1028, 'Ի՞նչի մասին է տեղեկացնում մոտոցիկլի վարորդը:', 'question1030_image.png', '["Ուղիղ երթևեկությունը շարունակելու մասին", "Աջ շրջադարձ կատարելու մասին", "Ձախ շրջադարձ կամ հետադարձ կատարելու մասին"]', 'Ձախ շրջադարձ կամ հետադարձ կատարելու մասին', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1028, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1029, 'Լուսային ցուցիչով տրված մանևրի մասին ազդանշանը պետք է դադարեցվի:', 'question1031_image.png', '["Անմիջապես մանևրից առաջ", "Անմիջապես մանևրից հետո", "Մանևրի ընթացքում"]', 'Անմիջապես մանևրից հետո', 9);
