INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1030, 'Լուսային ցուցիչով ազդանշան տալ նշված իրավիճակում:', 'question1032_image.png', '["Պարտադիր է", "Ըստ վարորդի հայեցողության"]', 'Պարտադիր է', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1030, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1031, 'Ո՞ր վարորդն է աջ շրջադարձի ազդանշան տալիս:', 'question1033_image.png', '["Միայն աջում գտնվողը", "Երկու վարորդներն էլ", "Միայն ձախում գտնվողը"]', 'Երկու վարորդներն էլ', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1031, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1032, 'Կայանատեղիներում կամ ավտոլցակայաններում մանևրելիս ազդանշան տալ լուսային ցուցիչով:', 'question1034_image.png', '["Պարտավոր եք", "Պարտավոր չեք"]', 'Պարտավոր եք', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1032, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1033, 'Այս իրավիճակում ի՞նչ կարող է նշանակել վարորդի դուրս պարզած ձեռքը:', 'question1035_image.png', '["Տեղեկություն նրա կողմից երթևեկությունը սկսելու վերաբերյալ", "Կանգնելու մասին խնդրելու նշան", "Ընդհանուր տագնապի ազդանշան"]', 'Տեղեկություն նրա կողմից երթևեկությունը սկսելու վերաբերյալ', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1033, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1034, 'Ի՞նչ ազդանշաններ պետք է տաք նշված հետագծով հետադարձը կատարելիս:', 'question1036_image.png', '["Աջ", "Ձախ", "Նախ աջ, ապա ձախ"]', 'Նախ աջ, ապա ձախ', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1034, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1035, 'Եթե անմիջապես խաչմերուկից հետո մտադրվել եք կանգառ կատարել երթևեկության մասնակիցներին շփոթության մեջ չգցելու նպատակով, երբ պետք է միացնեք աջ շրջադարձի լուսային ցուցիչը:', 'question1037_image.png', '["Նախապես մինչև խաչմերուկը", "Խաչմերուկ մուտք գործելուց հետո"]', 'Խաչմերուկ մուտք գործելուց հետո', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1035, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1036, 'Վադարձն ավարտող մեքենայի վարորդը ունի արդյո՞ք առավելություն համընթաց գոտի վերադասավորվելիս, տվյալ գոտով երթևեկող վարորդի նկատմամբ:', 'question1038_image.png', '["Ոչ", "Այո"]', 'Ոչ', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1036, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1037, 'Մերձակա տարածքից դուրս եկող հատուկ ձայնային և լուսային ազդանշաններ միացրած վարորդին զիջել:', 'question1039_image.png', '["Պարտավոր չենք", "Պարտավոր ենք"]', 'Պարտավոր ենք', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1037, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1038, 'Խաչմերուկն ուղիղ անցնելիս պարտավոր ենք արդյո՞ք զիջել ճանապարհը միացված դեղին առկայծող փարոսիկներով բեռնատարի վարորդին:', 'question1040_image.png', '["Այո", "Ոչ"]', 'Ոչ', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1038, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1039, 'Զիջել ճանապարհը պարտավոր ենք:', 'question1041_image.png', '["Մոտոցիկլի վարորդին", "Հատուկ լուսային և ձայնային ազդանշաններ միացրած ավտոմոբիլի վարորդին", "Երկու վարորդներին"]', 'Երկու վարորդներին', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1039, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1040, 'Զիջել ճանապարհը պարտավոր ենք:', 'question1042_image.png', '["Երկու վարորդներին", "Դեղին առկայծող փարոսիկով բեռնատարի վարորդին", "Միայն ավտոբուսի վարորդին"]', 'Միայն ավտոբուսի վարորդին', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1040, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1041, 'Այս իրադրությունում:', 'question1043_image.png', '["Խաչմերուկը կանցնեք առաջինը", "Պետք է զիջեք ճանապարհը ձախից մոտեցող վարորդին"]', 'Պետք է զիջեք ճանապարհը ձախից մոտեցող վարորդին', 9);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1041, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1042, 'Զիջել պարտավոր ենք:', NULL, '["Բոլորին", "Ոստիկանության ավտոմոբիլի վարորդին", "Ոչ ոքի"]', 'Ոստիկանության ավտոմոբիլի վարորդին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1042, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1043, 'Ձախ շրջադարձ կատարելիս:', NULL, '["Խաչմերուկն առաջինը կանցնեք", "Կզիջեք միայն ոստիկանության ավտոմոբիլի վարորդին", "Կզիջեք բոլոր վարորդներին"]', 'Կզիջեք բոլոր վարորդներին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1043, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1044, 'Խաչմերուկն ուղիղ անցնելիս պարտավոր ենք արդյո՞ք զիջել ճանապարհը միացված դեղին առկայծող փարոսիկներով բեռնատարի վարորդին:', NULL, '["Այո", "Ոչ"]', 'Ոչ', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1044, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1045, 'Զիջել ճանապարհը պարտավոր ենք:', NULL, '["Մոտոցիկլի վարորդին", "Հատուկ լուսային և ձայնային ազդանշաններ միացրած ավտոմոբիլի վարորդին", "Երկու վարորդներին"]', 'Երկու վարորդներին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1045, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1046, 'Զիջել ճանապարհը պարտավոր ենք:', NULL, '["Երկու վարորդներին", "Դեղին առկայծող փարոսիկով բեռնատարի վարորդին", "Միայն ավտոբուսի վարորդին"]', 'Միայն ավտոբուսի վարորդին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1046, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1047, 'Այս իրադրությունում:', NULL, '["Խաչմերուկը կանցնեք առաջինը", "Պետք է զիջեք ճանապարհը ձախից մոտեցող վարորդին"]', 'Պետք է զիջեք ճանապարհը ձախից մոտեցող վարորդին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1047, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1048, 'Զիջել պարտավոր ենք:', NULL, '["Բոլորին", "Ոստիկանության ավտոմոբիլի վարորդին", "Ոչ ոքի"]', 'Ոստիկանության ավտոմոբիլի վարորդին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1048, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1049, 'Ձախ շրջադարձ կատարելիս:', NULL, '["Խաչմերուկն առաջինը կանցնեք", "Կզիջեք միայն ոստիկանության ավտոմոբիլի վարորդին", "Կզիջեք բոլոր վարորդներին"]', 'Կզիջեք բոլոր վարորդներին', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1049, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1050, 'Վթարի հետեւանքով հետիոտն ընկել է եւ վնասել ձեռքը։ Նախաբազկի վրա կա մեծ վերք (մոտ 5 սմ երկարությամբ), որից միալար մուգ գույնի արյուն է հոսում։ Ի՞նչ է պետք անել արյունահոսությունը դադարեցնելու նպատակով:', NULL, '["Լվանալ վերքը ջրով:", "Բարձրացնել տուժածի ձեռքը եւ տեղադրել ճնշող վիրակապ:", "Վերքին յոդի սպիրտային լուծույթ քսել:"]', 'Բարձրացնել տուժածի ձեռքը եւ տեղադրել ճնշող վիրակապ:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1050, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1051, 'Վերջույթների փափուկ հյուսվածքների փակ վնասվածքների դեպքում առաջին ժամերին օգնություն ցուցաբերելիս պետք է:', NULL, '["Վնասվածքին տաքացնող թրջոց դնել:", "Վնասված մասի վրա սառը թրջոց դնել եւ բարձրացնել:", "Վնասված մասի վրա սառը թրջոց դնել եւ պահել սրտի մակարդակից ցածր:", "Վնասվածքին սպիրտային թրջոց դնել:"]', 'Վնասված մասի վրա սառը թրջոց դնել եւ բարձրացնել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1051, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1052, 'Վարորդը կքանստած երկար ժամանակ փոխում էր ավտոմեքենայի անիվը։ Կտրուկ վեր կենալով` նա բռնում է գլուխը եւ հանկարծ կորցնելով գիտակցությունը, ընկնում։ Ի՞նչ է պետք անել:', NULL, '["Փորձել նստեցնել նրան:", "Բարձրացնել նրա ոտքերը:", "Երեսին սառը ջուր լցնել:", "Ապտակել երեսին:"]', 'Բարձրացնել նրա ոտքերը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1052, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1053, 'Ի՞նչ է պետք անել, եթե հնարավոր չէ ապահովել դեպքի վայրի անվտանգությունը:', NULL, '["Բոլորին օգնություն ցուցաբերել, բայց զգույշ լինել:", "Օգնություն ցուցաբերել այն տուժածին, որն ավելի մոտ է գտնվում ձեզ:", "Չմոտենալ, անմիջապես ահազանգել եւ չթողնել կողմնակի մարդկանց մոտենալ դեպքի վայր:", "Չմոտենալ, խնդրել մեկ ուրիշին օգնություն ցույց տալ:"]', 'Չմոտենալ, անմիջապես ահազանգել եւ չթողնել կողմնակի մարդկանց մոտենալ դեպքի վայր:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1053, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1054, 'Դուք տեսնում եք ընկած մարդու եւ նկատում նրա սրունքից դուրս ցցված ոսկորը եւ արյուն։ Եթե դեպքի վայրն անվտանգ է, ի՞նչ պետք է անել առաջին հերթին:', NULL, '["Ահազանգել շտապ օգնություն:", "Ստուգել գիտակցությունը եւ շնչառությունը:", "Անշարժացնել ոտքը:"]', 'Ստուգել գիտակցությունը եւ շնչառությունը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1054, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1055, 'Երբ տուժածը ունի վերջույթի բաց կոտրվածք, ապա օգնություն ցուցաբերելիս անհրաժեշտ է:', NULL, '["Անմիջապես բարձրացնել տուժածի վերջույթը:", "Ստերիլ անձեռոցիկով ծածկել վերքը եւ անշարժացնել վնասված վերջույթը:", "Ուղղակի ճնշմամբ դադարեցնել արյունահոսությունը:", "Տեղադրել սառը թրջոցներ վերքին:"]', 'Ստերիլ անձեռոցիկով ծածկել վերքը եւ անշարժացնել վնասված վերջույթը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1055, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1056, 'Կրծքավանդակի վնասվածքի դեպքում պետք է:', NULL, '["Պառկեցնել տուժածին հորիզոնական դիրքով:", "Նստեցնել` հենելով վնասված կողմի վրա:", "Նստեցնել` հենելով առողջ կողմի վրա:"]', 'Նստեցնել` հենելով վնասված կողմի վրա:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1056, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1057, 'Տուժածի որովայնի վրա բաց վնասվածքից օրգանների արտընկման դեպքում պետք է:', NULL, '["Լվանալ եւ զգուշորեն փորձել տեղը մտցնել արտընկած օրգանները:", "Արտընկած օրգանները ծածկել մաքուր խոնավ գործվածքով եւ պոլիէթիլենային թաղանթով:", "Կտրել արտընկած օրգանները եւ վերքը վիրակապել:", "Ձեռք չտալ, այդ վիճակում տեղափոխել հիվանդանոց:"]', 'Արտընկած օրգանները ծածկել մաքուր խոնավ գործվածքով եւ պոլիէթիլենային թաղանթով:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1057, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1058, 'Անգիտակից վիճակում գտնվող եւ շնչառություն ունեցող տուժածին պետք է:', 'question1060_image.png', '["Պառկեցնել մեջքի վրա:", "Բացել բերանը եւ դուրս քաշել լեզուն:", "Շրջել կողքի եւ գլուխը հետ տանել:"]', 'Շրջել կողքի եւ գլուխը հետ տանել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1058, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1059, 'Ուժեղ արյունահոսության դեպքում պետք է:', 'question1061_image.png', '["Միայն վիրակապով ծածկել վերքը:", "Ճնշումով վիրակապել վնասված մասը եւ ճնշում գործադրել զարկերակի սեղման կետի վրա:", "Մոխիր լցնել վերքի մեջ:"]', 'Ճնշումով վիրակապել վնասված մասը եւ ճնշում գործադրել զարկերակի սեղման կետի վրա:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1059, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1060, 'Ավտովթարի դեպքում առաջին հերթին պետք է:', 'question1062_image.png', '["Տուժածին բերել հարմար դիրքի:", "Զննել դեպքի վայրը եւ ապահովել անվտանգությունը:", "Ստուգել տուժածի մոտ ուժեղ արյունահոսությունների առկայությունը:", "Տեղափոխել տուժածին մեքենայից:"]', 'Զննել դեպքի վայրը եւ ապահովել անվտանգությունը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1060, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1061, 'Եթե տուժածի վերքի մեջ օտար մարմին կա, ապա օգնություն ցուցաբերելիս պետք է:', 'question1063_image.png', '["Հեռացնել օտար մարմինը վերքից:", "Թողնել վնասված մասն արյունահոսի:", "Ապահովել օտար մարմնի անշարժ վիճակը:", "Սպիրտով մշակել վերքի տարածքը:"]', 'Ապահովել օտար մարմնի անշարժ վիճակը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1061, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1062, 'Հանգիստ վիճակում չափահաս մարդու անոթազարկը կազմում է:', 'question1064_image.png', '["40-60 զարկ մեկ րոպեում:", "60-80 զարկ մեկ րոպեում:", "80-100 զարկ մեկ րոպեում:"]', '60-80 զարկ մեկ րոպեում:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1062, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1063, 'Հանգիստ վիճակում չափահաս մարդու շնչառությունը կազմում է:', 'question1065_image.png', '["12-18 շնչառական շարժում մեկ րոպեում:", "20-30 շնչառական շարժում մեկ րոպեում:", "40-60 շնչառական շարժում մեկ րոպեում:"]', '12-18 շնչառական շարժում մեկ րոպեում:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1063, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1064, 'Վթարի դեպքում ավտոմեքենայից տուժածին պետք է տեղափոխել, եթե:', 'question1066_image.png', '["Տուժածն ունի լուրջ վնասվածքներ:", "Դեպքի վայրը վտանգավոր է, օրինակ` պայթյունի վտանգ կա:", "Մեքենայի վրա ընկած է հոսանքի հաղորդալար:"]', 'Դեպքի վայրը վտանգավոր է, օրինակ` պայթյունի վտանգ կա:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1064, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1065, 'Որովայնային ներքին արյունահոսության կասկածի դեպքում օգնություն ցուցաբերելիս պետք է:', 'question1067_image.png', '["Պառկեցնել տուժածին եւ վնասվածքին սառը թրջոց տեղադրել:", "Որովայնին տաք ջեռակ տեղադրել:", "Որովայնին ճնշող վիրակապ տեղադրել:", "Տուժածին մեծ քանակով հեղուկ տալ խմելու:"]', 'Պառկեցնել տուժածին եւ վնասվածքին սառը թրջոց տեղադրել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1065, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1066, 'Դուք հարեւանի ավտոտնակից լսում եք մեքենայի շարժիչի ձայնը եւ, բացելով դուռը, տեսնում եք գետին ընկած հարեւանին։ Ի՞նչ է պետք անել առաջին հերթին:', 'question1068_image.png', '["Լայն բացել դռները եւ անջատել շարժիչը, հնարավորության դեպքում տեղափոխել տուժածին դեպքի վայրից:", "Մանրակրկիտ զննել տուժածի մարմինը` վնասվածքներ հայտնաբերելու համար:", "Բերել տուժածին կողքի ապահովության դիրքի:", "Օգնել տուժածին ընդունել կիսանստած դիրք:"]', 'Լայն բացել դռները եւ անջատել շարժիչը, հնարավորության դեպքում տեղափոխել տուժածին դեպքի վայրից:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1066, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1067, 'Անգիտակից վիճակում գտնվող տուժածին հայտնաբերելուց հետո առաջին հերթին պետք է:', 'question1069_image.png', '["Խմեցնել նրան սառը ջուր:", "Բերել նրան կողքի ապահովության դիրքի:", "Պահպանել մարմնի նորմալ ջերմաստիճանը:", "Բացել շնչուղիները եւ ստուգել շնչառությունը:"]', 'Բացել շնչուղիները եւ ստուգել շնչառությունը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1067, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1068, 'Վերջույթներում արյան շրջանառությունը ստուգելու համար վիրակապից ներքեւ սեղմում եւ բաց եք թողնում տուժածի վնասված վերջույթի եղունգը։ Դուք որոշում եք, որ արյան շրջանառությունը վերջույթում խանգարված է, եթե:', NULL, '["Տուժածը ցավ է զգում:", "Տուժածն անհանգստություն է զգում:", "Սեղմելիս եղունգը դժվարությամբ է սպիտակում:", "Եղունգը դժվարությամբ է կրկին վարդագույն դառնում:"]', 'Եղունգը դժվարությամբ է կրկին վարդագույն դառնում:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1068, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1069, 'Շաքարախտով հիվանդ ձեր ընկերն իրեն վատառողջ է զգում եւ չի հիշում, թե վերջին անգամ երբ է ինսուլին ընդունել։ Ի՞նչ է պետք անել այդ դեպքում առաջին հերթին:', NULL, '["Տալ նրան շաքար կամ քաղցր հեղուկ:", "Առաջարկել նրան մի քանի ժամ հանգստանալ:", "Խորհուրդ տալ ներարկել ինսուլին:"]', 'Տալ նրան շաքար կամ քաղցր հեղուկ:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1069, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1070, 'Առավել վտանգավոր արյունահոսության նշան է, եթե:', NULL, '["Արյունը 10 րոպեի ընթացքում մակարդվում է:", "Արյունը շիթով բխում է վերքից:", "Արյունը մուգ կարմիր գույնի է:", "Արյունը միալար հոսում է վերքից:"]', 'Արյունը շիթով բխում է վերքից:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1070, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1071, 'Մեքենան բախվել է սյանին եւ էլեկտրական հաղորդալարն ընկած է մեքենայի կողքն անգիտակից վիճակում պառկած տուժածի վրա։ Օգնություն ցուցաբերելիս առաջին հերթին պետք է:', NULL, '["Հեռացնել տուժածին հոսանքի աղբյուրից:", "Կատարել առաջնային զննում:", "Հեռացնել հաղորդալարը տուժածի վրայից որեւէ մեկուսիչ առարկայով:", "Փնտրել մարմնի վրա հոսանքի մուտքի եւ ելքի տեղերը (այրվածքները):"]', 'Հեռացնել հաղորդալարը տուժածի վրայից որեւէ մեկուսիչ առարկայով:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1071, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1072, 'Առաջին օգնություն ցուցաբերելիս վարակումից պաշտպանվելու համար պետք է:', NULL, '["Խուսափել վերքին անմիջապես դիպչելուց եւ օգնություն ցուցաբերել միայն ստերիլ ձեռնոցներով:", "Չօգնել այն տուժածներին, որոնք ունեն արյունահոսություն:"]', 'Խուսափել վերքին անմիջապես դիպչելուց եւ օգնություն ցուցաբերել միայն ստերիլ ձեռնոցներով:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1072, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1073, 'Բրոնխիալ ասթմայով տուժածին նոպայի դեպքում պետք է:', NULL, '["Օգնել ընդունել կիսանստած դիրք:", "Պառկեցնել եւ բարձրացնել ոտքերը:", "Պառկեցնել` ոտքերը ծնկային հոդերում ծալած:", "Պառկեցնել գլուխը բարձր դիրքով:"]', 'Օգնել ընդունել կիսանստած դիրք:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1073, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1074, 'Որովայնի վնասվածքով տուժածին պետք է:', NULL, '["Պառկեցնել գլուխը բարձր դիրքով:", "Պառկեցնել եւ բարձրացնել ոտքերը:", "Պառկեցնել` ոտքերը ծնկային հոդերում ծալած:"]', 'Պառկեցնել` ոտքերը ծնկային հոդերում ծալած:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1074, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1075, 'Ուշագնացության դեպքում տուժածին պետք է:', NULL, '["Օգնել ընդունել կիսանստած դիրք:", "Պառկեցնել եւ բարձրացնել ոտքերը:", "Պառկեցնել` ոտքերը ծնկային հոդերում ծալած:", "Պառկեցնել գլուխը բարձր դիրքով:"]', 'Պառկեցնել եւ բարձրացնել ոտքերը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1075, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1076, 'Ցածր թափքով մեքենայի չափահաս հետիոտնին, որի հասակը կազմում է 1 մ 55 սմ եւ ավելի, բախման դեպքում նրա մոտ առավել հավանական վնասվածքներն են:', NULL, '["Ստորին վերջույթի եւ գլխի վնասվածք:", "Կոնքի եւ կրծքավանդակի վնասվածք:"]', 'Ստորին վերջույթի եւ գլխի վնասվածք:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1076, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1077, 'Ցածր թափքով մեքենայի 3-5 տարեկան երեխային բախման դեպքում նրա մոտ առավել հավանական վնասվածքներն են:', NULL, '["Ստորին վերջույթի եւ գլխի վնասվածք:", "Կոնքի եւ կրծքավանդակի վնասվածք:"]', 'Կոնքի եւ կրծքավանդակի վնասվածք:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1077, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1078, 'Եթե հաղորդալարն ընկած է մեքենայի վրա, ապա պետք է:', NULL, '["Օգնել մեքենայում գտնվող անձանց շտապ դուրս գալ մեքենայից:", "Մեքենայում գտնվող անձանց խնդրել մնալ մեքենայի մեջ մինչեւ էլեկտրական հոսանքը չանջատեն:"]', 'Մեքենայում գտնվող անձանց խնդրել մնալ մեքենայի մեջ մինչեւ էլեկտրական հոսանքը չանջատեն:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1078, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1079, 'Քիչ վտանգավոր վերքերի մշակման ժամանակ պետք է:', NULL, '["Լվանալ վերքը օճառով եւ մաքուր ջրով, այնուհետեւ վիրակապել:", "Մշակել վերքը սպիրտային հիմքով նյութերով (յոդ, օղի, օծանելիք եւ այլն):"]', 'Լվանալ վերքը օճառով եւ մաքուր ջրով, այնուհետեւ վիրակապել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1079, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1080, 'Վտանգավոր վերքերի մշակման ժամանակ պետք է:', NULL, '["Լվանալ վերքը օճառով եւ մաքուր ջրով:", "Մշակել վերքը սպիրտային հիմքով նյութերով (յոդ, օղի, օծանելիք եւ այլն):", "Դադարեցնել արյունահոսությունը եւ վիրակապել վերքը:"]', 'Դադարեցնել արյունահոսությունը եւ վիրակապել վերքը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1080, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1081, 'Վթարի դեպքում շտապօգնության կանչի համար ի՞նչ տեղեկություններ պետք է տրամադրվի օպերատորին:', NULL, '["Նշել վթարի վայրին ամենամոտ գտնվող կողմնորոշիչը: Հաղորդել տուժածների թիվը, նշել նրանց սեռը եւ տարիքը:", "Նշել վթարի վայրին ամենամոտ գտնվող փողոցը եւ տան համարը: Տեղեկացնել, թե ով է տուժել վթարի հետևանքով (հետիոտն, մեքենայի վարորդ կամ ուղևոր) եւ նկարագրել ստացված վնասվածքները:", "Նշել վթարի վայրը (փողոցը, տան համարը եւ դեպքի վայրին ամենամոտ կողմնորոշիչները): Տեղեկացնել տուժածների թիվը, նրանց սեռը, մոտավոր տարիքը, գիտակցության, շնչառության, արյան շրջանառության, ինչպես նաեւ ուժեղ արյունահոսության, կոտրվածքների եւ այլ վնասվածքների առկայության մասին: Սպասել մինչեւ օպերատորը նշի, որ կանչն ընդունված է:"]', 'Նշել վթարի վայրը (փողոցը, տան համարը եւ դեպքի վայրին ամենամոտ կողմնորոշիչները): Տեղեկացնել տուժածների թիվը, նրանց սեռը, մոտավոր տարիքը, գիտակցության, շնչառության, արյան շրջանառության, ինչպես նաեւ ուժեղ արյունահոսության, կոտրվածքների եւ այլ վնասվածքների առկայության մասին: Սպասել մինչեւ օպերատորը նշի, որ կանչն ընդունված է:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1081, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1082, 'Ի՞նչ օպտիմալ դիրք պետք է տրվի գիտակցությունը պահպանված տուժածին` ողնաշարի վնասվածք կասկածի դեպքում:', NULL, '["Տուժածին պառկեցնել կողքի:", "Տուժածին պառկեցնել մեջքի վրա` կոշտ, հարթ մակերեսի վրա, առանց անհրաժեշտության չտեղաշարժել, դիրքը չփոխել:", "Տուժածին պառկեցնել մեջքի վրա, պարանոցի տակ տեղադրել շորերից պատրաստված գլանակ եւ բարձրացնել ոտքերը:"]', 'Տուժածին պառկեցնել մեջքի վրա` կոշտ, հարթ մակերեսի վրա, առանց անհրաժեշտության չտեղաշարժել, դիրքը չփոխել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1082, 10);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1083, 'Ինչպե՞ս իրականացնել առաջին օգնությունը ցրտահարության և գերսառեցման դեպքում:', NULL, '["Մարմնի ախտահարված հատվածները շփել ձյունով կամ բրդյա կտորով, ապա տաքացնել, տալ ալկոհոլային խմիչք, տեղափոխել տաք տարածք:", "Տաքացնել մարմնի ախտահարված հատվածները եւ անշարժացնել դրանք, տուժածին ծածկել տաք շորերով կամ ծածկոցով, տալ տաք ըմպելիք, տեղափոխել տաք տարածք:", "Մարմնի ախտահարված հատվածները քսուքով պատել, տաքացնող կոմպրես եւ ջեռակ դնել, տեղափոխել տաք տարածք, տալ տաք ըմպելիք:"]', 'Տաքացնել մարմնի ախտահարված հատվածները եւ անշարժացնել դրանք, տուժածին ծածկել տաք շորերով կամ ծածկոցով, տալ տաք ըմպելիք, տեղափոխել տաք տարածք:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1083, 1);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1084, 'Ինչպիսի՞ առաջին օգնություն պետք է ցուցաբերել գլխի մազածածկ մասի վերքի առկայությամբ գանգուղեղային վնասվածքի դեպքում:', NULL, '["Դադարեցնել արյունահոսությունը վերքի վրա ուղղակի ճնշման միջոցներով, վերքի վրա դնել սեղմող վիրակապ: Գիտակցության կորստի դեպքում տուժածին տալ կայուն կողքի շրջված դիրք: Հնարավորության դեպքում գլխի վնասվածքի շրջանում սառը դնել:", "Անշարժացնել ողնաշարի պարանոցային հատվածը `օգտագործելով ինքնաշեն շինա (օձիք): վերքի վրա դնել ստերիլ բամբակե խծուծ, տուժածին պառկեցնել մեջքի վրա` ոտքերը բարձրացրած դիրքում: Հնարավորության դեպքում գլխին սառը դնել:", "Արգելվում է պարանոցային շինա դնել: Անհրաժեշտ է վերքը ծածկել բժշկական կպչուն սպեղանիով, տուժածին պառկեցնել կողքի վրա:"]', 'Դադարեցնել արյունահոսությունը վերքի վրա ուղղակի ճնշման միջոցներով, վերքի վրա դնել սեղմող վիրակապ: Գիտակցության կորստի դեպքում տուժածին տալ կայուն կողքի շրջված դիրք: Հնարավորության դեպքում գլխի վնասվածքի շրջանում սառը դնել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1084, 2);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1085, 'Գիտակցության կորստի ժամանակ` շնչառության և արյան շրջանառության առկայության դեպքում, առաջին օգնություն ցուցաբերելու նպատակով Ի՞նչ դիրքով պառկեցնել տուժածին:', NULL, '["Մեջքի վրա` գլխի տակ դնելով գլանակ:", "Մեջքի վրա` ոտքերը տարածած վիճակում:", "Տուժածին տալ կայուն կողքի շրջված դիրք այնպես, որ ծալված ծնկները հպվեն գետնին, իսկ վերևում գտնվող ձեռքը գտնվի այտի տակ:"]', 'Տուժածին տալ կայուն կողքի շրջված դիրք այնպես, որ ծալված ծնկները հպվեն գետնին, իսկ վերևում գտնվող ձեռքը գտնվի այտի տակ:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1085, 3);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1086, 'Որքա՞ն ժամանակ կարող է կապված մնալ արյունահոսությունը դադարեցնող լարանը:', NULL, '["Տաք եղանակին ոչ ավելի, քան կես ժամ, իսկ ցուրտ եղանակին` ոչ ավելի, քան մեկ ժամ:", "Տաք եղանակին ոչ ավելի, քան 1 ժամ, իսկ ցուրտ եղանակին` ոչ ավելի, քան կես ժամ:", "Լարանի կապված մնալու ժամանակը սահմանափակ չէ:"]', 'Տաք եղանակին ոչ ավելի, քան 1 ժամ, իսկ ցուրտ եղանակին` ոչ ավելի, քան կես ժամ:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1086, 4);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1087, 'Ինչպե՞ս որոշել գիտակցությունը կորցրած տուժածի մոտ շնչառության առկայությունը:', NULL, '["Բռնել տուժածի կզակից, հետ թեքել գլուխը և հետևել կրծքավանդակի շարժմանը 10 վայրկյան տևողությամբ:", "Մի ձեռքը դնել տուժածի ճակատին, մյուս ձեռքի երկու մատով կզակը բարձրացնելով և գլուխը հետ թեքելով անհրաժեշտ է 10 վայրկյան տևողությամբ հետևել շնչառությանը, փորձելով արտաշնչած օդը զգալ Ձեր այտին և հետևել կրծքավանդակի շարժմանը:", "Առանց տուժածի գլուխը թեքելու, անհրաժեշտ է խոնարհվել նրա դեմքին և 10 վայրկյան տևողությամբ հետևել նրա շնչառությունը, փորձելով արտաշնչած օդը զգալ Ձեր այտին և հետևել կրծքավանդակի շարժմանը:"]', 'Մի ձեռքը դնել տուժածի ճակատին, մյուս ձեռքի երկու մատով կզակը բարձրացնելով և գլուխը հետ թեքելով անհրաժեշտ է 10 վայրկյան տևողությամբ հետևել շնչառությանը, փորձելով արտաշնչած օդը զգալ Ձեր այտին և հետևել կրծքավանդակի շարժմանը:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1087, 5);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1088, 'Որո՞նք են խոշոր զարկերակից արյունահոսության նշանները և ինչի՞ց է սկսվում առաջին օգնությունը խոշոր զարկերակային արյունահոսության ժամանակ:', NULL, '["Վերքից դանդաղորեն դուրս է հոսում մուգ գույնի արյուն: Վերքի վրա դրվում է սեղմող վիրակապ, որի վրա գրառում կա վերքի վրա պահելու ժամանակի վերաբերյալ:", "Վերքից վառ կարմիր գույնի արյուն է հոսում` ուժեղ ցայտելով, ընդհատվող շիթով կամ շատրվանի նման: Վնասված զարկերակն անհրաժեշտ է սեղմել մատներով, այնուհետև վերքից վերև, որքան հնարավոր է վերքին մոտ դրվում է արյունահոսությունը կանգնեցնող լարան, որի վրա գրառում կա պահելու ժամանակի վերաբերյալ:", "Արյունը դանդաղորեն դուրս է հոսում վերքից: Վնասվածքից ցած դրվում է արյունահոսությունը կանգնեցնող լարան, որի վրա գրառում կա պահելու ժամանակի վերաբերյալ:"]', 'Վերքից վառ կարմիր գույնի արյուն է հոսում` ուժեղ ցայտելով, ընդհատվող շիթով կամ շատրվանի նման: Վնասված զարկերակն անհրաժեշտ է սեղմել մատներով, այնուհետև վերքից վերև, որքան հնարավոր է վերքին մոտ դրվում է արյունահոսությունը կանգնեցնող լարան, որի վրա գրառում կա պահելու ժամանակի վերաբերյալ:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1088, 6);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1089, 'Արդյո՞ք թույլատրվում է տուժածին դեղեր տալ առաջին բուժօգնություն ցուցաբերելու ժամանակ:', NULL, '["Թույլատրվում է", "Թույլատրվում է ծայրահեղ անհրաժեշտության դեպքում", "Արգելվում է"]', 'Արգելվում է', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1089, 7);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1090, 'Ինչպե՞ս դադարեցնել արյունահոսությունը երակների և ոչ խոշոր զարկերակների վնասվածքի դեպքում:', NULL, '["Դնել ճնշող վիրակապ վնասվածքի տեղում:", "Վերքից վերև հատվածում ճնշող վիրակապ դնել:", "Վերքից ներև հատվածում ճնշող վիրակապ դնել:"]', 'Դնել ճնշող վիրակապ վնասվածքի տեղում:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1090, 8);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1091, 'Որո՞նք են առաջին բուժօգնության նախնական քայլերը` վթարի հետևանքով առաջացած վնասվածքների դեպքում:', NULL, '["Վերքը լվանալ ջրով, վերքից հեռացնել օտար մարմինները, վերքի վրա դնել ստերիլ բամբակ` ամրացնելով բինտային վիրակապով:", "Հագնել բժշկական ձեռնոցներ, վերքը մաքրել յոդի ալկոհոլային լուծույթով, դեղաքսուք դնել և ծածկել կպչուն սպեղանիով:", "Հագնել բժշկական ձեռնոցներ, վերքն առանց մաքրելու ծածկել ստերիլ թանզիֆե անձեռոցիկով` եզրերին ամրացնելով կպչուն սպեղանի կամ բինտով վիրակապել:"]', 'Հագնել բժշկական ձեռնոցներ, վերքն առանց մաքրելու ծածկել ստերիլ թանզիֆե անձեռոցիկով` եզրերին ամրացնելով կպչուն սպեղանի կամ բինտով վիրակապել:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1091, 9);
INSERT INTO Question (id, question, image, answers, true_answer, book_id) VALUES (1092, 'Ինչպե՞ս է առաջին օգնություն իրականացվում վերջույթների կոտրվածքների դեպքում, եթե չկան շինաներ և այն պատրաստելու համար ձեռքի տակ եղած միջոցներ:', NULL, '["Վերին վերջույթը` իրանի երկայնքով տարածած, կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց՝ փափուկ կտոր դնելով դրանց միջև:", "Վերին վերջույթը` արմնկային հոդում ծալված, գլխաշորի վրա հենած`կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց` փափուկ կտոր դնելով դրանց միջև:", "Վերին վերջույթը, արմնկային հոդում ծալված, գլխաշորի վրա հենած`կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց:"]', 'Վերին վերջույթը` արմնկային հոդում ծալված, գլխաշորի վրա հենած`կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց` փափուկ կտոր դնելով դրանց միջև:', 10);
INSERT INTO QuestionCategoryJunction (question_id, category_id) VALUES (1092, 10);
